-- Poems batch 292
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6ef126e5-10f7-4d45-8639-594160f74913','挽仁宗皇帝歌四首  其一','劉敞','宋','宋诗','song-poetry','','[]','漢恩隆四世，商歷盛三宗。',48,'全唐诗/poet.song.27000.json','["漢恩隆四世，商歷盛三宗。", "與子孫能繼，寧民戶可封。", "雲歸疑厭代，鼎就莫攀龍。", "廟樂兼韶武，應傳盛德容。"]'),
('8bf9dab7-74de-4620-95aa-376f78ad4dc9','挽仁宗皇帝歌四首  其二','劉敞','宋','宋诗','song-poetry','','[]','措刑文武後，四十有餘年。',48,'全唐诗/poet.song.27000.json','["措刑文武後，四十有餘年。", "幾與華胥比，寧知帝力然。", "占齡無協夢，棄躧趣登山。", "後世稱稽古，應參堯舜篇。"]'),
('42ecc2a9-986c-4eb3-b666-5f792a4a0083','挽仁宗皇帝歌四首  其三','劉敞','宋','宋诗','song-poetry','','[]','不陣威逾遠，無爲俗自柔。',48,'全唐诗/poet.song.27000.json','["不陣威逾遠，無爲俗自柔。", "詩書通月窟，簫勺靖炎陬。", "畢陌宫車晚，蒼梧草露秋。", "定知千歲後，民尚是軒丘。"]'),
('f29bcdc9-af60-475b-8dba-3818adf6f47c','挽仁宗皇帝歌四首  其四','劉敞','宋','宋诗','song-poetry','','[]','謳歌歸命啟，遏密罄宗堯。',48,'全唐诗/poet.song.27000.json','["謳歌歸命啟，遏密罄宗堯。", "陵寝略依漢，衣冠深葬橋。", "空看同軌至，非復總章朝。", "西望新宫柏，悲風亦後凋。"]'),
('b5e0ddc7-8438-4373-886d-fdf99ca86f29','太一齋居','劉敞','宋','宋诗','song-poetry','','[]','適野性所喜，采真今更諳。',48,'全唐诗/poet.song.27000.json','["適野性所喜，采真今更諳。", "地偏塵土少，人遠井泉甘。", "長日眠高枕，微風酒半酣。", "從來天尺五，信有此城南。"]'),
('d25607f9-3bc2-4dcb-8052-a27705e45f6f','城南晚歸','劉敞','宋','宋诗','song-poetry','','[]','高秋變搖落，遠水露澄明。',48,'全唐诗/poet.song.27000.json','["高秋變搖落，遠水露澄明。", "飛鳥江中墮，孤帆木末征。", "逆風吹帽側，疏雨逐雲行。", "興盡聊當反，塗窮眼自驚。"]'),
('f58fa1e4-42e4-45c7-b1a1-32cfbdfe58df','獨酌憶和甫','劉敞','宋','宋诗','song-poetry','','[]','開窗一杯酒，獨酌靜無言。',48,'全唐诗/poet.song.27000.json','["開窗一杯酒，獨酌靜無言。", "明蟾不可駐，流水自東奔。", "野犬迎虛吠，舟人爭渡喧。", "悵然此時意，不醉已消魂。"]'),
('8f031cc7-0121-4d12-9d2e-7381d39f49eb','履冰','劉敞','宋','宋诗','song-poetry','','[]','昔聞小旻戒，今踐薄冰行。',48,'全唐诗/poet.song.27000.json','["昔聞小旻戒，今踐薄冰行。", "涌水怒愁裂，寒蛟蟠畏驚。", "遲遲但覺遠，戰戰尚思輕。", "誰斷孤疑志，窮源更北征。"]'),
('875c32f7-4200-4143-aadd-ab67231abcae','燒殘樹','劉敞','宋','宋诗','song-poetry','','[]','古樹荒祠側，他年雷震餘。',48,'全唐诗/poet.song.27000.json','["古樹荒祠側，他年雷震餘。", "蛟龍從此逝，螻蟻至今居。", "錯節摧犀甲，燒痕蠧漆書。", "會看妨要路，終勝斷溝渠。"]'),
('889db932-fa2c-41f3-a32b-8a1e3345bc8b','雙樹','劉敞','宋','宋诗','song-poetry','','[]','吾廬雙好樹，簇簇近浮烟。',48,'全唐诗/poet.song.27000.json','["吾廬雙好樹，簇簇近浮烟。", "急雨仍堪倚，斜陽不廢眠。", "山童勤掃葉，稚子莫驚蟬。", "俗態輕幽寂，柴門賴素偏。"]'),
('175b4f4f-39f3-45ad-a0c9-e57ec9810465','題巷北桃花','劉敞','宋','宋诗','song-poetry','','[]','深巷山桃樹，無人亦自芳。',48,'全唐诗/poet.song.27000.json','["深巷山桃樹，無人亦自芳。", "青苔何限地，紅蕚可憐香。", "俗眼輕幽僻，陰天逼艶陽。", "殷勤謀一醉，容易送春光。"]'),
('addf18b2-65de-468b-baa8-a98fe2db3a02','杜祁公挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','天下蒼生望，朝端百辟師。',48,'全唐诗/poet.song.27000.json','["天下蒼生望，朝端百辟師。", "辭榮如棄躧，得道去乘箕。", "無復臨雍問，空餘罷市悲。", "會書廊廟語，世世奉蕭規。"]'),
('199d61be-0056-4501-b8f9-1c550cb76967','杜祁公挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','第五廉莫比，留侯功不居。',48,'全唐诗/poet.song.27000.json','["第五廉莫比，留侯功不居。", "遺風何峻極，雅尚得冲虚。", "平昔常開閣，深慚晚曳裾。", "千金論一字，永慨袖中書。"]'),
('5a5bcbec-0430-474c-a529-ab7e6f67e96d','送人之洛','劉敞','宋','宋诗','song-poetry','','[]','逢人問嵩少，千里駕征軒。',48,'全唐诗/poet.song.27000.json','["逢人問嵩少，千里駕征軒。", "倦馬夜未寝，鳴蟬秋尚煩。", "風煙新洛邑，冠蓋上東門。", "合有西賓問，歸時許共論。"]'),
('1f2dc915-15ac-451f-85a0-06762facb2f9','聖俞墜馬傷臂以其好言兵調之','劉敞','宋','宋诗','song-poetry','','[]','知兵心自許，見謂百夫雄。',48,'全唐诗/poet.song.27000.json','["知兵心自許，見謂百夫雄。", "上馬常慷慨，墮車寧困窮。", "誠非代大匠，疑欲作三公。", "匹似陳湯病，猶成絕域功。"]'),
('23434eef-b563-49d3-9307-493b600a201b','烽火','劉敞','宋','宋诗','song-poetry','','[]','齊秦誰謂遠，烽火自相通。',48,'全唐诗/poet.song.27000.json','["齊秦誰謂遠，烽火自相通。", "消息雌雄國，關防百二同。", "流光下滄海，飛焰避驚鴻。", "不及承平日，空悲垂白翁。"]'),
('eb88872b-f519-4bf0-b347-e1994fa4c644','得貢甫巢縣書云阻風','劉敞','宋','宋诗','song-poetry','','[]','别離常作惡，衰老異他時。',48,'全唐诗/poet.song.27000.json','["别離常作惡，衰老異他時。", "望望風波苦，悠悠見女悲。", "江空人迹絕，天逈鳥飛遲。", "若復無雙鯉，何由慰我思。"]'),
('4a6a28a1-3dca-4d01-9d57-8bebb89e9280','曬書','劉敞','宋','宋诗','song-poetry','','[]','藏書不滿萬，幽蠧亦時除。',48,'全唐诗/poet.song.27000.json','["藏書不滿萬，幽蠧亦時除。", "上有朝廷副，多從秦漢餘。", "山川迷禹穴，雲海隔崐墟。", "持此遺清白，歸爲林下居。"]'),
('e10a299f-fdfe-4763-acd0-0154bb2e15fd','卲少卿挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','湖海青雲器，朝廷白首郎。',48,'全唐诗/poet.song.27000.json','["湖海青雲器，朝廷白首郎。", "蹉跎遇已晚，零落意仍傷。", "屢擁行臺節，頻腰太守章。", "東南滿遺愛，不獨一桐鄉。"]'),
('a0376fd3-1ec9-4f82-8a6d-47174201b220','卲少卿挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','廣柳非高蓋，空山異昔歸。',48,'全唐诗/poet.song.27000.json','["廣柳非高蓋，空山異昔歸。", "善人天不與，行道涕交揮。", "髣髴音容在，留連義故違。", "安居自傳世，閭里尚光輝。"]'),
('3e796a78-b3cf-4446-9639-ee1879dbf4a9','鎮潼觀察留後贈侍中李君挽詞','劉敞','宋','宋诗','song-poetry','','[]','築壇辭将鉞，分土繼緇衣。',48,'全唐诗/poet.song.27000.json','["築壇辭将鉞，分土繼緇衣。", "忌滿名猶誤，宜年報尚非。", "離鴻哀斷續，埋玉想光輝。", "冥漠金貂贈，空看鹵簿歸。"]'),
('0a387b46-5abc-441f-b644-2bf90e4d790b','侍讀右丞贈尚書李公挽詞','劉敞','宋','宋诗','song-poetry','','[]','扶陽詩禮學，世世有知名。',48,'全唐诗/poet.song.27000.json','["扶陽詩禮學，世世有知名。", "玉樹芳榮早，金華地望清。", "川沈終合劍，風折欲分荆。", "蕭瑟烏衣巷，偏傷道路情。"]'),
('d3ce55af-394e-4003-b2c6-1b3c2d3304df','再見禁卒住桂陽二首  其一','劉敞','宋','宋诗','song-poetry','','[]','古亦苗民患，今仍禁旅過。',48,'全唐诗/poet.song.27000.json','["古亦苗民患，今仍禁旅過。", "祅氛半翼軫，殺氣覆山河。", "御史暴公子，将軍馬伏波。", "不應淹日月，頻獻凱旋歌。"]'),
('07038c01-222f-4cc5-a8c9-65606bc60d6e','再見禁卒住桂陽二首  其二','劉敞','宋','宋诗','song-poetry','','[]','肅肅卷征甲，蕭蕭出郢門。',48,'全唐诗/poet.song.27000.json','["肅肅卷征甲，蕭蕭出郢門。", "蛟螭雄步驟，鷹隼急飛翻。", "數有蠻夷警，遙憐賦税煩。", "唐虞兩階舞，帝肯用昌言。"]'),
('881c0139-88ef-42a5-891a-53dd9aca0d0c','丁右丞挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','再歷三公府，終崇萬乘師。',48,'全唐诗/poet.song.28000.json','["再歷三公府，終崇萬乘師。", "優游邇臣表，簡淡古人爲。", "愛士常推轂，傳家不遺危。", "平生赤松願，猶復白駒悲。"]'),
('0e73149d-af04-4f0a-9c39-8998d3c8207c','丁右丞挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','司籍歸良史，調鐘待一夔。',48,'全唐诗/poet.song.28000.json','["司籍歸良史，調鐘待一夔。", "遽聞麟掩袂，猶觖鳳來儀。", "絕筆流風在，遺音後世知。", "春原國人送，黄鳥寄哀詩。"]'),
('33e91cab-4ca0-459f-8844-5f6b1fb14acf','國殤','劉敞','宋','宋诗','song-poetry','','[]','屢聞戎馬入，輒有國殤詩。',48,'全唐诗/poet.song.28000.json','["屢聞戎馬入，輒有國殤詩。", "多壘非吾責，亡民痛爾爲。", "請纓慚肉食，無敵怪王師。", "聞道臨洮野，天陰戰骨悲。"]'),
('9b6200f9-c56f-45ff-a863-8c91b142eed0','暮角','劉敞','宋','宋诗','song-poetry','','[]','落日孤城閉，高風暮角愁。',48,'全唐诗/poet.song.28000.json','["落日孤城閉，高風暮角愁。", "邊聲亂歸馬，物色向新秋。", "尚有單于怨，仍傳出塞憂。", "時平翻感激，不語看層樓。"]'),
('9323ad12-f7dc-453b-ae52-0f9b00eb9a64','題天池館二首  其一','劉敞','宋','宋诗','song-poetry','','[]','誰人畫素屏，中座對滄溟。',48,'全唐诗/poet.song.28000.json','["誰人畫素屏，中座對滄溟。", "雲氣隨蛟蜃，波濤湧戶庭。", "風高鵬解羽，天近客浮星。", "會有湯湯意，無琴亦自聽。"]'),
('db7fb926-e917-44dc-b6e1-99bb352fbbfb','題天池館二首  其二','劉敞','宋','宋诗','song-poetry','','[]','粉墨勢回環，滄波入座間。',48,'全唐诗/poet.song.28000.json','["粉墨勢回環，滄波入座間。", "溟茫朝百谷，迢遞隔三山。", "怪獸有時化，孤槎何日還。", "乘桴古人勇，向壁毎慚顔。"]'),
('c69cac0c-d7d3-4c1b-b181-51919f906f8e','自長平至陳州河水絕清','劉敞','宋','宋诗','song-poetry','','[]','清川百里餘，凈淥照空虚。',48,'全唐诗/poet.song.28000.json','["清川百里餘，凈淥照空虚。", "落日金波蕩，微風霧縠舒。", "塋心看白石，明目數游魚。", "洗耳非吾事，兹身與世疏。"]'),
('2db1c50a-3af1-4aa0-bb17-d44e64a3ad49','金山館','劉敞','宋','宋诗','song-poetry','','[]','出塞二千里，荒亭無四鄰。',48,'全唐诗/poet.song.28000.json','["出塞二千里，荒亭無四鄰。", "貪烏饑攫肉，狡兔急投人。", "短短西隅日，冥冥北路塵。", "腰間丈二組，空愧漢廷臣。"]'),
('6c3eeb3c-bc89-4089-981f-fba9da4227d5','庶幾堂雨夜偃几作','劉敞','宋','宋诗','song-poetry','','[]','短夜催微月，流雲濕太空。',48,'全唐诗/poet.song.28000.json','["短夜催微月，流雲濕太空。", "瀟瀟鳴竹雨，颯颯舞松風。", "形影明燈裏，歡娛隱几中。", "吾衰儻未甚，正復夢周公。"]'),
('aca4551a-18c5-492c-8c4d-213555415eb2','春晚','劉敞','宋','宋诗','song-poetry','','[]','芳菲不少住，白日定空長。',48,'全唐诗/poet.song.28000.json','["芳菲不少住，白日定空長。", "庭樹暗新綠，春衣生晚凉。", "悠悠向時節，細細到壼觴。", "誰使風前絮，來參醉後狂。"]'),
('01ef02b1-1303-41f6-a22c-136e51520c29','鐡漿館','劉敞','宋','宋诗','song-poetry','','[]','稍出盧龍塞，回看萬壑青。',48,'全唐诗/poet.song.28000.json','["稍出盧龍塞，回看萬壑青。", "曠原開磧口，别道入松亭。", "虜馬寒隨草，奚車夕戴星。", "忽悲田子泰，寂寞向千齡。"]'),
('19a0d92f-ef21-4f15-89f8-e06d26ee46d6','凉雨','劉敞','宋','宋诗','song-poetry','','[]','晚雨蕭蕭急，秋陰處處高。',48,'全唐诗/poet.song.28000.json','["晚雨蕭蕭急，秋陰處處高。", "風雲愁宇宙，淮海怒波濤。", "貧有匣中劍，饑餘井上桃。", "誰能散積靄，萬里度鴻毛。"]'),
('9385e70b-9bb6-4a7b-bb01-89f2dd33f112','風雨寄張野人','劉敞','宋','宋诗','song-poetry','','[]','天地初開泰，雲雷未厭屯。',48,'全唐诗/poet.song.28000.json','["天地初開泰，雲雷未厭屯。", "泥深長閉戶，謀拙苦憂貧。", "狼籍千株雪，空亡一半春。", "仍愁三徑裏，草色斷幽人。"]'),
('341afb94-62ab-4b19-906b-9d05e8691ba3','孤壘二首  其一','劉敞','宋','宋诗','song-poetry','','[]','孤壘敞新觀，層軒臨暮霞。',48,'全唐诗/poet.song.28000.json','["孤壘敞新觀，層軒臨暮霞。", "分明魚意樂，徙倚客愁賖。", "遠近見百里，高低有萬家。", "春風甚不遠，更種滿城花。"]'),
('a1ff7f63-ce34-48fc-863b-22dad6987fea','孤壘二首  其二','劉敞','宋','宋诗','song-poetry','','[]','落日含古意，高臺多遠心。',48,'全唐诗/poet.song.28000.json','["落日含古意，高臺多遠心。", "魚龍潛凍水，蟋蟀有哀音。", "江漢南浮遠，關山北望深。", "張衡四愁意，歷歷起登臨。"]'),
('339e98c7-aad0-44c0-b6c1-c85eb82b018e','連日西南風戲作','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','連日風且曀，端居突不黔。',48,'全唐诗/poet.song.28000.json','["連日風且曀，端居突不黔。", "西南人殆絕，甲子雨還兼。", "巫峽雲屢起，洞庭波正添。", "誰能誅屏翳，試使後飛廉。"]'),
('9c01c1da-7ce7-4397-a0fb-1ac6ef4c6aa0','雨中送孜入京兼呈諸親舊','劉敞','宋','宋诗','song-poetry','','[]','江外五年别，齋中三日留。',48,'全唐诗/poet.song.28000.json','["江外五年别，齋中三日留。", "何能慰衰疾，正足亂羈愁。", "澤國瓜時雨，淮山桂樹秋。", "思歸欲招隱，一一謝交遊。"]'),
('2469f485-76f7-452f-8fbb-a9d24c65e147','對雪','劉敞','宋','宋诗','song-poetry','','[]','朔雪似迎春，霏霏散玉塵。',48,'全唐诗/poet.song.28000.json','["朔雪似迎春，霏霏散玉塵。", "稍看人迹絕，坐對物華新。", "地暖消還疾，風高舞正頻。", "郊扉聊自卧，誤怪洛城人。"]'),
('d46c54ef-4cfc-4ab9-814c-38ea0839d6ce','對雪憶隱直','劉敞','宋','宋诗','song-poetry','','[]','淅淅度窗竹，紛紛綴館梅。',48,'全唐诗/poet.song.28000.json','["淅淅度窗竹，紛紛綴館梅。", "怕消愁寂寞，看舞愛徘徊。", "寡和思吾友，相望共酒杯。", "時披白鶴氅，西北上高臺。"]'),
('c2068b15-e4a7-4dfa-92e1-0613f4f5ef51','八月十六日夜月','劉敞','宋','宋诗','song-poetry','','[]','不减冰輪滿，微增玉漏長。',48,'全唐诗/poet.song.28000.json','["不减冰輪滿，微增玉漏長。", "過雲收薄潤，重露濕清光。", "歷歷素娥影，菲菲丹桂芳。", "枯槎容客載，醉過羽人傍。"]'),
('cd5cd78c-90ea-4b14-a0ad-180765b26675','秋霽望月','劉敞','宋','宋诗','song-poetry','','[]','明蟾此夜新，佇立爽精神。',48,'全唐诗/poet.song.28000.json','["明蟾此夜新，佇立爽精神。", "幾夕隔霖雨，相看如故人。", "風生疑折桂，雲過欲埋輪。", "應有關山客，長歌淚滿巾。"]'),
('fce27c2c-9284-4245-951a-1df3ac097e85','送張器著作','劉敞','宋','宋诗','song-poetry','','[]','昔年聞子虚，上國重相如。',48,'全唐诗/poet.song.28000.json','["昔年聞子虚，上國重相如。", "老厭諸侯客，晚陪東觀書。", "絃歌魯儒習，風俗楚人餘。", "感激青雲氣，功名亦未疏。"]'),
('235faf0a-85b1-4039-b015-8f0a76e0208d','江行寄隱直','劉敞','宋','宋诗','song-poetry','','[]','自念復遠適，與君仍解攜。',48,'全唐诗/poet.song.28000.json','["自念復遠適，與君仍解攜。", "天文鶉首尾，地勢陜東西。", "江漢饒風雨，關山盛鼓鼙。", "離憂各易老，秋意欲悽悽。"]'),
('64bfcf94-87b6-4c33-a31d-ed72995aacce','新梅寄春卿給事','劉敞','宋','宋诗','song-poetry','','[]','徂歲嗟無奈，新花笑自如。',48,'全唐诗/poet.song.28000.json','["徂歲嗟無奈，新花笑自如。", "雪魂消去未，春色復歸初。", "欲折意空遠，少留香有餘。", "一枝寄驛使，浪語故愁予。"]'),
('0bfba75c-c186-45bc-ad05-57719bb650fd','禦冬','劉敞','宋','宋诗','song-poetry','','[]','漂泊愁多病，差池歲復闌。',48,'全唐诗/poet.song.28000.json','["漂泊愁多病，差池歲復闌。", "老驚時月疾，貧畏雪霜寒。", "外物關身足，空堂寓膝寛。", "敢希王佐略，聊取一枝安。"]'),
('e995e86c-fd9c-4af0-8987-d3eb1b3b3c8e','春日小園憶張六','劉敞','宋','宋诗','song-poetry','','[]','不見張公子，春遊分寂寥。',48,'全唐诗/poet.song.28000.json','["不見張公子，春遊分寂寥。", "獨行愁楚澤，何處榜吳橈。", "芳樹皆宜笑，垂楊總細腰。", "一樽成强醉，四望欲魂銷。"]'),
('bdc993ed-305f-4454-9641-18533275b9c2','雪後遊小園','劉敞','宋','宋诗','song-poetry','','[]','園林過新雪，草木散芳華。',48,'全唐诗/poet.song.28000.json','["園林過新雪，草木散芳華。", "物色皆疑似，春歸亦有涯。", "逕泥生沮洳，凍乳滴楂枒。", "所適從吾樂，淹留見暮霞。"]'),
('f458ff0d-0f75-48c8-8dac-6efd45ad5fd0','納凉明教臺呈太守','劉敞','宋','宋诗','song-poetry','','[]','榻移隨樹影，杯側見山岑。',48,'全唐诗/poet.song.28000.json','["榻移隨樹影，杯側見山岑。", "白鳥渇求水，玄蟬清噪林。", "道書無近語，天籟有遺音。", "向北新開逕，行苔過竹陰。"]'),
('222032a9-1c62-48be-8b8e-caa318139779','臨淵亭寄輦下親舊','劉敞','宋','宋诗','song-poetry','','[]','蠶魚山迤邐，濟汶水交流。',48,'全唐诗/poet.song.28000.json','["蠶魚山迤邐，濟汶水交流。", "信羙終非土，思鄉更倚樓。", "露滋黄菊晚，風起白雲秋。", "長嘯澄潭上，誰憐公子牟。"]'),
('546324a3-9cc8-4b43-a23a-ae19c73e2ec1','丁酉五月郭守恩戰殁武戡走入壁守恩勇将有智略','劉敞','宋','宋诗','song-poetry','','[]','敵兵得漢巧，五月戰西河。',48,'全唐诗/poet.song.28000.json','["敵兵得漢巧，五月戰西河。", "壮士平原死，孤城殺氣多。", "猶聞疏勒守，無復魯陽戈。", "不反東流水，滔滔奈爾何。"]'),
('d5957885-03c5-4712-a074-e41d446544fa','聞舅氏以秘書監致政謹獻拙詩爲賀','劉敞','宋','宋诗','song-poetry','','[]','今日王朝士，多稱賢大夫。',48,'全唐诗/poet.song.28000.json','["今日王朝士，多稱賢大夫。", "恩榮隨几杖，官職上蓬壼。", "行路歎或泣，都城畫有圖。", "他時辟雍問，惇史記訏謨。"]'),
('47a8ef2e-f56b-4f2b-b45c-f95a3a7251ba','得和書自越入京時寓商丘','劉敞','宋','宋诗','song-poetry','','[]','遙想行舟處，春江花正繁。',48,'全唐诗/poet.song.28000.json','["遙想行舟處，春江花正繁。", "殊方更回首，不語獨銷魂。", "寡和愁郢客，雅遊思兔園。", "吾能事應聘，見爾大梁門。"]'),
('a14a8200-c79e-4f15-864c-df18d55eb403','送杜横州','劉敞','宋','宋诗','song-poetry','','[]','小郡横山外，居民半島夷。',48,'全唐诗/poet.song.28000.json','["小郡横山外，居民半島夷。", "路偏逢客少，地濕見秋遲。", "銅鼓侵城角，蠻旌接使麾。", "平生聞義勇，好祭伏波祠。"]'),
('13800c65-43e5-4cf2-8bac-47e05c98f04e','送余江州','劉敞','宋','宋诗','song-poetry','','[]','潮汐通城下，東南仍上游。',48,'全唐诗/poet.song.28000.json','["潮汐通城下，東南仍上游。", "懷章趨便道，疊鼓送華舟。", "卷旆鷹隼急，落帆江漢秋。", "心知戀魏闕，頻上庾家樓。"]'),
('95f47c73-31b6-47ac-9397-35a15a8dfd6f','冬至即事','劉敞','宋','宋诗','song-poetry','','[]','南極日差永，幽人喜不勝。',48,'全唐诗/poet.song.28000.json','["南極日差永，幽人喜不勝。", "陽生漸堙鬱，陰老尚憑陵。", "風解吳山雪，江流蜀地冰。", "衝寒彊乘興，屣履過鄰僧。"]'),
('531cce00-2e5d-4071-8e40-d09c2d783481','晏公挽詞三首  其一','劉敞','宋','宋诗','song-poetry','','[]','望苑牧英雋，巖廊奉德音。',48,'全唐诗/poet.song.28000.json','["望苑牧英雋，巖廊奉德音。", "功如四支重，化以二南深。", "安仰嗟維石，能傳賴碎金。", "浮雲送哀挽，慘澹更爲霖。"]'),
('8bb52ed4-78b6-4f31-a83d-7fa20eebc089','晏公挽詞三首  其二','劉敞','宋','宋诗','song-poetry','','[]','簡易能容士，精誠樂與賢。',48,'全唐诗/poet.song.28000.json','["簡易能容士，精誠樂與賢。", "如何五湖上，非復赤松年。", "几几空遺舄，悠悠不問天。", "獨應春輟相，令望故依然。"]'),
('a95f28aa-16e2-4019-b1d6-307a049d2680','晏公挽詞三首  其三','劉敞','宋','宋诗','song-poetry','','[]','衮韍三司舊，笳簫一品榮。',48,'全唐诗/poet.song.28000.json','["衮韍三司舊，笳簫一品榮。", "獨傷去國意，仍以撫封行。", "落日白駒影，空林黄鳥聲。", "公歸那不復，悽愴國人情。"]'),
('fb10786b-aa7c-4756-855d-784c32a895df','鄰幾挽詞二首  其一','劉敞','宋','宋诗','song-poetry','','[]','那知一樽酒，流涕寝門前。',48,'全唐诗/poet.song.28000.json','["那知一樽酒，流涕寝門前。", "非復平生日，空看東逝川。", "詩書遺素業，山水閟空弦。", "人物陳留古，當憑耆舊傳。"]'),
('61d71a80-90df-4c2f-86d2-4ffd4e6028e4','鄰幾挽詞二首  其二','劉敞','宋','宋诗','song-poetry','','[]','忘年一傾蓋，適意兩虚舟。',48,'全唐诗/poet.song.28000.json','["忘年一傾蓋，適意兩虚舟。", "老去翻相失，人生固若浮。", "蕭條蒿里餞，零落竹林游。", "知與不知者，同時俱涕流。"]'),
('75a41a43-51c5-48a7-bb23-64464e7cbe5c','聖俞挽詞','劉敞','宋','宋诗','song-poetry','','[]','孤宦衆人後，空名三十年。',48,'全唐诗/poet.song.28000.json','["孤宦衆人後，空名三十年。", "交游一時絕，詩筆四方傳。", "歸旐江湖永，藏書日月邊。", "應封史通子，他日慰窮泉。"]'),
('47e469c8-a8ae-4790-b0ca-75763d7033cf','洗竹','劉敞','宋','宋诗','song-poetry','','[]','舍側萬竿綠，蕭蕭終歲佳。',48,'全唐诗/poet.song.28000.json','["舍側萬竿綠，蕭蕭終歲佳。", "翠深疑魍魎，根老畏龍蛇。", "翦剔扶霜節，分張及馬撾。", "世無嵇阮輩，竟負野人家。"]'),
('61d1a94a-44bd-4e3b-baff-4f92ee23184b','爆竹','劉敞','宋','宋诗','song-poetry','','[]','節物隨時俗，端憂見旅情。',48,'全唐诗/poet.song.28000.json','["節物隨時俗，端憂見旅情。", "土風猶記楚，辭賦謾譏傖。", "烈火琅玕碎，深堂霹靂鳴。", "但令休鬼瞰，非敢願高明。"]'),
('78e32e45-5262-45ff-8b6f-499bc3a37502','歲暮憶隱直','劉敞','宋','宋诗','song-poetry','','[]','歲窮浩長歎，心事如波瀾。',48,'全唐诗/poet.song.28000.json','["歲窮浩長歎，心事如波瀾。", "高卧老将至，相思天正寒。", "浮雲紛霰雪，陋巷獨瓢簞。", "裏飯非無意，悠悠行路難。"]'),
('433e86c2-e0b2-4313-b279-c31667734f8a','雪中與長文景仁會西閣','劉敞','宋','宋诗','song-poetry','','[]','梁山風與雪，歲暮自崢嶸。',48,'全唐诗/poet.song.28000.json','["梁山風與雪，歲暮自崢嶸。", "誤逐滄浪叟，飛來白玉京。", "屯雲紫微閣，疊壁九重城。", "更挹浮丘袂，端令俗眼驚。"]'),
('74206f07-eb4a-46a4-af31-ec80a27660ee','梅','劉敞','宋','宋诗','song-poetry','','[]','澤國春還早，山梅臘競花。',48,'全唐诗/poet.song.28000.json','["澤國春還早，山梅臘競花。", "繽紛迷雪意，浩蕩逼年華。", "驛使紅塵遠，江風短日斜。", "芳菲恐易失，愁思亂悲笳。"]'),
('5222cab2-3db2-46cf-ad47-dc48e9f08dd1','立春日雪中遊蒙谷','劉敞','宋','宋诗','song-poetry','','[]','冰解泉應動，雲寒雪更飛。',48,'全唐诗/poet.song.28000.json','["冰解泉應動，雲寒雪更飛。", "谷中知律變，林下覺春歸。", "風物如游蜀，衣冠似浴沂。", "瑤林與碧樹，處處競芳菲。"]'),
('b0d294ec-340b-4f19-b7e7-2ae58c220fe2','墨竹','劉敞','宋','宋诗','song-poetry','','[]','羈游念此君，子墨慰幽人。',48,'全唐诗/poet.song.28000.json','["羈游念此君，子墨慰幽人。", "灑落不經思，蒼筤如出塵。", "交加月下影，濃澹霧中筠。", "試作吳山想，蕭蕭意亦真。"]'),
('d01dbbf0-b01c-4edd-8472-28a627be3a54','夕陽','劉敞','宋','宋诗','song-poetry','','[]','過雨風景好，斜陽林下明。',48,'全唐诗/poet.song.28000.json','["過雨風景好，斜陽林下明。", "倦游宜几杖，卻埽稱柴荆。", "宿蝶依花靜，歸禽觸葉驚。", "逍遙共兹世，聊復得吾生。"]'),
('61f43718-d156-4425-aa41-60e44f6165d4','寄題歙州流杯池','劉敞','宋','宋诗','song-poetry','','[]','公子愛客意，高山流水間。',48,'全唐诗/poet.song.28000.json','["公子愛客意，高山流水間。", "清波無斷續，翠斝自迴還。", "野興四時得，棠陰終日間。", "何當竹林賞，醉耳聽潺潺。"]'),
('8c4f0a7e-1d21-4bc6-a590-2d912ea611d0','答張給事途中微雪見寄四韻','劉敞','宋','宋诗','song-poetry','','[]','空行萬里塞，不見六花飛。',48,'全唐诗/poet.song.28000.json','["空行萬里塞，不見六花飛。", "今日傳清唱，端來點客衣。", "度關迷馬色，拂樹散春暉。", "不减山陰興，從軍中夜歸。"]'),
('1d8d123c-f668-4006-bfcd-7196f0dba9c1','雪後','劉敞','宋','宋诗','song-poetry','','[]','飛塵暫消凍，春意亦冲融。',48,'全唐诗/poet.song.28000.json','["飛塵暫消凍，春意亦冲融。", "野水涓涓綠，林梢靡靡紅。", "躍魚輕泮凍，鳴鶴舞和風。", "出處驚時節，悠悠看歲窮。"]'),
('81f9cda6-c919-49b9-9251-5a9a5052c538','古北口對月','劉敞','宋','宋诗','song-poetry','','[]','萬古關山月，遙憐此夜看。',48,'全唐诗/poet.song.28000.json','["萬古關山月，遙憐此夜看。", "蛾眉空自嫵，叢桂不勝寒。", "他日刀頭問，何時客寝安。", "因之千里夢，共下白雲端。"]'),
('2275fcbc-8847-460a-8890-bfa926a17787','新月','劉敞','宋','宋诗','song-poetry','','[]','花外驚新月，春殘復滿弓。',48,'全唐诗/poet.song.28000.json','["花外驚新月，春殘復滿弓。", "餘香輕墜露，疏影細寒風。", "火禁通方俗，年華思老翁。", "清光堪半夜，稍醉玉壼空。"]'),
('370b2338-1f17-4c12-a289-a98ec299969a','雪後病愈至射堂作','劉敞','宋','宋诗','song-poetry','','[]','病失千峰雪，晴開萬影新。',48,'全唐诗/poet.song.28000.json','["病失千峰雪，晴開萬影新。", "鴈飛天欲暖，風起野無塵。", "弱柳悲羌笛，辛夷思楚人。", "攀條復顧影，頗似去年春。"]'),
('2fa86021-ce04-4b00-ac7e-123218b4172d','目疾呈深甫','劉敞','宋','宋诗','song-poetry','','[]','久思廢耳目，乃復困觀瞻。',48,'全唐诗/poet.song.28000.json','["久思廢耳目，乃復困觀瞻。", "默坐但憑几，幽居長下簾。", "玄黄迷宇宙，明晦錯烏蟾。", "萬事形骸外，人将不汝嫌。"]'),
('7f76448d-516d-40cb-abcb-c28b0ee0de10','新晴二首  其一','劉敞','宋','宋诗','song-poetry','','[]','雨餘春更好，日出望還新。',48,'全唐诗/poet.song.28000.json','["雨餘春更好，日出望還新。", "暄鳥啼驚客，林花笑向人。", "年華如過鴈，世事劇飛塵。", "置酒陶嘉月，滔滔醉任真。"]'),
('d46434d1-d213-4a5e-a8a7-d0f913059b9d','新晴二首  其二','劉敞','宋','宋诗','song-poetry','','[]','薄雲開早景，宿潤减飛塵。',48,'全唐诗/poet.song.28000.json','["薄雲開早景，宿潤减飛塵。", "好在松筠色，依然鳥雀馴。", "避人深卻埽，炙背暖生春。", "未得獻天子，潛書報近鄰。"]'),
('8a311b76-5250-4032-bdec-dced6ce6fd7a','秦淮對月','劉敞','宋','宋诗','song-poetry','','[]','舊熟秦淮水，今浮萬里船。',48,'全唐诗/poet.song.28000.json','["舊熟秦淮水，今浮萬里船。", "泬寥明月夜，淡泊始秋天。", "靜境他時絕，清光度曉圓。", "無人漫詠史，回首憶先賢。"]'),
('05c8bc14-0234-46c7-9d83-699ee8047d96','晚泊對月','劉敞','宋','宋诗','song-poetry','','[]','川光晚都白，岸色遠全青。',48,'全唐诗/poet.song.28000.json','["川光晚都白，岸色遠全青。", "明月隨孤劍，浮槎送客星。", "南飛鵲擾擾，北嚮雁冥冥。", "誰謂悲歌短，能吟酒易醒。"]'),
('fb376a10-d06f-46d8-ac64-b6bedcc328e0','欲雪寄貢甫','劉敞','宋','宋诗','song-poetry','','[]','欲雪天地閉，積雲江海昏。',48,'全唐诗/poet.song.28000.json','["欲雪天地閉，積雲江海昏。", "著書成寂寞，玩歲覺崩奔。", "鴻鴈自嘯侣，鶺鴒常在原。", "離憂紛滿眼，浪作種庭萱。"]'),
('538ae772-f2ec-413d-8415-b6d635e28cdf','初雪','劉敞','宋','宋诗','song-poetry','','[]','三日風振海，中宵雪覆城。',48,'全唐诗/poet.song.28000.json','["三日風振海，中宵雪覆城。", "已看秋落漠，更逼歲崢嶸。", "原隰龍沙磧，樓臺白玉京。", "知誰錯吹律，物物驟堪驚。"]'),
('feba00f8-a5b3-40be-9ecf-22cb0c92b889','殘雪','劉敞','宋','宋诗','song-poetry','','[]','積素不可卷，潛陽方未蘇。',48,'全唐诗/poet.song.28000.json','["積素不可卷，潛陽方未蘇。", "勁風吹强起，明月照全無。", "封蟄龍蛇病，傷根竹柏枯。", "誰能開白日，后土正泥塗。"]'),
('735e9dec-5787-4278-bfe4-dbe2b28053c3','望雪山','劉敞','宋','宋诗','song-poetry','','[]','朔風何處雪，徑度江南山。',48,'全唐诗/poet.song.28000.json','["朔風何處雪，徑度江南山。", "半出青天外，猶臨庭戶間。", "崔嵬海潮湧，泱漭暮雲還。", "壮觀感人意，長謡如可攀。"]'),
('53d7b46f-c54f-4319-90a1-c7b16a7bcffe','戯賀段生','劉敞','宋','宋诗','song-poetry','','[]','驃騎門下士，蹉跎已白頭。',48,'全唐诗/poet.song.28000.json','["驃騎門下士，蹉跎已白頭。", "知人家監誤，彈劍起吹愁。", "忽逐侏儒飽，遙聞祿仕優。", "還鄉問耆舊，當憶負薪謳。"]'),
('d647d43d-9598-4e82-9c0a-2ba8b8ab0456','贈致政葉郎中','劉敞','宋','宋诗','song-poetry','','[]','老掛朝冠息故園，國人同嘆仲翁賢。',64,'全唐诗/poet.song.28000.json','["老掛朝冠息故園，國人同嘆仲翁賢。", "心慚白首戀三署，意與赤松均大年。", "玉樹承風榮紫闥，史臣書美耀青編。", "他時就問朝廷策，還見公卿語鄧先。"]'),
('f569f8b4-a296-49f0-822c-c2ce053d052f','次韻和寄','劉敞','宋','宋诗','song-poetry','','[]','講業儒林璧水開，望親雲下想徘徊。',64,'全唐诗/poet.song.28000.json','["講業儒林璧水開，望親雲下想徘徊。", "平原日暖歌鴒在，横隴風高聽鴈来。", "隱几郡齋閒主諾，薦羞家府樂循陔。", "何時乞得歸寧告，對襲班衣捧慶杯。"]'),
('1745f37e-1040-4377-a051-0d067021958c','送晏公留守南都','劉敞','宋','宋诗','song-poetry','','[]','蒼龍大火明堂分，原廟離宫萬乘居。',64,'全唐诗/poet.song.28000.json','["蒼龍大火明堂分，原廟離宫萬乘居。", "五帝遺聲在名頌，三公出使用安車。", "去思尚想多耆老，條教祇煩讀舊書。", "複道平臺彌百里，鄒陽何處曳長裾。"]'),
('fff22fe5-9092-4b56-9e50-460aacfbf0d9','伯父挽詞','劉敞','宋','宋诗','song-poetry','','[]','四十賓興七十歸，清風遠與古人稀。',64,'全唐诗/poet.song.28000.json','["四十賓興七十歸，清風遠與古人稀。", "未如彭祖猶爲天，頗似桐鄉得所依。", "何路可能奔遠日，此生無復待烏衣。", "故尋庭樹丁寧誨，東望吳門涕自揮。"]'),
('e1d40c98-2569-4af1-a42e-fb4492c3f7ca','城下種竹今春極有佳筍','劉敞','宋','宋诗','song-poetry','','[]','環城密篠舊檀欒，春筍新成幾萬竿。',64,'全唐诗/poet.song.28000.json','["環城密篠舊檀欒，春筍新成幾萬竿。", "池上龍蛇驚蟄起，軍中矛戟繞營看。", "烏啼窈窈千重碧，風過蕭蕭五月寒。", "緩带輕裘容自暇，屨綦多向此林端。"]'),
('14909915-76b0-4ad6-b0ea-050821002e7c','四月見梅花作','劉敞','宋','宋诗','song-poetry','','[]','臘前芳樹暑前開，笑憶周南摽有梅。',64,'全唐诗/poet.song.28000.json','["臘前芳樹暑前開，笑憶周南摽有梅。", "玉色還如雪中見，天香不減嶺頭来。", "黄鶯未識休頻顧，粉蝶初逢亦自猜。", "應與靈芝競三秀，碧城瑤圃隔塵埃。"]'),
('8db7eaf9-71eb-4aab-b56f-0becbd7fdd52','寄慶州子華侍讀諫議','劉敞','宋','宋诗','song-poetry','','[]','禁中頗牧去臨戎，屬國歸來敵壘空。',64,'全唐诗/poet.song.28000.json','["禁中頗牧去臨戎，屬國歸來敵壘空。", "聞道詩書今絕幕，復看天馬亦從東。", "醉傾床酒留邊月，歌倚鵾弦舞朔風。", "猶憶平生歡一笑，莫忘書札寄賓鴻。"]'),
('0bd53cf7-7cea-4e14-a715-e7d31f22c34c','姚家寨道中逢李諫議','劉敞','宋','宋诗','song-poetry','','[]','蕭蕭歸騎歷崔嵬，一見塵中耳目開。',64,'全唐诗/poet.song.28000.json','["蕭蕭歸騎歷崔嵬，一見塵中耳目開。", "授玉同爲萬里使，望雲先識二星回。", "北荒鵬躍南溟去，西極馬循東道來。", "世上應無此别遠，留連彊盡手中杯。"]'),
('20ab3c80-74e3-4a68-b667-6cb9d1da2df2','逢范景仁李審言二諫議','劉敞','宋','宋诗','song-poetry','','[]','怪來原隰滿光華，不意相逢天一涯。',64,'全唐诗/poet.song.28000.json','["怪來原隰滿光華，不意相逢天一涯。", "久别班荆情未易，少留傾盖日空斜。", "山連木葉千峰雪，地逼龍城萬里沙。", "深愧壮心輕遠適，自嫌憔悴聽悲笳。"]'),
('9af2f501-9614-46d8-811e-2b84162cb466','貝州未破書寄王子直司徒','劉敞','宋','宋诗','song-poetry','','[]','孤城死地尚睢盱，智勇俱當竭蹶趨。',64,'全唐诗/poet.song.28000.json','["孤城死地尚睢盱，智勇俱當竭蹶趨。", "貧且賤焉真恥也，壮之良者盍行乎。", "料無豪傑同吳反，陰有神靈助漢誅。", "深怪先登少瑕叔，不應時論惜蝥弧。"]'),
('10bf41d8-69ae-49fb-a3f7-022c338ebc5f','酬宋次道憶館閣曝書七言','劉敞','宋','宋诗','song-poetry','','[]','長廊複閣接天居，炎日清風蠧寶書。',64,'全唐诗/poet.song.28000.json','["長廊複閣接天居，炎日清風蠧寶書。", "乍到似迷羣玉近，饜觀疑及羽陵餘。", "俊游真與塵埃隔，逸賞空驚應接疏。", "石室會須歸史筆，周南寧復滯君車。"]'),
('703fa746-b99d-4c9c-bd25-d1bfe0e400e7','九日龍華閣寄永叔','劉敞','宋','宋诗','song-poetry','','[]','黄花欲落曉霜濃，極目秦川一望中。',64,'全唐诗/poet.song.28000.json','["黄花欲落曉霜濃，極目秦川一望中。", "節物還如去年好，懽游不與故人同。", "接䍦自恣風前落，羽檄寧妨席上通。", "還畏簡書歸未得，寄詩黄閣付征鴻。"]'),
('b6c7e206-5d7a-45eb-82df-6461316ce9e0','寄題友生水閣','劉敞','宋','宋诗','song-poetry','','[]','曲岸重重植淺莎，雨餘初覺長微波。',64,'全唐诗/poet.song.28000.json','["曲岸重重植淺莎，雨餘初覺長微波。", "水紋滿屋浮清簟，風力衝階折芰荷。", "境靜自宜詩興遠，夜空應見月明多。", "從来著述希揚子，爲羡幽人載酒過。"]'),
('341f6002-9df7-4efe-84e1-ea69d498cd6d','逢永叔','劉敞','宋','宋诗','song-poetry','','[]','絕域逢君水暫留，舉杯相屬問刀頭。',64,'全唐诗/poet.song.28000.json','["絕域逢君水暫留，舉杯相屬問刀頭。", "久持漢節旄空盡，獨拜穹廬死可羞。", "醉裏歲華驚易老，愁邊溝水愴分流。", "玉關生入知無恨，不願張騫博望侯。"]'),
('5dc977c4-2e17-48b9-a5a7-bda88aee80a9','和永叔景靈朝謁從駕還宫','劉敞','宋','宋诗','song-poetry','','[]','漢帝迎年十二樓，明廷朝計萬諸侯。',64,'全唐诗/poet.song.28000.json','["漢帝迎年十二樓，明廷朝計萬諸侯。", "真仙降集鈞天樂，雲旆回翔駟玉虬。", "物色遙占紫氣入，香烟不隔曙光浮。", "秘祠非爲神君語，自飭衣冠渭北游。"]'),
('b180862d-2f04-4a14-b34a-334c467aad1c','泥雨早朝','劉敞','宋','宋诗','song-poetry','','[]','雲氣卷舒東復西，月華明晦曉兼迷。',64,'全唐诗/poet.song.28000.json','["雲氣卷舒東復西，月華明晦曉兼迷。", "正憐盛服坐假寐，何處蒼蠅來誤雞。", "高卧山林勞夢想，出門冠带混塗泥。", "人間氣味故易厭，豈若從容歸治畦。"]'),
('fc0908e7-d3cf-4dfa-96d7-c1212c34103d','次韻得午日酒','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','午日風光復晏陰，軒昂未許歲華侵。',64,'全唐诗/poet.song.28000.json','["午日風光復晏陰，軒昂未許歲華侵。", "楚魂招後宜皆醉，春醖來時且獻斟。", "高枕洞庭看鳥度，卷簾衡岳聽猿吟。", "郢中寡和由來事，應喜新詩有嗣音。"]'),
('ddb4c4d1-9ec4-4ccf-aefa-12db6d634c75','十二月十六日','劉敞','宋','宋诗','song-poetry','','[]','水國冰銷天欲春，山城日出景還新。',64,'全唐诗/poet.song.28000.json','["水國冰銷天欲春，山城日出景還新。", "可憐物色曾非土，亦復窮愁不放人。", "碌碌流年轉車轂，悠悠生意厭風塵。", "草茅不必開三徑，杖履何嘗及四鄰。"]'),
('859dbf6d-8eba-4830-9345-ec30106fda8a','孫侍郎訪及仍携示近詩','劉敞','宋','宋诗','song-poetry','','[]','泌水衡門野老居，彤幨丹轂使君輿。',64,'全唐诗/poet.song.28000.json','["泌水衡門野老居，彤幨丹轂使君輿。", "固驚北海猶知備，曾謂西河尚起予。", "高卧窮愁述歲晚，立談襟抱爲公攄。", "浪傳方伯中和頌，詎有虚儀講德書。"]'),
('a972a5dd-d6fb-487b-8327-b9b46f758924','逢呂侍郎','劉敞','宋','宋诗','song-poetry','','[]','北鴈南鳬不自期，異鄉交臂復分飛。',64,'全唐诗/poet.song.28000.json','["北鴈南鳬不自期，異鄉交臂復分飛。", "壮心巳折霜侵鬢，徂歲相看涙滿衣。", "絕幕陰多逢日少，滯林行苦見人稀。", "子牟意緒君諳識，况乃登臨遠送歸。"]'),
('4dee6d1c-789e-4579-9d79-c8bb86d67da5','寄西臺吳侍郎','劉敞','宋','宋诗','song-poetry','','[]','淮陽高卧彊逾時，洛水嵩峰入夢思。',64,'全唐诗/poet.song.28000.json','["淮陽高卧彊逾時，洛水嵩峰入夢思。", "霖雨徒深旱歲望，白雲自與帝鄉期。", "功名擺落人間世，出處優游萬乘師。", "坐視天民應未可，似公當就太平基。"]'),
('8c09eac4-bfb3-469a-a8f0-d9f952e4dc8a','同濟川題王金吾園亭','劉敞','宋','宋诗','song-poetry','','[]','王侯功業等山河，謝傅風流倦燮和。',64,'全唐诗/poet.song.28000.json','["王侯功業等山河，謝傅風流倦燮和。", "治第由來處窮僻，賞心曾是極酣歌。", "歲寒松竹孫枝在，詩罷池塘宿草多。", "聞道将軍亦愛客，春游不問主人過。"]'),
('320cba08-882a-4c5d-992f-aff8b0bec244','謝晏公蓮實','劉敞','宋','宋诗','song-poetry','','[]','落蘂漂香思碧蓮，嫩芳成實澹晴烟。',64,'全唐诗/poet.song.28000.json','["落蘂漂香思碧蓮，嫩芳成實澹晴烟。", "玉杯側露參差重，麟趾模金約略圓。", "擷秀乍聞回急槳，薦新還許備加籩。", "涉江不限芻蕘往，志服深希百疾蠲。"]'),
('d5b4f0ef-37c5-487d-aae9-88a6be437fb1','答許待制依韻','劉敞','宋','宋诗','song-poetry','','[]','水衡錢朽太倉陳，均逸于藩布上仁。',64,'全唐诗/poet.song.28000.json','["水衡錢朽太倉陳，均逸于藩布上仁。", "期月政聲歸卧理，舊邦風物變車鄰。", "懷章昔别江湖永，辭劇由來意氣真。", "召伯甘棠大山賦，去思留得與邦人。"]'),
('bb018439-b4f7-4c05-805e-8672df9ecf9c','曹秀之待制罷福建還朝劉君玉待制自長沙移鄧俱會郡下作七言敘别','劉敞','宋','宋诗','song-poetry','','[]','華閣昭回雲漢間，侍臣高選奉清閒。',64,'全唐诗/poet.song.28000.json','["華閣昭回雲漢間，侍臣高選奉清閒。", "曹劉共許同時貴，楚粤初看報政還。", "邂逅相逢驚遠别，從君一笑發愁顔。", "莫教鐃鼓催行色，更益春風雨鬢斑。"]'),
('fbe79d0f-5a19-4e59-b6fb-f8854a25c1df','将去上清題梧桐樹','劉敞','宋','宋诗','song-poetry','','[]','小砌圓陰覆暝霞，曲軒疏牖稱相遮。',64,'全唐诗/poet.song.28000.json','["小砌圓陰覆暝霞，曲軒疏牖稱相遮。", "已成嘉實誠無用，未遇知音勿遽嗟。", "得地豈須矜露井，随流方共笑枯槎。", "明年冠者成春服，重看紛紛滿樹花。"]'),
('c68c20d1-73cf-499b-bd7f-db6e0174a3ae','鳯凰山笙竹','劉敞','宋','宋诗','song-poetry','','[]','仙山不記鳯鳴時，碧篠空含玉潤姿。',64,'全唐诗/poet.song.28000.json','["仙山不記鳯鳴時，碧篠空含玉潤姿。", "海外雖傳有嶰谷，人間似未悟孫枚。", "道家正貴知音少，野處還于靜節宜。", "千歲重尋樂毅傳，悠悠更覺使心悲。"]'),
('8a0b081d-e2cb-4a3e-9d03-44e96e02dc84','上巳日玉津園賜宴是日雜端爲主人','劉敞','宋','宋诗','song-poetry','','[]','御苑初晴暖景微，侍臣還許宴春輝。',64,'全唐诗/poet.song.28000.json','["御苑初晴暖景微，侍臣還許宴春輝。", "鳴禽試羽交交囀，落葉迎風冉冉飛。", "執法在前容款曲，大官先置盡膏肥。", "和平自是歡娛日，未醉春醪未可歸。"]'),
('80386101-a786-433c-9e96-57b0800be96c','和憶幽谷二首  其一','劉敞','宋','宋诗','song-poetry','','[]','早聞幽谷未曾窺，翠壁清泉入夢思。',64,'全唐诗/poet.song.28000.json','["早聞幽谷未曾窺，翠壁清泉入夢思。", "到眼惜無名手畫，醒心欣得醉翁詩。", "種花舊比甘棠樹，刻石今成峴首碑。", "使我一麾從此逝，勝遊當不減君時。"]'),
('cd6496e4-79d0-44b7-a706-b5e9b88aafaa','和憶幽谷二首  其二','劉敞','宋','宋诗','song-poetry','','[]','深居忽忽春空過，積雨瀟瀟夏欲交。',64,'全唐诗/poet.song.28000.json','["深居忽忽春空過，積雨瀟瀟夏欲交。", "近砌梧桐新有蔭，銜泥燕子總成巢。", "此邦卑濕酒長醉，随事文章亦解嘲。", "心遠地偏人跡絕，漫勞三逕數誅茅。"]'),
('d8cc727d-f812-423e-aff8-c4151cc4d350','京尹仲議侍讀自成都赴闕将過長安先寄','劉敞','宋','宋诗','song-poetry','','[]','都城一别遠相望，楚水秦山各異方。',64,'全唐诗/poet.song.28000.json','["都城一别遠相望，楚水秦山各異方。", "毎頌中和傳四子，重聞京兆得三王。", "執經誤接金華袐，卧閣驚看鬢色蒼。", "逃暑肯爲千日飲，能無歌舞薦清觴。"]'),
('ad262503-a780-48e5-8d59-a21d40edd9a2','初雪朝退與諸公至西閣','劉敞','宋','宋诗','song-poetry','','[]','朝光初上九門開，貝闕珠宫白玉臺。',64,'全唐诗/poet.song.28000.json','["朝光初上九門開，貝闕珠宫白玉臺。", "真有燭龍浮渤澥，卻占雲氣認蓬萊。", "斗回暖景開鳴鶴，稍借新芳入早梅。", "更覺年華無限賞，履綦重疊遶蒼苔。"]'),
('71c6c569-4266-4a86-b910-99e546ca397c','答河中梅龍圖','劉敞','宋','宋诗','song-poetry','','[]','龍池柳色鎖春烟，故國風光此地偏。',64,'全唐诗/poet.song.28000.json','["龍池柳色鎖春烟，故國風光此地偏。", "高下樓臺渾浸水，往來車馬自随船。", "舉杯醉舞時相屬，倚瑟悲歌忽愴然。", "安敢爲文敵金谷，誤煩求友賦新篇。"]'),
('03b0d0b9-c920-4d60-8077-f5a82b4307d2','離陳州先寄潁上龍圖','劉敞','宋','宋诗','song-poetry','','[]','蓬蒿一畝亦蘧廬，終歲紛紛三徙居。',64,'全唐诗/poet.song.28000.json','["蓬蒿一畝亦蘧廬，終歲紛紛三徙居。", "客耳欣沾潁川水，兒謡積厭武昌魚。", "寧知代舍悲長鋏，忽幸侯門埽敝裾。", "雖信師金譏數昧，未甘萊子勤捐書。"]'),
('0f684236-75ef-4544-9028-540da5f7bd1e','寄襄陽舅氏龍圖','劉敞','宋','宋诗','song-poetry','','[]','虎符龍節鎮方州，天祿先生尚黑頭。',64,'全唐诗/poet.song.28000.json','["虎符龍節鎮方州，天祿先生尚黑頭。", "南紀山川殊壮麗，高陽賓客故風流。", "沈碑幾處書遺愛，非土他時恨倚樓。", "想詠五君夸屢薦，爲憑三鳥寄綢繆。"]'),
('8065a785-03b3-4976-b6c8-56c7b9eaaca6','送司馬倩赴權官平涼尉','劉敞','宋','宋诗','song-poetry','','[]','将女隨郎過渭城，正如前曰武陵行。',64,'全唐诗/poet.song.28000.json','["将女隨郎過渭城，正如前曰武陵行。", "當時底事傷離别，今日安知隔死生。", "渺渺平波侵漢苑，纍纍高塚厭秦京。", "登臨感慨尋常事，何况衰年父子情。"]'),
('9b025c78-00b6-4b32-b509-0e552b2d8588','和春鄉答韓殿丞','劉敞','宋','宋诗','song-poetry','','[]','暫辭金鼎擁朱旛，注意雖殊體貌存。',64,'全唐诗/poet.song.28000.json','["暫辭金鼎擁朱旛，注意雖殊體貌存。", "擺落功名如脱屣，招攜賓客許遊藩。", "東人愁詠鴻遵渚，北海欣看酒滿罇。", "無以公歸君幸識，鳯池深隔九重閽。"]'),
('219a6609-cd31-4d04-9bda-f3c563399b95','復雨','劉敞','宋','宋诗','song-poetry','','[]','閉門高枕避春霖，眼見羣芳稍見侵。',64,'全唐诗/poet.song.28000.json','["閉門高枕避春霖，眼見羣芳稍見侵。", "獨醒不如終日醉，暫晴那似斷年陰。", "老驚歲月都無用，興在江湖特更深。", "正想青楓千里外，草長波闊亂愁心。"]'),
('c5d318e0-c6df-4788-933c-92703f2ab1af','雨中醉歸','劉敞','宋','宋诗','song-poetry','','[]','楚山終日雨霏霏，寥落村花入眼稀。',64,'全唐诗/poet.song.28000.json','["楚山終日雨霏霏，寥落村花入眼稀。", "可惜東風變酒味，無端宿靄破春暉。", "屈原漁父誰清濁，御叔臧孫交是非。", "倒著接䍦驚道路，悠悠判與世相違。"]'),
('4a70ebbd-d79a-42cf-b563-9e511482fd61','永叔附寄滁州庶子泉李監題十二字','劉敞','宋','宋诗','song-poetry','','[]','瑯琊山側白雲溪，石壁何年李監題。',64,'全唐诗/poet.song.28000.json','["瑯琊山側白雲溪，石壁何年李監題。", "翰墨一時稱妙絕，塵埃數字尚端倪。", "驚看龍虎潛光彩，恨使莓苔損角圭。", "大呌發狂心未足，竹林幽賞負招攜。"]'),
('3e1bdc66-053b-452a-8ff7-52665f058b81','臨崑亭','劉敞','宋','宋诗','song-poetry','','[]','孤城西北起高樓，天半崑崙入寸眸。',64,'全唐诗/poet.song.28000.json','["孤城西北起高樓，天半崑崙入寸眸。", "碧樹参差見平圃，屯雲重疊辨軒丘。", "百年禮樂逢休運，千里江山極勝遊。", "那似鮑昭空寫恨，不爲王粲獨銷憂。"]'),
('0204a554-7219-4a9d-8276-897303786ce1','和永叔李太尉飲席聞筝','劉敞','宋','宋诗','song-poetry','','[]','紅顔翠髪奪春輝，繁手哀弦逐羽巵。',64,'全唐诗/poet.song.28000.json','["紅顔翠髪奪春輝，繁手哀弦逐羽巵。", "正使千觴無復醉，誰令中曲不勝悲。", "留連起舞驚殘夜，倣寫遺音入怨詩。", "我識東山安石意，沾襟應自屬桓伊。"]'),
('880ebd65-37d5-4de0-9716-fb68f1e31ac4','齋宿集禧觀戯酬永叔見寄時永叔在後廟攝事','劉敞','宋','宋诗','song-poetry','','[]','尚平故有五山期，獨許迎年太液池。',64,'全唐诗/poet.song.28000.json','["尚平故有五山期，獨許迎年太液池。", "貝闕碧城相絢爛，石林琪樹共參差。", "玉杯醽好經時醉，冰簟風多盡日棋。", "正想火龍勞陟降，更煩佳句寄相思。"]'),
('8d03e36e-e138-4b97-8e82-e760473c166c','依韻和致政龐相公上巳約遊集禧觀不至','劉敞','宋','宋诗','song-poetry','','[]','琳館經春瑞氣浮，當時曾約相車遊。',64,'全唐诗/poet.song.28000.json','["琳館經春瑞氣浮，當時曾約相車遊。", "仙花又向庭中落，宫水還縈苑外流。", "雲路空思攀去鶴，沙堤猶憶問行牛。", "明年三月芳菲在，須把蘭亭褉事脩。"]'),
('2896f5ea-a77e-42d5-b7b3-5b226a147f52','馬上南風變晴','劉敞','宋','宋诗','song-poetry','','[]','繁陰欲閉凱風來，一埽窮荒萬里開。',64,'全唐诗/poet.song.28000.json','["繁陰欲閉凱風來，一埽窮荒萬里開。", "日色葱曨浮渤澥，雲容舒卷映蓬萊。", "旅情更覺光華遠，暖意何妨節物催。", "醉眼卻思山雪好，臘前容可當新梅。"]'),
('9b40afb1-e1b8-437f-8f70-5a574cc23060','新種雜花樹','劉敞','宋','宋诗','song-poetry','','[]','江邊臘破東風起，舍側栽花遶四鄰。',64,'全唐诗/poet.song.28000.json','["江邊臘破東風起，舍側栽花遶四鄰。", "要似桃源堪避世，會令桂樹默留人。", "即看紅葉娟娟秀，豫想喧蜂處處新。", "庾宅荒涼宋亭古，應須大占郢中春。"]'),
('7f412daa-7f55-48a4-9482-689764cdc9d2','答子温雪中見寄','劉敞','宋','宋诗','song-poetry','','[]','勁風蕭颯結衝波，飛雪奔騰萬里過。',64,'全唐诗/poet.song.28000.json','["勁風蕭颯結衝波，飛雪奔騰萬里過。", "亦未妨人洛陽卧，還聞有客郢中歌。", "壮心可念哀鴻遠，正色遙憐翠竹多。", "會卜豊年慰羈旅，敢辭荒逕重張羅。"]'),
('711deeba-0170-4d7c-b115-d95b7ede9edd','次韻和永叔歲旦對雪見寄時某于上源驛典護契丹朝正使人日當歸前一日始得此詩','劉敞','宋','宋诗','song-poetry','','[]','朔風千里動高簾，雷起龍山晝擁簷。',64,'全唐诗/poet.song.28000.json','["朔風千里動高簾，雷起龍山晝擁簷。", "屬國請纓謀巳拙，屠蘇澆酒歲空添。", "翦幡春事宜人日，破鑑歸期見玉蟾。", "聊欲爲君留薄具，𤐣蠡床酒水精鹽。"]'),
('2afe1187-2735-4f28-af85-fb3fc38914d9','答景彝對月','劉敞','宋','宋诗','song-poetry','','[]','正惜蟾蜍沈夕靄，忽傳鐘鼓送秋晴。',64,'全唐诗/poet.song.28000.json','["正惜蟾蜍沈夕靄，忽傳鐘鼓送秋晴。", "浮雲四卷無餘跡，斜漢西流亦自明。", "危檻鈎簾吟獨久，薄帷高枕夢逾清。", "幽蘭佳菊漙新露，的曆珠華滿翠莖。"]'),
('8dea9dc4-caf8-44a8-b2f9-fe2eae2a0b68','立夏祠太乙宫','劉敞','宋','宋诗','song-poetry','','[]','綘闕迎年侯執期，羽衣通夕侍嚴祠。',64,'全唐诗/poet.song.28000.json','["綘闕迎年侯執期，羽衣通夕侍嚴祠。", "神光映月開璇室，香霧含風拂桂旗。", "路遶城南天最近，地非人境日偏遲。", "還聞增授無窮筴，馳奏中宸對受釐。"]'),
('123270e6-cf17-488b-bf33-f65908527434','自陝到闕感而成詠','劉敞','宋','宋诗','song-poetry','','[]','葱葱氣象瞻嶢闕，肅肅行装造近畿。',64,'全唐诗/poet.song.28000.json','["葱葱氣象瞻嶢闕，肅肅行装造近畿。", "鈞奏昔年曾夢到，玉關今日是生歸。", "茂林病久迷朝序，宣室人疏懾帝暉。", "簪履未忘恩再造，不然何路謁彤闈。"]'),
('f9d45f1f-6f1e-41bb-9f84-f6c4d4a0aac2','送人赴闕','劉敞','宋','宋诗','song-poetry','','[]','五月齊侯報政時，衮章英節照西畿。',64,'全唐诗/poet.song.28000.json','["五月齊侯報政時，衮章英節照西畿。", "昔看高鴈冥冥去，今喜長魂婉婉歸。", "詔使相望擁冠盖，都人傾倒遲光暉。", "師臣固有三公拜，豈獨優游奉講闈。"]'),
('7abdf23e-a838-4239-a959-450436ca401b','留别永叔','劉敞','宋','宋诗','song-poetry','','[]','回車欲度幕南庭，此地那知眼界清。',64,'全唐诗/poet.song.28000.json','["回車欲度幕南庭，此地那知眼界清。", "老覺鬢毛俱種種，醉看風物盡冥冥。", "平時慟哭休論事，遠別悲歌更忍聽。", "且共春風同入塞，憶君時計短長亭。"]'),
('67e49361-cc13-42af-974b-f2ad30dea1a7','澄心堂讀許渾以下諸詩','劉敞','宋','宋诗','song-poetry','','[]','許渾詩後三百年，長嘯空堂覽舊篇。',64,'全唐诗/poet.song.28000.json','["許渾詩後三百年，長嘯空堂覽舊篇。", "落日孤城曾不改，曲池高榭復依然。", "塵埃暫憇道路客，文雅相追今昔賢。", "魚躍鳶飛殊有意，卜居仍欲近湖邊。"]'),
('dbc03dda-5712-40ab-898e-27c1631e6de3','寄密令楊彦文','劉敞','宋','宋诗','song-poetry','','[]','傾盖相親成白頭，離懷終日敵三秋。',64,'全唐诗/poet.song.28000.json','["傾盖相親成白頭，離懷終日敵三秋。", "可憐鷄黍虚朋好，應用弦歌亂旅愁。", "太史成書自留滯，石城通信已沈浮。", "王孫可恨山中久，舊令曾爲褒德侯。"]'),
('550f5f67-bbfe-4688-838a-66c237b2a957','答楊令彦文','劉敞','宋','宋诗','song-poetry','','[]','從吏相望千里餘，蓬蒿無以避空虛。',64,'全唐诗/poet.song.28000.json','["從吏相望千里餘，蓬蒿無以避空虛。", "豈惟論議沈時俗，更覺精神耗簿書。", "慚愧故人存雅素，殷勤佳句慰離居。", "周南會是弦歌地，莫忘尋盟一起予。"]'),
('22413df3-aee0-4ef4-9329-deb8fe39e040','寄致政張大卿','劉敞','宋','宋诗','song-poetry','','[]','昭回雲漢麗清秋，曾看星槎曆斗牛。',64,'全唐诗/poet.song.28000.json','["昭回雲漢麗清秋，曾看星槎曆斗牛。", "歸去還爲竹林會，相望寧減赤松遊。", "達人軒冕都如夢，塵世功名不自謀。", "聞道東山多逸賞，從君欲具五湖舟。"]'),
('b2a707d7-588a-44e4-938b-725465d2280f','送伯鎮守湖州','劉敞','宋','宋诗','song-poetry','','[]','馮公白首敞長裾，萊子斑衣樂有餘。',64,'全唐诗/poet.song.28000.json','["馮公白首敞長裾，萊子斑衣樂有餘。", "金馬門前歌避世，水精宫裏奉安輿。", "萬重巖岫高藏日，百丈溪前俯見魚。", "去去春風稱行樂，京塵回首憶離居。"]'),
('63728fbb-e372-42e3-aa14-d0cad3b2f8ae','次韻四叔父出守新定寄歐陽一首','劉敞','宋','宋诗','song-poetry','','[]','勾吳半在海山中，聞道驅車更向東。',64,'全唐诗/poet.song.28000.json','["勾吳半在海山中，聞道驅車更向東。", "舊治空傳漢都尉，遺民無復楚諸熊。", "文章老去輕時輩，勢利恬来付覺雄。", "臥理便應長閉閣，一方還見古人風。"]'),
('bc67e747-22d4-47ae-bb69-8aba3de02da2','園人獻蒲萄','劉敞','宋','宋诗','song-poetry','','[]','婉婉柔條萬虺蟠，纍纍佳實紫金寒。',64,'全唐诗/poet.song.28000.json','["婉婉柔條萬虺蟠，纍纍佳實紫金寒。", "甘泉滲液秋香重，瑞露凝膏曉色乾。", "鮫室珠盤驚不定，蓬萊金體恨微酸。", "貴人寧借涼州牧，暫負衡門報一餐。"]'),
('5be06740-0b84-4e3b-b9d4-5495deb86684','送劉先輩恕','劉敞','宋','宋诗','song-poetry','','[]','關東少年西入都，諸老先生驚不如。',64,'全唐诗/poet.song.28000.json','["關東少年西入都，諸老先生驚不如。", "射策遂爲天下選，限年郤就里中居。", "豫章固起秋毫末，千里方從跬步初。", "會見高明成偉器，不憂綘灌毁新書。"]'),
('6e7ecb2b-b363-4a37-9b2b-af58acb5c1e0','聞范參政巡西邊','劉敞','宋','宋诗','song-poetry','','[]','漢與匈奴如弟兄，猶傳敵騎向邊城。',64,'全唐诗/poet.song.28000.json','["漢與匈奴如弟兄，猶傳敵騎向邊城。", "數煩卿士親持節，始恨儒生妄請纓。", "形勢倒懸方舛逆，計謀無益是縱横。", "古來賢哲多屠釣，公試諮詢策太平。"]'),
('999a9e4d-dfac-4d27-85a8-07d9882bce8e','次韻和王刑部秋日寄元兄尚書','劉敞','宋','宋诗','song-poetry','','[]','脊令原隰曉霜清，季子嗟行不自寧。',64,'全唐诗/poet.song.28000.json','["脊令原隰曉霜清，季子嗟行不自寧。", "歸夢時環北斗極，相輝猶隔太微星。", "源流淮水占何遠，羽翼西山藥最靈。", "接武禁嚴多故事，共看蘭玉出階庭。"]'),
('d38fe3f4-6418-441b-bac2-c2328e9e3e7d','至日早起','劉敞','宋','宋诗','song-poetry','','[]','至日應添一線長，漢儀憶奉萬年觴。',64,'全唐诗/poet.song.28000.json','["至日應添一線長，漢儀憶奉萬年觴。", "鳴珂列炬随丞相，長劍高冠滿未央。", "法從此時瞻玉座，侍臣獨許近清光。", "輶軒今出荒山外，厭見塵沙萬里黄。"]'),
('78b0d4df-fbb6-42b0-a360-303035cd5ad4','冬至','劉敞','宋','宋诗','song-poetry','','[]','殊方喜及固陰消，積雪層冰意亦聊。',64,'全唐诗/poet.song.28000.json','["殊方喜及固陰消，積雪層冰意亦聊。", "就日稍欣南極永，觀雲尚恨帝鄉遙。", "閉關自信天心復，吹律應知玉琯調。", "留滯能無越鄉戀，甘泉受計萬神朝。"]'),
('60859931-fa17-41e8-8398-64f6bbaa8d83','聞元旦大朝會','劉敞','宋','宋诗','song-poetry','','[]','玉帛雍容萬國來，帝城如斗挹春逥。',64,'全唐诗/poet.song.28000.json','["玉帛雍容萬國來，帝城如斗挹春逥。", "旂常影亂三辰象，鐘皷聲喧百里雷。", "北極正臨丹鳯扆，南山遙入萬年杯。", "諸神受計明堂定，留滯江濱志已摧。"]'),
('ed1a27d5-d90c-4e31-8f7f-6ef705751cbb','招友上清宫','劉敞','宋','宋诗','song-poetry','','[]','脩竹高松無俗塵，全然不似近城闉。',64,'全唐诗/poet.song.28000.json','["脩竹高松無俗塵，全然不似近城闉。", "黄冠習靜多藏客，野鳥忘機郤傍人。", "高閣切雲銜落日，廣庭霏雨濕清珉。", "北窗固有逍遙地，來讀離騷戴角巾。"]'),
('cc3c7891-e5cb-4854-afe5-30c0c2fc3ed5','聞范饒州移疾','劉敞','宋','宋诗','song-poetry','','[]','汲黯亷平漢主知，淮陽移病苦情羸。',64,'全唐诗/poet.song.28000.json','["汲黯亷平漢主知，淮陽移病苦情羸。", "偃藩政事應無及，伏閣精神定未衰。", "天欲期人身必乏，帝疑飛将數多奇。", "何當半夜開宣室，獨使雍容對受釐。"]'),
('3b1cae2a-3857-4bc3-a9ba-c4b5b728c347','編杜子美外集','劉敞','宋','宋诗','song-poetry','','[]','少陵詩筆捷懸河，亂後流傳簡策譌。',64,'全唐诗/poet.song.28000.json','["少陵詩筆捷懸河，亂後流傳簡策譌。", "樂自戴公全廢壞，書從魯壁幸增多。", "斯文未喪微而顯，吾道猶存嘯也歌。", "病肺悲愁情自失，苦吟時復望江沱。"]'),
('2e34c2f8-7471-41df-8a2b-9188ce67d6d5','鼓角樓宴集','劉敞','宋','宋诗','song-poetry','','[]','周城百雉擁中軍，阿閣三間麗白雲。',64,'全唐诗/poet.song.28000.json','["周城百雉擁中軍，阿閣三間麗白雲。", "燕雀總知依盛德，山河相與助雄文。", "輕裘緩带居多暇，旨酒嘉肴客易醺。", "還識魏牟懷北醺，正逢長日扇南熏。"]'),
('3f953ba3-4189-4311-b871-1a2554f381d6','夏日上府公','劉敞','宋','宋诗','song-poetry','','[]','紅芳過盡綠陰多，索寞無如長日何。',64,'全唐诗/poet.song.28000.json','["紅芳過盡綠陰多，索寞無如長日何。", "午影遲留成藴暑，熏風飄蕩作清和。", "夢餘欲騐松生腹，棋罷真知斧爛柯。", "還想高吟酬美景，訟庭岑寂長青莎。"]'),
('a987fb09-bdb2-4ea1-be5e-4d04312e086c','賀司馬君實何濟川得寵公炭','劉敞','宋','宋诗','song-poetry','','[]','上府愛才天下聞，兩君素出将軍門。',64,'全唐诗/poet.song.28000.json','["上府愛才天下聞，兩君素出将軍門。", "欲正大冶慰民望，豫排寒風作春溫。", "不煩束縕資遊說，聊復遊賢報國恩。", "自笑野人卧窮巷，負暄方擬獻天閽。"]'),
('7823cc6f-244c-4742-bd39-0371e624cc40','獨宿直舍','劉敞','宋','宋诗','song-poetry','','[]','談笑從容宫漏稀，高軒去盡掩重屝。',64,'全唐诗/poet.song.28000.json','["談笑從容宫漏稀，高軒去盡掩重屝。", "風含玉宇霜威勁，月上疏窗燭影微。", "周衞相望諠夕警，爐香不斷護朝衣。", "塵軀更覺仙山峻，旅夢端從江海歸。"]'),
('ebde33ff-c2b7-40e1-8f79-0104a6cef1ba','五月望日赴紫宸謁待旦假寐','劉敞','宋','宋诗','song-poetry','','[]','半夜北風天反寒，倒衣驚問紫宸班。',64,'全唐诗/poet.song.28000.json','["半夜北風天反寒，倒衣驚問紫宸班。", "雲容不辨陰晴際，月色猶迷爽晦間。", "獨喜鳴鷄應鐘漏，正憐殘夢識江山。", "濯纓簪筆初無補，空愧紛紛數往還。"]'),
('c4c0b252-d4a2-4cee-abd6-cf1917263cb2','送李留後守東平','劉敞','宋','宋诗','song-poetry','','[]','少壮去人如水流，似君那作待祠侯。',64,'全唐诗/poet.song.28000.json','["少壮去人如水流，似君那作待祠侯。", "高談毎及功名際，出守真寛聖主憂。", "麾下百城包海岱，道旁千騎擁貔貅。", "家聲時論俱輝赫，世将寧爲好畤羞。"]'),
('d8baa3aa-238b-45ca-88f8-a930e921d780','題連理亭','劉敞','宋','宋诗','song-poetry','','[]','靈光蕪滅泮宫平，三百年中獨此亭。',64,'全唐诗/poet.song.28000.json','["靈光蕪滅泮宫平，三百年中獨此亭。", "無復喬林見連理，尚傳高棟出窮溟。", "疏簾清簟宜炎日，菀柳長梧半廣庭。", "卧向汶篁慚薊植，燕山都欲負刋銘。"]'),
('24608127-934e-49a8-b5f3-1aac5cf31b25','答陳州通判廷評同年','劉敞','宋','宋诗','song-poetry','','[]','黄門獻賦接羣賢，上國知名獨累年。',64,'全唐诗/poet.song.28000.json','["黄門獻賦接羣賢，上國知名獨累年。", "不謂招徠從隗始，至今慚愧在盧前。", "簿書幾廢三餘學，繩墨空勤一割鉛。", "還喜遷喬友聲近，高山流水入清絃。"]'),
('422a7ec6-5c14-4644-8d55-3a3282d91f33','麃子嶺帳館寄隱直','劉敞','宋','宋诗','song-poetry','','[]','離腸易感歲華催，更席龍沙望紫台。',64,'全唐诗/poet.song.28000.json','["離腸易感歲華催，更席龍沙望紫台。", "持節不眠宵自永，聽笳無事淚空摧。", "扁舟何處山陰雪，驛使他年嶺上梅。", "欲寄一書愁已亂，天邊應候客星回。"]'),
('e6855e56-1b2b-48bb-9201-bb53400eb877','過中京走馬上平安奏状','劉敞','宋','宋诗','song-poetry','','[]','載驅冬歲極河源，状奏今朝款帝閽。',64,'全唐诗/poet.song.28000.json','["載驅冬歲極河源，状奏今朝款帝閽。", "目斷白雲浮魏闕，心先飛騎向中原。", "揣摩詎試衡人術，感激空銜國士恩。", "猶使匈奴戴黄屋，南歸慚弔陸公魂。"]'),
('95cfa969-f3a9-427b-b06c-2ce06d296193','冀州正月十六日飲席','劉敞','宋','宋诗','song-poetry','','[]','月缺雪殘雲亂飛，千燈相照續長輝。',64,'全唐诗/poet.song.28000.json','["月缺雪殘雲亂飛，千燈相照續長輝。", "寒欺短夜禁杯酒，春入東風試舞衣。", "老惜佳辰經歲得，醉驚陳迹出門非。", "漁陽鼓節尤悲壮，知我新從萬里飛。"]'),
('1b903ea1-cddd-47d2-8b81-bc5ee6cbb5dc','無雙亭觀瓊花贈聖民','劉敞','宋','宋诗','song-poetry','','[]','東風萬木競紛華，天下無雙獨此花。',64,'全唐诗/poet.song.28000.json','["東風萬木競紛華，天下無雙獨此花。", "那有靈霙凌暖日，不爲琪樹隔流沙。", "祠城寂寂春空老，江雨冥冥日易斜。", "仙品國香俱絕妙，少傾高興盡流霞。"]'),
('4cc4a971-e9dd-4cd9-8572-969f3eb5429b','園人獻芍藥','劉敞','宋','宋诗','song-poetry','','[]','淮海由來草木夭，春工殊復自嬌嬈。',64,'全唐诗/poet.song.28000.json','["淮海由來草木夭，春工殊復自嬌嬈。", "始知隋苑多佳麗，未覺吳宫久寂寥。", "冰雪肌膚明綽約，雲霞衣服潤飄蕭。", "一枝漫取堪誰贈，老去風情不自聊。"]'),
('31c6f1e7-54f8-4b28-8833-fb0fd68b451a','雨中北軒晚寝','劉敞','宋','宋诗','song-poetry','','[]','樹色禽聲相與閒，吾廬仍共一枝安。',64,'全唐诗/poet.song.28000.json','["樹色禽聲相與閒，吾廬仍共一枝安。", "浮雲蔽日綿綿雨，積水嬰城慘慘寒。", "還恐百芳從此歇，不知后土幾時乾。", "閉關高枕交游絕，一夢江湖意緒寛。"]'),
('c13db9d7-09e1-44ba-a021-57312c885743','和府公多葉榴花','劉敞','宋','宋诗','song-poetry','','[]','翠條紅蘂映貧家，笑倚熏風拂露華。',64,'全唐诗/poet.song.28000.json','["翠條紅蘂映貧家，笑倚熏風拂露華。", "重疉火雲燒落日，淺深金鼎矗丹砂。", "多情強自含春恨，不語那能學舘娃。", "但寄一枝共醉賞，試将顔色比裙紗。"]'),
('7ee5dfd9-85eb-4a75-901f-44a964da67ef','寄謝霍丘靜樂亭','劉敞','宋','宋诗','song-poetry','','[]','城西陵谷幾推移，仍有中亭玉樹枝。',64,'全唐诗/poet.song.28000.json','["城西陵谷幾推移，仍有中亭玉樹枝。", "從政真同傲吏隱，賞心能與古人期。", "誅茅改築成芳榭，引水交流漲曲池。", "聞道小山多麗句，還因春草夢新詩。"]'),
('2af8bf24-92ba-410e-9ac2-59b24741935c','晝寝','劉敞','宋','宋诗','song-poetry','','[]','屋邊高樹綠雲陰，堂下清池碧玉深。',64,'全唐诗/poet.song.28000.json','["屋邊高樹綠雲陰，堂下清池碧玉深。", "卧想溪山迷遠近，夢爲魚鳥或飛沉。", "治逢平日如無事，老覺衰容稍見侵。", "聊取南華寄齊物，不爲東武極悲吟。"]'),
('14000346-52d2-4c30-b4f9-a6f5f59b82ea','雨中家人致酒','劉敞','宋','宋诗','song-poetry','','[]','急雨連宵晝不收，草堂晨起似新秋。',64,'全唐诗/poet.song.28000.json','["急雨連宵晝不收，草堂晨起似新秋。", "山歌倚瑟清無賴，野饌隨樽特自優。", "追古最宜真渾沌，旁騷仍有畔牟愁。", "綸巾搭腦醒還醉，得此堯民已甚休。"]'),
('31c29b1e-b331-44d1-b979-48e36a46f8c3','答令狐司封使君舟中見寄','劉敞','宋','宋诗','song-poetry','','[]','汝潁相從彌十年，江樓今日遲歸船。',64,'全唐诗/poet.song.28000.json','["汝潁相從彌十年，江樓今日遲歸船。", "自驚物役還如昔，但覺詩情更爽然。", "寥落鶯花千騎裏，蒼茫烟雨萬山前。", "未知後會仍何地，彊醉春風酒似泉。"]'),
('15e6a063-5c33-4d8e-9d49-ec2f4ccc0ccd','次韻和春卿城西同步','劉敞','宋','宋诗','song-poetry','','[]','夕光郤射戍樓紅，野色遙瞻百里中。',64,'全唐诗/poet.song.28000.json','["夕光郤射戍樓紅，野色遙瞻百里中。", "玉帳坐休鈴下衛，春衣行試舞雩風。", "招擕直許威儀略，戲笑深矜意氣融。", "流水高山俱在眼，知公令望共無窮。"]'),
('62c94b31-f214-4cd4-b38d-7bb34bad43f4','往得南嶽玄猿特善嘯立秋後風雨頗凉聲尤清絕憐其山林之思爲作七言','劉敞','宋','宋诗','song-poetry','','["\u8861\u5c71"]','薄雲疏雨濕風枝，衡岳猿啼憶此時。',64,'全唐诗/poet.song.28000.json','["薄雲疏雨濕風枝，衡岳猿啼憶此時。", "回首那無萬里感，向人時作一聲悲。", "鍾儀故有南冠恨，荘舄猶多舊國思。", "車馬紛紛九域客，路傍翻笑斷腸爲。"]'),
('c88f0f9c-a480-4724-92ae-e89bfd1f5501','過思鄉嶺南茂林清溪啼鳥游魚頗有佳趣','劉敞','宋','宋诗','song-poetry','','[]','山下回溪溪上峰，清輝相映幾千重。',64,'全唐诗/poet.song.28000.json','["山下回溪溪上峰，清輝相映幾千重。", "游魚出沒穿青荇，斷蝀蜿蜒奔白龍。", "盡日浮雲横暗谷，有時喧鳥語高松。", "欲忘旅思行行遠，無奈春愁處處濃。"]'),
('59d1cfd1-ffa0-4a24-bb43-0fa6a6a7fbd9','題臨波亭','劉敞','宋','宋诗','song-poetry','','[]','綠楊芳草舊無蹊，竹隖花源敵剡溪。',64,'全唐诗/poet.song.28000.json','["綠楊芳草舊無蹊，竹隖花源敵剡溪。", "水影時翻高檻動，天形略抱曲城低。", "逢迎野興鷗雙下，點綴春愁鶯亂啼。", "宿雨楚山雲正滿，高樓莫上使人迷。"]'),
('2f51eb6a-b7c0-48ab-a4f6-ea40da477819','至日宴水上嘔吐先醉上府公','劉敞','宋','宋诗','song-poetry','','[]','南極微陽中夜新，碧池風物曉來春。',64,'全唐诗/poet.song.28000.json','["南極微陽中夜新，碧池風物曉來春。", "鼓鼙似動魚龍伏，旌旆不驚鷗鷺馴。", "東閣于今待賢士，西曹不意吐車茵。", "博陽氣度平津學，雖賤猶堪頌得人。"]'),
('9f37e7e1-1858-4336-8425-3bef6a8dcfab','送沈康學士知常州','劉敞','宋','宋诗','song-poetry','','[]','三科妙選漢臺臣，君去分符牧遠人。',64,'全唐诗/poet.song.28000.json','["三科妙選漢臺臣，君去分符牧遠人。", "富貴須爲千騎長，中和好布萬家春。", "山川陽羡由來勝，謡俗延陵自古淳。", "曾是倦遊覉旅地，送行增羡兩朱輪。"]'),
('eb2d4f77-6991-4068-829b-1418fd5d6034','送柳舒州','劉敞','宋','宋诗','song-poetry','','[]','金馬宿儒當世賢，著書天祿自忘年。',64,'全唐诗/poet.song.28000.json','["金馬宿儒當世賢，著書天祿自忘年。", "中和屢以樂職用，九次方爲耆老遷。", "何恨一回仍出守，會須千室看鳴絃。", "祗因閉閣江湖上，正想遙心象魏前。"]'),
('1cab868f-4291-441c-8d5c-aa7c9e84eb2c','送張蘇州','劉敞','宋','宋诗','song-poetry','','[]','始上蓬邱肅羽儀，舊更臺省著清規。',64,'全唐诗/poet.song.28000.json','["始上蓬邱肅羽儀，舊更臺省著清規。", "懷章又下芙蓉闕，候騎先瞻鳥隼旂。", "楚澤潦收騰駕遠，廣陵濤起渡江遲。", "吳中事事皆奇勝，還見風流太守詩。"]'),
('659bfe2b-cdbc-4e4f-bbe3-9fee863c51d6','送刁越州','劉敞','宋','宋诗','song-poetry','','[]','笑持符印下瀛州，真得千巖萬壑游。',64,'全唐诗/poet.song.28000.json','["笑持符印下瀛州，真得千巖萬壑游。", "父老爲郎無自苦，鑑中行樂不知秋。", "居人舊俗多姚姒，幕府連城半斗牛。", "太守會兼四千石，璽書寧復久淹留。"]'),
('41feaf3c-913f-482b-b3c3-50f15c2b0849','送修撰張待制知越州','劉敞','宋','宋诗','song-poetry','','[]','倦簪華筆直承明，自請分符江外行。',64,'全唐诗/poet.song.28000.json','["倦簪華筆直承明，自請分符江外行。", "真得蓬萊爲治所，徑從雲漢濯塵纓。", "山游訪古窮書穴，春事劭農見象耕。", "若向鑑中望明月，會吟還肯寄新聲。"]'),
('00fec8f9-c6fb-4df6-96f8-e10381a53de6','送張兵部知遂州','劉敞','宋','宋诗','song-poetry','','[]','錦帳郎官錦里賢，皁衣休直綵衣還。',64,'全唐诗/poet.song.28000.json','["錦帳郎官錦里賢，皁衣休直綵衣還。", "懷章過邸驚羣吏，建節乘春感舊關。", "道側壺漿積遺愛，里中牛酒慶承顔。", "朝廷孝治君先布，更聽傳歌太學間。"]'),
('26052cd5-e3c9-4c11-ad34-771640e7b6c0','送彭待制知瀛州','劉敞','宋','宋诗','song-poetry','','[]','趙北燕南如掌平，定知臺選寄長城。',64,'全唐诗/poet.song.28000.json','["趙北燕南如掌平，定知臺選寄長城。", "雅歌不廢軍中樂，緩带能令塞外清。", "傾蓋由來欣意氣，著鞭從此想功名。", "灞池送目邯鄲道，倚瑟空多惜别聲。"]'),
('5ceecf52-fa83-4ee4-bcec-eafecc4e84a6','同鄰幾持國過杜和州','劉敞','宋','宋诗','song-poetry','','[]','江南太守水齋居，殘雪層冰正滿渠。',64,'全唐诗/poet.song.28000.json','["江南太守水齋居，殘雪層冰正滿渠。", "忽憶山陰乘興往，可憐心抱向人攄。", "放歌浩蕩驚狂客，換酒從容解佩魚。", "四座歡衷兩傾倒，歸鞍欲犯夕鐘初。"]'),
('3c95aa9a-0165-435d-ab77-7c2123723102','寄獻臣','劉敞','宋','宋诗','song-poetry','','[]','通塞由來自有期，奏書未上莫嗟咨。',64,'全唐诗/poet.song.28000.json','["通塞由來自有期，奏書未上莫嗟咨。", "錐藏勉後三千客，舌在須強百萬師。", "固有青雲堪自致，暫虚丹桂不爲遲。", "如今相府聞名甚，應以雄文薦赤墀。"]'),
('b276aecc-e2c8-46ca-a17c-de286ffe6b6a','離京後寄貢甫隱直','劉敞','宋','宋诗','song-poetry','','[]','清川如带屢回環，信宿猶居百里間。',64,'全唐诗/poet.song.28000.json','["清川如带屢回環，信宿猶居百里間。", "敢恨淹留同桂渚，正憐風雨似梁山。", "月殘虚魄無由共，雲映高樓不可攀。", "郤怪夢中翻識路，化爲蝴蝶一飛還。"]'),
('30e00713-9b32-4e09-bcac-203f795cd83c','伯鎮出都後見寄','劉敞','宋','宋诗','song-poetry','','[]','疉鼓鳴笳太守船，都人傾注似登仙。',64,'全唐诗/poet.song.28000.json','["疉鼓鳴笳太守船，都人傾注似登仙。", "舊遊俯仰成陳迹，離思紛紜遶别絃。", "愁目青楓空自極，素書雙鯉不忘傳。", "恐君未得江湖樂，追詔方将急用賢。"]'),
('e77dbf0f-a9a3-48a8-a152-d1eae5f7e5eb','寄劉景烈','劉敞','宋','宋诗','song-poetry','','[]','漢設重關斥塞垣，詔移飛将護秋屯。',64,'全唐诗/poet.song.28000.json','["漢設重關斥塞垣，詔移飛将護秋屯。", "胡人無復窺南牧，燕客時應祭北門。", "清酒肥牛宴長日，輕車精騎獵平原。", "少年真得軍中樂，况復詩書盛討論。"]'),
('e22e2631-12c5-45ec-8cda-e091229b73bb','寄隱直','劉敞','宋','宋诗','song-poetry','','[]','江漢相思山萬里，君家少室定西東。',64,'全唐诗/poet.song.28000.json','["江漢相思山萬里，君家少室定西東。", "年華過去如流水，心事差池似老翁。", "一世共爭蝸角上，微生多付酒杯中。", "窮途何必多垂涕，吾更冥冥笑阮公。"]'),
('9e5f9472-e43f-4402-906e-64289ebe63c3','寄王二十','劉敞','宋','宋诗','song-poetry','','[]','昔借君家杜甫集，無端卧疾不曾編。',64,'全唐诗/poet.song.28000.json','["昔借君家杜甫集，無端卧疾不曾編。", "近從霅上吳員外，復得遺文數百篇。", "夫子刪詩吾豈敢，古人同疾意相憐。", "新書不惜傳将去，悵望秦城北斗邊。"]'),
('9c586ac2-b53c-4d74-a19f-30a3aca12fc6','新居陳州城下讀書作','劉敞','宋','宋诗','song-poetry','','[]','誅茅負郭楚人居，泌水衡門自有餘。',64,'全唐诗/poet.song.28000.json','["誅茅負郭楚人居，泌水衡門自有餘。", "數困米鹽希辟穀，素輕農圃重捐書。", "絕糧尼父期先進，畫卦羲皇序古初。", "千世風流尚在眼，百年貧病不欺予。"]'),
('650f7d83-5590-4861-8251-c3548cb6bbf7','讀漢書','劉敞','宋','宋诗','song-poetry','','[]','賈誼求爲典屬國，終軍願得使匈奴。',64,'全唐诗/poet.song.28000.json','["賈誼求爲典屬國，終軍願得使匈奴。", "和親不及當時策，慷慨猶爲大丈夫。", "百年強敵輕中國，一世奇功悲腐儒。", "聞道邊民尚嚴警，異時回首恨江湖。"]'),
('9e006c3e-e882-47fc-b6fd-e03f7d8a3d70','連雨三日東軒讀書','劉敞','宋','宋诗','song-poetry','','[]','雨中無復故人居，寂寞閉門三日餘。',64,'全唐诗/poet.song.28000.json','["雨中無復故人居，寂寞閉門三日餘。", "郤信袁安似有道，未知原憲定何如。", "浮雲極目無由卷，積蘚侵階不易除。", "正賴高眠堪自遣，時時紛亂滿床書。"]'),
('f49dc524-0678-492f-92de-292f9da2fa98','次韻滕岳州謝王南郡酒','劉敞','宋','宋诗','song-poetry','','[]','誰信專城千騎居，空齋圖籍兩三厨。',64,'全唐诗/poet.song.28000.json','["誰信專城千騎居，空齋圖籍兩三厨。", "銷憂盡付鴟夷酒，乘興兼忘阮籍塗。", "愛客誰先魏公子，長貧郤愛范萊蕪。", "歸軒仍有東門餞，顯父還須至百壺。"]'),
('4308a93f-57d3-40ce-94f6-4eb5d6e95303','和章伯鎮','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南上湘潭誰記初，北還宣室受釐餘。',64,'全唐诗/poet.song.28000.json','["南上湘潭誰記初，北還宣室受釐餘。", "共憐賈傅才無敵，真作揚雄老著書。", "調笑羣騶饑欲死，去來千騎樂何如。", "洞庭木下鱸魚熟，三嘆新詩重起予。"]'),
('40e0b9d3-ca8f-44c2-b471-d17af5d437a6','和滕巴陵寄張虢州','劉敞','宋','宋诗','song-poetry','','[]','明府功名期壮年，滯留中路鬢成斑。',64,'全唐诗/poet.song.28000.json','["明府功名期壮年，滯留中路鬢成斑。", "豈知汲黯輕爲郡，真爲劉伶善閉關。", "歸夢未嘗離帝所，謫仙寧久混人間。", "會看使者持三節，緩带輕裘且自閒。"]'),
('75150bf5-fa8d-47a1-9b2f-5e8b7126bf13','寄楊子華閣老使君','劉敞','宋','宋诗','song-poetry','','[]','吾丘不樂直承明，固請分符關外行。',64,'全唐诗/poet.song.28000.json','["吾丘不樂直承明，固請分符關外行。", "賜冊最榮批鳯尾，離羣獨恨出龍城。", "壮謀欲負腰間組，愁思空搖塞外旌。", "塵土滿衫頭半白，一聞班馬不勝情。"]'),
('b50a6be5-1dcc-48b2-8f27-41f71f0a9374','風雨','劉敞','宋','宋诗','song-poetry','','[]','晚雲蒸雨瀉驚湍，積水浮城五月寒。',64,'全唐诗/poet.song.28000.json','["晚雲蒸雨瀉驚湍，積水浮城五月寒。", "卑濕向人如楚澤，風塵回首憶長安。", "歲華徂暑參差盡，旅舘懷歸去就難。", "自昔梁山有遺操，試憑繁手一清彈。"]'),
('9afa6a8c-df76-4a83-8d76-e65bdb2c8ea8','重過華陰馬上口占寄李君錫王懿臣薛師政三漕','劉敞','宋','宋诗','song-poetry','','[]','三歲重過二華間，衰年彌覺厭塵喧。',64,'全唐诗/poet.song.28000.json','["三歲重過二華間，衰年彌覺厭塵喧。", "自知碌碌初無補，正是紛紛不憚煩。", "江壁向來憂鄭客，鼎湖今日望軒轅。", "修門漸近翻鳴咽，滿面風埃涕淚痕。"]'),
('d34da4bb-720b-4eac-8544-dbf3099ee6f1','過中京後寄和貢兩弟','劉敞','宋','宋诗','song-poetry','','[]','歸鞍蹀躞弄輕塵，滿眼韶光破宿雲。',64,'全唐诗/poet.song.28000.json','["歸鞍蹀躞弄輕塵，滿眼韶光破宿雲。", "去國幾愁歌白紵，上天真喜望緹羣。", "華林雪盡鶯先囀，廣陌風多草競熏。", "我欲還家千日飲，益須釀酒張吾軍。"]'),
('b51eacea-c8f0-4f8b-976e-7fe1b93ea049','舍弟東還病中口占七言奉寄景仁彝唐公甫','劉敞','宋','宋诗','song-poetry','','[]','眼暗頭昏逾十旬，涔涔終歲髮華新。',64,'全唐诗/poet.song.28000.json','["眼暗頭昏逾十旬，涔涔終歲髮華新。", "幽如羑里迷天路，醉似中山與鬼鄰。", "閉閣郤憐廷掾力，廢書彌信道家淳。", "修門已後君無恙，試枉招魂慰滿身。"]'),
('fd3dfdba-2557-44bc-8081-109bc9a75005','句容劉同年寄示游山詩及术煎','劉敞','宋','宋诗','song-poetry','','[]','江外三峰倚碧天，古來相續幾神仙。',64,'全唐诗/poet.song.28000.json','["江外三峰倚碧天，古來相續幾神仙。", "自無飛骨何由到，賴有新詩尚許傳。", "餌术始知堪度世，聽松真得自忘年。", "會驅雞犬從君隱，與擇華陽數畝田。"]'),
('1d714075-cb42-4611-a6ea-559b7581836f','登城','劉敞','宋','宋诗','song-poetry','','[]','前歲登城日幾回，去年猶記隔辰來。',64,'全唐诗/poet.song.28000.json','["前歲登城日幾回，去年猶記隔辰來。", "老侵筋力銖銖减，慵壞心情寸寸灰。", "幸有風光相挽引，那無賓友共追陪。", "北臺好在中秋月，便是重陽菊蘂開。"]'),
('4fc9b388-ae13-4295-af52-8e6874c348e7','喜春卿自陜歸','劉敞','宋','宋诗','song-poetry','','[]','休汝曾更月旦評，幾年漂泊倦塵冥。',64,'全唐诗/poet.song.28000.json','["休汝曾更月旦評，幾年漂泊倦塵冥。", "神峰好在巖巖石，符采依然兩兩星。", "天祿自嫌書尚白，絳帷猶喜眼猶青。", "召南風什知多少，一一親弦更許聽。"]'),
('b1e27622-692a-4cb8-a26a-21770d4315f3','聞鶯','劉敞','宋','宋诗','song-poetry','','[]','舍南舍北柳陰陰，竟日啼鶯不自禁。',64,'全唐诗/poet.song.28000.json','["舍南舍北柳陰陰，竟日啼鶯不自禁。", "羈旅可憐還擇木，間關似欲向知音。", "鴂鶗無事催芳草，燕雀相喧守舊林。", "幽獨閉門驚歲晚，固煩求友慰愁心。"]'),
('68a78726-0c28-4104-af76-8099f0a57c42','寄貢甫時遷居城南水上','劉敞','宋','宋诗','song-poetry','','[]','城南風物似江湖，卜築尤宜近水隅。',64,'全唐诗/poet.song.28000.json','["城南風物似江湖，卜築尤宜近水隅。", "俗薄容垂真釣否，庭閒得種此君無。", "關身調度惟存劍，適意圖書略滿厨。", "心遠地偏俱可喜，免逢甲馬與塵塗。"]'),
('4f20d433-ab8d-4368-85b7-63c976e9fa3e','中使傳宣二月一日史院賜御筵某亦預召作七言呈禹玉真孺景仁三內翰','劉敞','宋','宋诗','song-poetry','','[]','虞書紀典上稽唐，魯史傳經近屬商。',64,'全唐诗/poet.song.28000.json','["虞書紀典上稽唐，魯史傳經近屬商。", "刻玉春山瞻氣象，積星東壁聚鈎芒。", "朝思膏飫懽情洽，天令中和盡刻長。", "雖引客卿譏子墨，翰林還許望清光。"]'),
('b2ff6895-10de-4a4b-a13e-f8232d2d860d','答次道學士','劉敞','宋','宋诗','song-poetry','','[]','世路相逢難自期，江城三歲想瓊枝。',64,'全唐诗/poet.song.28000.json','["世路相逢難自期，江城三歲想瓊枝。", "寧知邂逅驅千騎，亦復東南寄一麾。", "把酒聊同醉鄉樂，看花欲後麥秋時。", "舊都紅藥猶堪賞，不負風流謝客詩。"]'),
('69aabc42-caad-453b-80ae-22f511fb5fd6','送陜府祖學士','劉敞','宋','宋诗','song-poetry','','[]','承明持槖倦徂年，自陜分符得近關。',64,'全唐诗/poet.song.28000.json','["承明持槖倦徂年，自陜分符得近關。", "人物風流二南後，山河形勢兩周間。", "莫嗟落魄書猶白，共許優游鬢未斑。", "數醉申湖好風月，傳車行且趣君還。"]'),
('205055ac-abc0-4488-a4f7-ec1777c72988','酒席贈欽聖提刑學士','劉敞','宋','宋诗','song-poetry','','[]','棄捐不預朝廷議，落莫真成老禿翁。',64,'全唐诗/poet.song.28000.json','["棄捐不預朝廷議，落莫真成老禿翁。", "放眼能寛蜀郡禮，高賢信有古人風。", "都門倐忽三年别，樽酒淹留一笑同。", "還有野歌隨拙舞，肯敎庭炬徹明紅。"]'),
('d91b9527-1fdb-4a56-95df-fae07aea73cd','秋日和韻','劉敞','宋','宋诗','song-poetry','','[]','禁垣清切近雲霓，楚客逢秋意亦悲。',64,'全唐诗/poet.song.28000.json','["禁垣清切近雲霓，楚客逢秋意亦悲。", "拙學由來玄尚白，敝裘何意素成緇。", "解嘲郤笑朱丹轂，迕俗兼懲百一詩。", "短景正須棋玩歲，薄寒寧厭酒盈巵。"]'),
('c1be9b49-5ebd-4043-bfe3-460f46672b85','涵虚閣晝卧','劉敞','宋','宋诗','song-poetry','','[]','池水無波清照心，庭柯交讓綠成陰。',64,'全唐诗/poet.song.28000.json','["池水無波清照心，庭柯交讓綠成陰。", "游魚自與江湖闊，翔鳥不期山谷深。", "身外悠悠日復夜，世間擾擾古猶今。", "寄愁天上從吾樂，高卧聊爲招隱吟。"]'),
('45d6d966-346d-4b45-ab47-889753c54ce6','于司録東園','劉敞','宋','宋诗','song-poetry','','[]','辟疆園圃厭城闉，聞道池臺事事新。',64,'全唐诗/poet.song.28000.json','["辟疆園圃厭城闉，聞道池臺事事新。", "自置一樽消永日，别留槃石待幽人。", "雨添草色迷三徑，風散花香入四鄰。", "亦欲肩輿乘興去，主人何必舊相親。"]'),
('d6a465a4-d34f-448e-849d-adcab05a83e8','送劉郎中監靈仙觀盡室而往','劉敞','宋','宋诗','song-poetry','','["\u8861\u5c71"]','華髪星郎七十餘，碧山遙訪羽人居。',64,'全唐诗/poet.song.28000.json','["華髪星郎七十餘，碧山遙訪羽人居。", "白石不爲天上藥，淮南欲試枕中書。", "長纓自濯滄浪水，高蓋仍瞻駟馬車。", "福地神仙應易致，幾時南嶽侯乘輿。"]'),
('f04673b4-bf39-44fd-bf33-b73ef2869c81','奉和諸公御製後苑賞花釣魚','劉敞','宋','宋诗','song-poetry','','[]','四照繁英拂檻開，九重芝蓋賞春來。',64,'全唐诗/poet.song.28000.json','["四照繁英拂檻開，九重芝蓋賞春來。", "卿雲共和光華旦，瑞霧偏凝沆瀣杯。", "池藻躍魚波淡蕩，林光傾日景徘徊。", "淮陽閉閣頭今白，夢達鈞天惜未陪。"]'),
('923301e0-5dd1-42f8-ab0b-28abd8d0edab','秋晚西樓','劉敞','宋','宋诗','song-poetry','','[]','微霜欲堕木葉脱，積潦已收天宇清。',64,'全唐诗/poet.song.28000.json','["微霜欲堕木葉脱，積潦已收天宇清。", "皎皎日華映林莽，瀟瀟風色閉柴荆。", "正憐戎馬秋防塞，何處悲笳暮繞城。", "回首浮雲滿西北，七哀還見古人情。"]'),
('0cb76705-714c-4da1-9110-51e6cba9598a','送劉中允渙年五十餘以頴上縣令致仕卜居廬山','劉敞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五柳先生厭俗紛，拂衣歸去卧江濱。',64,'全唐诗/poet.song.28000.json','["五柳先生厭俗紛，拂衣歸去卧江濱。", "松菊還同昔人好，山川復似向時新。", "瀑泉飛雪千巖晚，仙杏蒸霞萬樹春。", "亦欲扁舟乘興往，滄浪借取濯埃塵。"]'),
('048cc264-04ec-4c08-9878-9f017687189f','答令狐司封求酒','劉敞','宋','宋诗','song-poetry','','[]','馮公郎隱髪蒼蒼，撥棄塵煩得醉鄉。',64,'全唐诗/poet.song.28000.json','["馮公郎隱髪蒼蒼，撥棄塵煩得醉鄉。", "富貴兩行安用聖，滄浪獨醒詎非狂。", "顧慚宿釀能千日，遠愧深衷頌短章。", "當就天公借北斗，更傾東海益君觴。"]'),
('0658e062-94a3-45c2-9a02-7aa2302e449d','持禮北庭回示希元并寄之翰彦猷當世','劉敞','宋','宋诗','song-poetry','','[]','肅承朝命謁穹廬，郤卧空牀涕滿裾。',64,'全唐诗/poet.song.28000.json','["肅承朝命謁穹廬，郤卧空牀涕滿裾。", "不敢復論天下事，更能重讀篋中書。", "男兒戰死自無恨，國勢倒懸誰爲攄。", "我本不來人強我，百年空使愧相如。"]'),
('5b4d7ce0-bd16-4c3c-8d85-6d33d3f1a37f','聞鶯','劉敞','宋','宋诗','song-poetry','','[]','陰陰老樹連村路，羃羃輕烟過雨天。',64,'全唐诗/poet.song.28000.json','["陰陰老樹連村路，羃羃輕烟過雨天。", "長愛禽聲能永日，似于鶯友欲忘年。", "朱纓紫椹看齊熟，深巷荒城得屢遷。", "朗詠謝公池上作，勿驚春物變熏絃。"]'),
('9457a83e-daea-4235-b855-8e75e84814b5','元日發古北口寄禹玉直孺昌言三閣老','劉敞','宋','宋诗','song-poetry','','[]','桂酒椒盤共發春，山川雖舊物華新。',64,'全唐诗/poet.song.28000.json','["桂酒椒盤共發春，山川雖舊物華新。", "仲尼魯史王正月，泰帝河圖歲甲寅。", "玉殿聳聞斟白獸，火城想見接清塵。", "應憐二使星安在，北斗杓端析木津。"]'),
('0c871335-fe95-4c5e-981c-6862c9483c03','立春後遊杜城陳丞相郊園','劉敞','宋','宋诗','song-poetry','','[]','韋杜勝遊誰可尋，相君舊隱對雲岑。',64,'全唐诗/poet.song.28000.json','["韋杜勝遊誰可尋，相君舊隱對雲岑。", "水渠婉轉蛟蛇活，霜竹參差孔翠深。", "故老能言卧龍地，兒童不用滿籯金。", "郡齋殊負青山郭，空挹芳樽慰客心。"]'),
('ce43a6fc-1aa4-4de3-99da-59975e123e20','至日登樓','劉敞','宋','宋诗','song-poetry','','[]','南極陽生天地新，高樓氣色已含春。',64,'全唐诗/poet.song.28000.json','["南極陽生天地新，高樓氣色已含春。", "得無鴻鴈翻歸翼，應有龍蛇動蟄鱗。", "亦復書雲占楚歳，不辭爲壽引湘醇。", "甘泉從祀雖能賦，悵望鈎陳擁北辰。"]'),
('2e53191f-f901-4d29-8f75-47f171e90ccf','久雨','劉敞','宋','宋诗','song-poetry','','[]','長至須臾二月來，朔雲零雨未嘗開。',64,'全唐诗/poet.song.28000.json','["長至須臾二月來，朔雲零雨未嘗開。", "陰藏晝景長繡線，寒奪陽和潛律灰。", "宿翼困冰多後鴈，暗香漂水惜殘梅。", "撩晴召暖無他術，安得凉風一夜回。"]'),
('129a8f44-7c8b-41eb-9ea8-bd3b7850c04a','同鄰幾伯鎮觀秘閣壁上蘇子美草書','劉敞','宋','宋诗','song-poetry','','[]','蘇子佯狂不自疑，漢庭籍甚莫言非。',64,'全唐诗/poet.song.28000.json','["蘇子佯狂不自疑，漢庭籍甚莫言非。", "放歌金馬居常醉，窮老滄洲不更歸。", "浮世功名均夢寐，平生翰墨獨光輝。", "壁間數字龍蛇動，神物通神亦恐飛。"]'),
('6c046cac-edb9-43ef-a221-3c2c888cbafd','立春','劉敞','宋','宋诗','song-poetry','','[]','臘去春歸意可憐，久爲羈客海西偏。',64,'全唐诗/poet.song.28000.json','["臘去春歸意可憐，久爲羈客海西偏。", "溫風泛泛生卮酒，和氣融融媚管絃。", "剪綵直爲兒女戲，土牛向自國家傳。", "事情爭愛新翻擲，還道今年勝去年。"]'),
('6e61dca7-a5be-45a8-a215-c86ede4dbc5a','立春日紫宸拜賜歸持國見率同過江十不行','劉敞','宋','宋诗','song-poetry','','[]','蓬萊佳氣舊無時，春物迎新特更宜。',64,'全唐诗/poet.song.28000.json','["蓬萊佳氣舊無時，春物迎新特更宜。", "燕識玉箱來自早，漏隨宫線報還遲。", "溝聲破凍纔通苑，酒力含風易滿卮。", "蓬鬢不堪雙綵勝，懶随君向習家池。"]'),
('9bd3a544-9d9e-4f76-8b51-9b558cba90ac','賀隱直','劉敞','宋','宋诗','song-poetry','','[]','寂寞三年倦一飛，知音不限向來希。',64,'全唐诗/poet.song.28000.json','["寂寞三年倦一飛，知音不限向來希。", "雖然主簿非高士，猶喜分曹近太微。", "吏部銓中超俗状，京官班首望天威。", "漢儒多有司空掾，努力新書更發揮。"]'),
('05c88ca6-a1de-4808-9141-89cad4381c68','送楊景修秘校歸','劉敞','宋','宋诗','song-poetry','','[]','武夷曾孫塵外仙，手擕桂枝歸故山。',64,'全唐诗/poet.song.28000.json','["武夷曾孫塵外仙，手擕桂枝歸故山。", "夸鄉始信一經是，衣錦不須三組還。", "蓬萊觀書聊復爾，枳棘棲鸞殊未然。", "野人放蕩辱先進，慚愧竹林諸阮間。"]'),
('48bf0eb0-1551-4524-8dc7-0e599caa5a95','答校書郎孫侔少述','劉敞','宋','宋诗','song-poetry','','[]','金華勸講愧通經，銅虎分憂強請行。',64,'全唐诗/poet.song.28000.json','["金華勸講愧通經，銅虎分憂強請行。", "千騎亦知翁子貴，一麾誰覺仲容輕。", "西賓落莫空遺俗，北斗闌干有舊城。", "欲作過秦無與語，故人高論憶盱衡。"]'),
('e46c76e7-6e31-46b1-817c-616cd631a319','次韻奉答屯田宋員外','劉敞','宋','宋诗','song-poetry','','[]','汗血龍文千里駒，長楸未試跼庭隅。',64,'全唐诗/poet.song.28000.json','["汗血龍文千里駒，長楸未試跼庭隅。", "一麾幾老諸侯相，五日初還建禮趨。", "獨得鳯毛驚衆目，相望花蕚照亨衢。", "白頭漫感悲秋賦，自笑妨賢此禁塗。"]'),
('7fb3d93d-ad74-46da-82fa-9ac2b3a7c244','爲轉運沈郎中題','劉敞','宋','宋诗','song-poetry','','[]','寶軸牙籤三萬餘，中園華宇蔭清渠。',64,'全唐诗/poet.song.28000.json','["寶軸牙籤三萬餘，中園華宇蔭清渠。", "風流復見郊居賦，榮觀歸乘使者車。", "俯仰江山樂無有，優游文籍昔誰如。", "何當去此從君語，盡得平生未見書。"]'),
('429f8cb5-0faf-491e-908c-995669a492ce','題溪堂','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','蘇俠遺懽小洞庭，高堂殊恨曲池平。',64,'全唐诗/poet.song.28000.json','["蘇俠遺懽小洞庭，高堂殊恨曲池平。", "山川滿目仍非昔，魚鳥依人自不驚。", "瑣細幽花相嫵媚，回環流水共澄清。", "秋風初足江湖意，不作鱸蓴萬里情。"]'),
('df112e79-9e81-49a0-bb71-c86e66ae55b9','和伯鎮初拜湖州','劉敞','宋','宋诗','song-poetry','','[]','君向江湖領一麾，親歡自與宿心期。',64,'全唐诗/poet.song.28000.json','["君向江湖領一麾，親歡自與宿心期。", "腰間紫綬新光彩，都內青錢厚寵私。", "廐吏莫催乘傳去，詔恩方許戌瓜時。", "碧瀾堂上青山下，爛醉尋春亦未遲。"]'),
('6e782ccc-e437-4b11-b19e-6897809ee0f7','和韓司諫移亳宫雙檜植于道山','劉敞','宋','宋诗','song-poetry','','[]','仙子分根白鹿檀，定知高峭出巖端。',64,'全唐诗/poet.song.28000.json','["仙子分根白鹿檀，定知高峭出巖端。", "濃雲借色曾無變，初日移陰漸可觀。", "風外共成蒼鶴舞，夜深齊作翠幢看。", "人今俟爾爲梁棟，慎勿輪囷取自安。"]'),
('15c16462-7c43-4648-a644-c2c4959764a4','新秋','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','七月荆人亦具裘，朔風颯颯動昭丘。',64,'全唐诗/poet.song.28000.json','["七月荆人亦具裘，朔風颯颯動昭丘。", "巫峽出雲杳無定，洞庭飛月絕堪愁。", "長歌濯足滄浪水，回首開襟西北樓。", "宇宙歊蒸暫瀟灑，小山青桂與淹留。"]'),
('5a67e48a-7efe-47b1-b955-cf97a40e7d08','和宿直晨出遂赴奉慈齋告寄持國子履','劉敞','宋','宋诗','song-poetry','','[]','玉殿鳴鞘闢寝闈，銀臺歸騎蹀霜蹄。',64,'全唐诗/poet.song.28000.json','["玉殿鳴鞘闢寝闈，銀臺歸騎蹀霜蹄。", "樓光已映朝霞動，樹色猶銜宿靄迷。", "身貴承明翻厭直，歲窮樽酒幸招擕。", "太常幾日休齋禁，亦欲從公醉似泥。"]'),
('76a23ea3-0c53-46b4-af01-959c01c9cd1a','遊平山堂寄歐陽永叔內翰','劉敞','宋','宋诗','song-poetry','','[]','蕪城此地遠人寰，盡借江南萬疉山。',64,'全唐诗/poet.song.28000.json','["蕪城此地遠人寰，盡借江南萬疉山。", "水氣横浮飛鳥外，嵐光平堕酒杯間。", "主人寄賞來何暮，遊子銷憂醉不還。", "無限秋風桂枝老，淮王先去可能攀。"]'),
('9464393d-c3e4-4585-b0ab-495b1acddd29','再遊平山堂','劉敞','宋','宋诗','song-poetry','','[]','背城歷歷纔十里，經歲悠悠能一來。',64,'全唐诗/poet.song.28000.json','["背城歷歷纔十里，經歲悠悠能一來。", "可惜薄書捐白日，強從賓客宴平臺。", "暮雲自與千山合，醉眼時令萬宇開。", "老子誰憐興不淺，黄花欲落更添杯。"]'),
('b8b686f2-422f-4765-b148-ade78ced51bc','病中口占七言奉送前成都尹呂寶臣龍圖還朝','劉敞','宋','宋诗','song-poetry','','[]','開遠故城長樂坡，三年從此送君過。',64,'全唐诗/poet.song.28000.json','["開遠故城長樂坡，三年從此送君過。", "宦遊不道相逢少，愁病何堪惨别多。", "強敵猶知奉威信，巴童莫忘習中和。", "廟堂應趨緇衣拜，少緩離亭白玉珂。"]'),
('8c1f7b26-4733-4687-ba97-bdcd5a40f92b','月夜獨酌','劉敞','宋','宋诗','song-poetry','','[]','涼月破雲涵碧霄，暫憐庭宇斷塵囂。',64,'全唐诗/poet.song.28000.json','["涼月破雲涵碧霄，暫憐庭宇斷塵囂。", "露翻高樹光明滅，風度疏篁影動搖。", "驚鵲似投人處息，暗蟲如恨歳華凋。", "短歌薄酒清輝裏，百感先秋不自聊。"]'),
('864dbab5-94a9-440f-80c5-5fb364b6832a','奉和永叔雨中見寄','劉敞','宋','宋诗','song-poetry','','[]','泥塗后土未曾亁，騎馬相過行路難。',64,'全唐诗/poet.song.28000.json','["泥塗后土未曾亁，騎馬相過行路難。", "卧聽鷄鳴知景晦，起逢花謝惜春殘。", "銀臺幸闋連宵直，樽酒能謀盡日懽。", "紅藥蒼苔雖寂寞，多情肯作舊游看。"]'),
('3c2687c4-d42d-4698-b2fb-ab77e801117a','城樓晚望','劉敞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','長夏淮天郤似秋，居人未解白貂裘。',64,'全唐诗/poet.song.28000.json','["長夏淮天郤似秋，居人未解白貂裘。", "雲起岱山時漲雨，風迎滄海欲横流。", "日邊渇問長安使，天際頻瞻賈客舟。", "自是七哀宜寫望，不關非土故登樓。"]'),
('704e799f-fd0a-4a86-9845-b50f75d28311','答宋都官游驪山見寄','劉敞','宋','宋诗','song-poetry','','[]','華清宫殿映春暉，未醉三晡莫遽歸。',64,'全唐诗/poet.song.28000.json','["華清宫殿映春暉，未醉三晡莫遽歸。", "人事廢興猶可記，風光流轉不相違。", "歌臨灞岸朱絃脆，走度章臺汗馬肥。", "自是秦川貴公子，城隅相望不能飛。"]'),
('eb96690b-c1a5-4f7f-ba7a-ad04904e629c','和孫少述題虎丘','劉敞','宋','宋诗','song-poetry','','[]','吳墟秦燼滅遺蹤，誰見千巖鎖梵宫。',64,'全唐诗/poet.song.28000.json','["吳墟秦燼滅遺蹤，誰見千巖鎖梵宫。", "化出樓臺雙樹外，密移天地一壺中。", "石形虎踞森相向，劍氣龍盤冷射空。", "羈宦無由蠟山屐，因君詩句夢江束。"]'),
('f1c17e56-774d-4acb-9ca8-a7d9c0f37545','和孫侔鴈蕩山二首  其一','劉敞','宋','宋诗','song-poetry','','[]','鼇翻溟漲折靈山，漂落塵區莽眇間。',64,'全唐诗/poet.song.28000.json','["鼇翻溟漲折靈山，漂落塵區莽眇間。", "自有神仙護真境，故令林木斷人寰。", "碧城萬玉重重合，琪樹三株寂寂間。", "安得長風破高浪，拂衣東去一躋攀。"]'),
('e2c22d59-9e28-4c99-bbc6-b12e34e84484','和孫侔鴈蕩山二首  其二','劉敞','宋','宋诗','song-poetry','','[]','天台賦後世多賢，復在君家鴈蕩篇。',64,'全唐诗/poet.song.28000.json','["天台賦後世多賢，復在君家鴈蕩篇。", "氣逸還令人聳動，境幽初許俗流傳。", "萬峰林立浮雲外，一徑梯横絕海邊。", "聞道歸艎從此逝，秋風招隱特依然。"]'),
('534574ce-19c1-418e-9b59-8bdac358e835','答羅同年憶楸花之作','劉敞','宋','宋诗','song-poetry','','[]','勾稽嚴密不通賓，因見楸花憶去春。',64,'全唐诗/poet.song.28000.json','["勾稽嚴密不通賓，因見楸花憶去春。", "當日同僚嘗把酒，于今邑子遠思人。", "臨安草木皆蒙錦，金谷池塘各鬥茵。", "自笑癡兒了公事，經年不識酒沾唇。"]'),
('91bc69bf-6fb7-4d84-a413-6dc93148d8c7','依韻謝某送行詩','劉敞','宋','宋诗','song-poetry','','[]','天涯畢昴隔烟塵，風雪梁山憶侍親。',64,'全唐诗/poet.song.28000.json','["天涯畢昴隔烟塵，風雪梁山憶侍親。", "行記簡書聊接淅，去懷印綬正逢春。", "評依月旦情增戀，詩感蘭陔意重陳。", "先向沙隄侯歸騎，郤瞻霖雨作伊晨。"]'),
('c0c5c0fe-4903-4e71-bd44-6e1f95b1f7ba','閣下午寝晚歸','劉敞','宋','宋诗','song-poetry','','[]','高閣遙依日月光，蒼苔重疉紫微芳。',64,'全唐诗/poet.song.28000.json','["高閣遙依日月光，蒼苔重疉紫微芳。", "蝉聲已覺迎秋急，雲物還驚過午凉。", "獨往山林非復昔，夢爲魚鳥不能忘。", "芝泥封詔雞棲樹，半落宫槐滿地黄。"]'),
('5c8d2f85-10a0-4ce9-b404-e8f0223dc847','觀沖卿所試詩賦賀府君','劉敞','宋','宋诗','song-poetry','','[]','斗城烟霧隔金鑾，日破輕陰玉滴寒。',64,'全唐诗/poet.song.28000.json','["斗城烟霧隔金鑾，日破輕陰玉滴寒。", "捷筆補天凌造化，高文驚世湧波瀾。", "夢成白鳯飛鳴遠，功就丹梯步武寛。", "回首蓬萊笑清淺，春風前後發芝蘭。"]'),
('5fd391e3-5232-4c7f-88bd-70e3b54c8171','歲晚偶作','劉敞','宋','宋诗','song-poetry','','[]','不嫌臘過催人老，直恐春歸惱客愁。',64,'全唐诗/poet.song.28000.json','["不嫌臘過催人老，直恐春歸惱客愁。", "柳眼梅心俱次苐，雲容雪意與淹留。", "歲窮楚俗依稀古，冰解巴江洶湧流。", "遣興長須一樽酒，呼兒徑典敝貂裘。"]'),
('6debef25-80cc-483f-803a-ab0f7a9bf0a6','立春日過薦福寺','劉敞','宋','宋诗','song-poetry','','[]','一歲還随一歲來，立春人日競相催。',64,'全唐诗/poet.song.28000.json','["一歲還随一歲來，立春人日競相催。", "細細谷風能破凍，熙熙習俗似登臺。", "初陽弄色明高柳，殘雪留寒伴落梅。", "淮北風光元自好，壮心摧謝不勝哀。"]'),
('a42fa237-9cf3-4245-bab8-ff309c51ecec','宿齋中書外省答永叔京尹內翰朝回馬上見寄并謝子華次韻','劉敞','宋','宋诗','song-poetry','','[]','朝罷章臺日幾竿，遙聞走馬試雕鞍。',64,'全唐诗/poet.song.28000.json','["朝罷章臺日幾竿，遙聞走馬試雕鞍。", "春風自發遊人意，宿雪偏留下省寒。", "坐久獨知宫漏永，詩成誰盡玉堂懽。", "會須一辦如泥醉，從笑歸來筆向乾。"]'),
('aefc5756-c3c3-42b3-af55-7dd981f8de40','富谷老人臧用自云本京師兵士咸平中沒番五十餘年矣','劉敞','宋','宋诗','song-poetry','','[]','白髪衰翁雙涕零，曾随諸将戰咸平。',64,'全唐诗/poet.song.28000.json','["白髪衰翁雙涕零，曾随諸将戰咸平。", "一捐左衽迷歸路，郤問中華似隔生。", "思報漢恩身已朽，恥埋胡壤死無名。", "今朝縱觀非他意，得見官儀眼自明。"]'),
('fe98d4fd-8415-462b-80a4-2e9fa4f9e92f','都運陳光祿自河北移陜西以病不得詣别作七言奉送','劉敞','宋','宋诗','song-poetry','','[]','西州判袂忽三年，夢想城南尺五天。',64,'全唐诗/poet.song.28000.json','["西州判袂忽三年，夢想城南尺五天。", "謝病歸來真老矣，傷春刻意益茫然。", "受降塞外威名遠，足食關中寄注專。", "北顧邯鄲復臨灞，更能一醉促哀弦。"]'),
('7c55f060-a7d4-4804-8683-93ae84953b43','游禪智寺','劉敞','宋','宋诗','song-poetry','','[]','重岡斗上半浮雲，行繞芳叢日已曛。',64,'全唐诗/poet.song.28000.json','["重岡斗上半浮雲，行繞芳叢日已曛。", "蒙頂川原眼中見，揚州歌吹竹西聞。", "梵王重壁臺先毁，古佛雙林火亦焚。", "會看旃檀重滿地，莫悲糜鹿向成羣。"]'),
('cfb818f7-437d-4b8f-a3d4-3286a65d2383','寄題黄州李史君韋杜山居','劉敞','宋','宋诗','song-poetry','','[]','主人朝隱望誰先，卜築城南地復偏。',64,'全唐诗/poet.song.28000.json','["主人朝隱望誰先，卜築城南地復偏。", "服食早知仁者壽，退休前惜大夫賢。", "封千戶比蒼蒼竹，畝一鍾金上上田。", "從此去天纔尺五，幾時雞犬亦登仙。"]'),
('f84f1fc0-7945-4213-af2c-03e866ba35e3','和龐相公寄題白郎中鳯棲巖山居','劉敞','宋','宋诗','song-poetry','','[]','丹鳯何年此地棲，蒼山流水入巖扉。',64,'全唐诗/poet.song.28000.json','["丹鳯何年此地棲，蒼山流水入巖扉。", "主人早逐長離去，邑子先期駟馬歸。", "脩竹萬竿終歲碧，蹲鴟千畝入秋肥。", "已聞父老釃牛酒，會看夸鄉畫錦衣。"]'),
('a6fcd769-932d-44ec-a0d9-18729e263d79','次韻酬張直溫','劉敞','宋','宋诗','song-poetry','','[]','未曾相見已相知，自許聞絃可識微。',64,'全唐诗/poet.song.28000.json','["未曾相見已相知，自許聞絃可識微。", "毎信白頭于義得，豈将青眼向君違。", "坳堂仍滯三年蟄，寥廓方看萬里飛。", "誰謂夜光投道路，莫因長鋏起思歸。"]'),
('f925912b-976e-483a-8a37-b04d57744227','陪府公泛汝水作七言奉呈府公給事','劉敞','宋','宋诗','song-poetry','','[]','寒波略傍曲城流，彩鷁遙兼翠蓋浮。',64,'全唐诗/poet.song.28000.json','["寒波略傍曲城流，彩鷁遙兼翠蓋浮。", "努力濟川天下望，暫時乘興鑒中游。", "蓬萊清淺迷滄海，河漢昭回隔斗牛。", "君看龍門盛賓客，世間還自有仙舟。"]'),
('45a2494c-6170-42ae-99dd-75f518eb50e5','聞韓范移軍涇原兼督關中四路','劉敞','宋','宋诗','song-poetry','','[]','涇原非遠略，韓范各名卿。',96,'全唐诗/poet.song.28000.json','["涇原非遠略，韓范各名卿。", "地盡三秦國，身當萬里城。", "指麾沙漠静，談笑鐵山輕。", "報國心如日，憂民病若酲。", "終軍材冠世，汲黯直知名。", "風雪隨車騎，鷹鸇起旆旌。", "年年戰頻衄，事事淚堪横。", "會刷蒼生恥，重看鑄劍耕。"]'),
('8b25ef11-8fe7-4656-89ea-c0a3a3da766f','送隱直辟青州幕府','劉敞','宋','宋诗','song-poetry','','[]','全齊七十城，表海寄名卿。',72,'全唐诗/poet.song.28000.json','["全齊七十城，表海寄名卿。", "開府馳羔鴈，除書得俊英。", "借籌心感激，憑軾氣縱横。", "浩蕩軍中樂，從容稷下生。", "士由知己用，祿以及親榮。", "送别羞長鋏，能無歸去聲。"]'),
('af6654fe-72ce-4492-a43f-1b133c256b3f','駕幸飛山教場閱武侍宴','劉敞','宋','宋诗','song-poetry','','[]','冬令三農畢，時巡萬乘行。',144,'全唐诗/poet.song.28000.json','["冬令三農畢，時巡萬乘行。", "川源分壁壘，貔虎望麾旌。", "王氣雲成殿，天光日繞營。", "風隨鼓桴急，塵絕馬蹄輕。", "發石機投短，抨弦火激眀。", "響振摧列缺，影墮落欃槍。", "令下凝霜肅，恩加挾纊平。", "搴旗輕俯仰，奪槊妙縱横。", "壯士前歌勇，儒生從觀榮。", "炙行熢燧舉，觴溢海濤傾。", "清道遙傳警，鳴鞭夕向城。", "欲知威略遠，區外讋天聲。"]'),
('cebc8bde-6266-47a7-aef6-d08a90f53e7d','鳳覽德輝','劉敞','宋','宋诗','song-poetry','','[]','婉婉丹山鳳，飄飄萬里飛。',72,'全唐诗/poet.song.28000.json','["婉婉丹山鳳，飄飄萬里飛。", "識時翻羽翼，覽德下光輝。", "逸勢凌雲起，和聲遂吹微。", "層霄猶降顧，治世獨知歸。", "繒繳初無慮，梧桐正可依。", "願分阿閣地，永謝楚狂譏。"]'),
('ee8b5567-92dd-46dd-940f-ee91ef8aeb08','校獵同支使作','劉敞','宋','宋诗','song-poetry','','[]','長郊被山澤，積雪浄林臯。',120,'全唐诗/poet.song.28000.json','["長郊被山澤，積雪浄林臯。", "殺物天時武，從禽士氣豪。", "飈塵遂車騎，鷹隼亂旌旄。", "壯節排蒼極，歡聲激怒濤。", "興餘生鼻火，空闊散風毛。", "狡穴無遺噍，窮巢或暗嘷。", "中原遂除害，汗馬敢辭勞。", "勸賞車行炙，均恩士籍醩。", "歸塗喧鼓吹，餘勇屬鞬櫜。", "快意當如此，君看歲月淊。"]'),
('22ad0210-2d16-4520-95c7-645620d04904','得隱直書重陽日登高于三門禹廟悵然恨不參之作一詩以寄','劉敞','宋','宋诗','song-poetry','','[]','九日情何極，三門望特高。',144,'全唐诗/poet.song.28000.json','["九日情何極，三門望特高。", "大河横日夜，砥柱析毫毛。", "眺覽興亡古，登臨意氣豪。", "窮源悲絕域，微禹歎容刀。", "萬事浮雲去，前賢逝水滔。", "秋陰生遠塞，殺氣起臨洮。", "努力追遊晚，逢人應接勞。", "黄花滿酌酒，白鷺看驚濤。", "醉舞相傾倚，商歌散欎陶。", "别離懷病友，書禮諭綈袍。", "俗態隨傖父，愁吟困楚騷。", "飛車儻可得，攜手恣遊遨。"]'),
('f7639c0a-d5d3-4c08-ba56-3def7f1c5e6c','王秘丞惠然相訪并見遺蜀牋玄石硯','劉敞','宋','宋诗','song-poetry','','[]','僕本時名薄，君胡雅顧偏。',96,'全唐诗/poet.song.28000.json','["僕本時名薄，君胡雅顧偏。", "聞弦賞流水，望氣覓龍泉。", "談笑心相得，逢迎禮率然。", "樵蘇從不爨，詩賦許深傳。", "墨石巴山硯，魚鱗蜀客牋。", "寵分通縞带，慕用比先賢。", "知我春秋貴，論交金石堅。", "誰能憚先進，自古有忘年。"]'),
('3dcd5b2d-981e-46e9-b7e7-397249e927f2','送孫之翰知陜府','劉敞','宋','宋诗','song-poetry','','[]','山河晉表裏，方伯陜西東。',72,'全唐诗/poet.song.28000.json','["山河晉表裏，方伯陜西東。", "昔重諸侯選，今煩太史公。", "固疑多直諫，不得久居中。", "時論譏憂半，天心待考功。", "旌麾都護道，謠俗召南風。", "偃息甘棠下，知君簡易同。"]'),
('37c0cf0e-94cf-4883-ac51-5028263d3436','吳資政守陜一年還守西都又改禮部寄示在陜時詩作此致謝','劉敞','宋','宋诗','song-poetry','','[]','分陜間何闊，期年迨有成。',96,'全唐诗/poet.song.28000.json','["分陜間何闊，期年迨有成。", "去思仍舊俗，來暮已新聲。", "父老壺漿遠，兒童竹馬輕。", "圖書還洛奥，禮樂命春卿。", "繼出甘棠什，流傳大雅情。", "正風瞻豈弟，舊觀復神眀。", "露鶴九秋警，霜蟬千里清。", "知音非季子，猶識二南并。"]'),
('ba2cfefb-c1bd-4728-bcd2-efe6301d4341','寄張六卧疾在山陽','劉敞','宋','宋诗','song-poetry','','[]','都門一分袂，覉旅兩如何。',72,'全唐诗/poet.song.28000.json','["都門一分袂，覉旅兩如何。", "薄宦貧病久，畏塗憂懼多。", "幾成哭寢戶，幸免葬江波。", "彌有三秋感，誰杭一葦過。", "新愁添素髪，幽境長青莎。", "安得攜君手，開懷醉且歌。"]'),
('6522084c-a92a-41d6-a13c-909c3cfec1de','張樂洞庭','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','聞昔軒轅帝，時巡臨洞庭。',72,'全唐诗/poet.song.28000.json','["聞昔軒轅帝，時巡臨洞庭。", "咸池備廣樂，南極燀威靈。", "至樂均夷夏，希聲入窈冥。", "江湖亂魚鳥，宇宙激雷霆。", "會有馮夷舞，還令楚客醒。", "遺音不可學，逝近向東溟。"]'),
('d4154ba3-921f-45dd-adbc-789628312d17','分題鳥鳴山更幽','劉敞','宋','宋诗','song-poetry','','[]','空山高不極，喧鳥自相求。',72,'全唐诗/poet.song.28000.json','["空山高不極，喧鳥自相求。", "永日曾一哢，深林疑更幽。", "遺音散虚谷，習響動岑樓。", "寂寂千峰暝，蒼蒼萬木稠。", "居成境外趣，真慰静中游。", "誰强騷人賦，王孫不可留。"]'),
('183c6b7b-744e-4704-a268-79e21019775b','社日宴臨波亭呈府公','劉敞','宋','宋诗','song-poetry','','[]','春色池上好，公來朝日初。',72,'全唐诗/poet.song.28000.json','["春色池上好，公來朝日初。", "棟梁歸喜燕，霖雨躍潛魚。", "雲氣隨歌妓，林光暗碧車。", "心閒簿領暇，興適酒杯餘。", "言志吾與點，論詩商起予。", "定知金谷集，不比右軍書。"]'),
('3a164a4f-91ca-4075-b78a-cdfa5a4ba862','送升之','劉敞','宋','宋诗','song-poetry','','[]','諫官上耳目，河北今股肱。',96,'全唐诗/poet.song.28000.json','["諫官上耳目，河北今股肱。", "出處誰與並，功名方見稱。", "鈎陳虚侍從，天路逼飛騰。", "急病忍濡足，憂民先飲冰。", "萬人瞻使表，百縣懾風稜。", "雅意本朝在，規摹方面憑。", "寒荄待暖律，狡兔避秋鷹。", "慷慨都亭語，無嫌力未能。"]'),
('ef9e95fb-2946-4901-9c67-0b254d7553f9','九月八日晚會永叔西齋','劉敞','宋','宋诗','song-poetry','','[]','醉翁手種菊，呼我宴西齋。',96,'全唐诗/poet.song.28000.json','["醉翁手種菊，呼我宴西齋。", "落日有餘興，窮秋多所懷。", "緩歌揮白羽，趣舞墮金釵。", "烏帽何勝落，黄花故自佳。", "念離還作惡，處世亦安排。", "蒼鬢聊相對，青雲豈易階。", "母容燭見跋，能盡酒如淮。", "少作三年别，人生定鮮諧。"]'),
('14386c8a-4f01-43de-b99f-fb3ec9d5be69','奉酬春卿資政給事見寄并貺法酒','劉敞','宋','宋诗','song-poetry','','[]','王甸雄三輔，侯邦重百城。',288,'全唐诗/poet.song.28000.json','["王甸雄三輔，侯邦重百城。", "公雖縱談笑，人自服神明。", "烹幹元和正，陶鎔庶物精。", "優游破餘地，灑落動高情。", "訟比甘棠息，居無吠犬驚。", "勤追頖宫學，繼出汝南評。", "風雅移方俗，弦歌溢頌聲。", "忘年及晚輩，與進絕諸生。", "預列登堂拜，陪參别乘行。", "襟懷向客盡，風彩照人清。", "弧矢親觀德，滄浪並濯纓。", "宴餘花爛漫，獵罷雪縱横。", "末節形骸外，良辰樂賞并。", "西曹寛吏讁，東閣借賓榮。", "密席眀金炬，佳人出玉笙。", "聽歌濃黛斂，看舞小腰輕。", "敢謂招攜訊，由來許與誠。", "會知私坎井，未可屈長鯨。", "鳳尾騰中詔，麟符寄别京。", "去思邈已遠，陳迹浩難平。", "叩叩煩書禮，悠悠想旆旌。", "何時命霖雨，舉世望阿衡。", "逸唱回春藻，深衷釋吝萌。", "自然心醉久，那在酒如餳。"]'),
('d35047c0-6a1d-472b-b0e5-6097a0d52e2a','次韻和宋職方北城','劉敞','宋','宋诗','song-poetry','','[]','菏澤元通濟，陶邱已近齊。',144,'全唐诗/poet.song.28000.json','["菏澤元通濟，陶邱已近齊。", "身紆會稽綬，詔圻武都泥。", "求瘼初無術，端居愧擇棲。", "萬家嚴壁壘，五雉聳樓梯。", "版築人同欲，經營事不迷。", "峻防誰敢慢，隆棟可言低。", "兵衛森旂戟，軍聲疊鼓鼙。", "論詩譏自鄶，肄士取諸暌。", "物境晨昏異，賓朋步武躋。", "遠烟春漠漠，殘雪晝淒淒。", "華髮歡同籍，他年恨解攜。", "瓊瑰何足報，埽壁爲君題。"]'),
('abf59067-9b04-4629-9d51-fafe887ef3e4','蒙某借示新詩不勝嘆服輒妄作五言一首以誌欣慕','劉敞','宋','宋诗','song-poetry','','[]','元化陶鈞外，中樞斗極邊。',144,'全唐诗/poet.song.28000.json','["元化陶鈞外，中樞斗極邊。", "濟時俱陟降，均逸暫蕃宣。", "近輔城連十，東方騎累千。", "親歡主于適，時論老而傳。", "養志古何有，承顔能浩然。", "君羮鼎味在，綵服衮衣聫。", "德表真希世，天倫略比肩。", "名今萬石最，學肯一經專。", "相戒南陔養，賡歌棠樹篇。", "塤箎盛迭奏，金玉爛相鮮。", "錫類迂深眷，懷歸私自憐。", "一聞詩禮意，特悟昔人賢。"]'),
('c244ba72-4b16-4596-a5e3-1f7db048e9de','觀後苑瑞蓮','劉敞','宋','宋诗','song-poetry','','[]','靈液涵秋色，仙花露夕香。',72,'全唐诗/poet.song.28000.json','["靈液涵秋色，仙花露夕香。", "交陰分擢秀，並蒂爛齊芳。", "回復天鍾氣，深沈地獻祥。", "寶燈輝四照，文羽勢雙翔。", "飛蓋宸游密，披圖秘牒光。", "重華與同本，併此祝無疆。"]'),
('afbcc048-8a92-415d-9405-7100f594b565','擬御試求遺書於天下','劉敞','宋','宋诗','song-poetry','','[]','中秘收圖籍，清衷訪古初。',74,'全唐诗/poet.song.28000.json','["中秘收圖籍，清衷訪古初。", "周爰馳使傳，悉上得遺書。", "事有先秦舊，文多變隸餘。", "千巖窮禹穴，四徹按崑⿱山虛。", "高閣題天祿，羣英議石渠。", "定知奎壁彩，從此麗雲居。"]'),
('1e09c92a-8b04-43c0-8ea7-156a8de40bb0','河決東郡以平聲爲韻叔父令賦','劉敞','宋','宋诗','song-poetry','','[]','傳聞大河决，遠與北溟通。',72,'全唐诗/poet.song.28000.json','["傳聞大河决，遠與北溟通。", "汜濫蛟鼉怒，蕭條郡國空。", "淇園方下竹，瓠子復修宫。", "世代文成術，民懷伯禹功。", "沈牲煩太史，負土困關東。", "封禪應知外，誰人秦矩公。"]'),
('3ff3c6c1-7495-4fe7-88f9-4d57fdd76db0','上夏太尉','劉敞','宋','宋诗','song-poetry','','[]','四海傳烽急，長安亦響振。',192,'全唐诗/poet.song.28000.json','["四海傳烽急，長安亦響振。", "老儒稽變事，强敵暴生民。", "廷議衣冠客，書聞草野臣。", "諸公咸世傑，天子識平津。", "開府三司舊，提兵十萬新。", "丹青大信著，明白睿謀伸。", "賜馬飛龍亞，分衣寶带親。", "貔貅帳下士，鵷鵠幕中賓。", "虎節關河雪，天街畢昴塵。", "朔方須築郡，燕谷豫含春。", "策效曾無敵，師行輒有神。", "人心惟助順，天道亦親仁。", "執鉞來刑虢，勾芒下賜秦。", "成功符屈指，默化劇陶鈞。", "既已通西域，還應察珮珉。", "焉知充國頌，不足壯麒麟。"]'),
('2f57b18e-5280-4c6c-894f-f8b76728894c','次袁陟十四韻','劉敞','宋','宋诗','song-poetry','','[]','羈旅嗟無友，佯狂漢水陰。',168,'全唐诗/poet.song.28000.json','["羈旅嗟無友，佯狂漢水陰。", "相逢幸傾蓋，送别悵分襟。", "之子雖吏隱，高名何陸沈。", "蛟龍蟠學海，風雨潤詞林。", "寡和嘗歌郢，傳經雅屬參。", "丈人今諭蜀，幹譽爾勞心。", "接淅予征遠，看雲反顧深。", "旅懷兼去住，秋色愴登臨。", "信有江山助，宜無霧露侵。", "相思見逸唱，清絕響寒砧。", "擊節時孤笑，開樽憶共斟。", "歳華幾向晚，客恨孰能禁。", "城闕愁回首，詩人誨嗣音。", "曾非青玉案，爲愧洛生吟。"]'),
('db125467-c410-4d09-ae7e-a852537bae56','聞西使到關','劉敞','宋','宋诗','song-poetry','','[]','遙聞西域使，來獻大明宫。',96,'全唐诗/poet.song.28000.json','["遙聞西域使，來獻大明宫。", "故事三苗比，官儀敵國同。", "賜書深慰藉，錫命極優崇。", "含垢應王度，懷柔尚古風。", "蒼生向來急，殊俗此時通。", "冠蓋長城北，邊關絕幕東。", "春秋大一統，吏事責三公。", "何有長沙客，題詩慟哭中。"]'),
('4db13dac-089e-4308-94f3-9031f9a493f0','寄閬州諸弟','劉敞','宋','宋诗','song-poetry','','[]','渤澥來參首，西南入漏天。',96,'全唐诗/poet.song.28000.json','["渤澥來參首，西南入漏天。", "泄雪三峽壅，噴雨五河懸。", "雷電虚巖底，虹霓白日邊。", "孤城危獸角，沈竈溢蛟涎。", "朐䏰愁巴俗，超騰怯羽仙。", "傳聞吞夢澤，想見墮飛鳶。", "漢河星槎遠，泥塗劍閣偏。", "空懷萬里浪，興盡閬風前。"]'),
('467e4b9a-d391-4a90-bf36-554187eccceb','九月二十五日召赴後苑觀稻','劉敞','宋','宋诗','song-poetry','','[]','農祥依帝力，鈎盾即天田。',96,'全唐诗/poet.song.28000.json','["農祥依帝力，鈎盾即天田。", "覽物秋成後，回輿銍艾前。", "膏塍衆錦錯，香穟萬珠聯。", "共賞倉箱富，初非雨露偏。", "銅池寒引溜，玉樹晚含烟。", "縱觀欣遊豫，登嘗慶吉蠲。", "執經紆顧問，拜賜濫周旋。", "不負春秋學，端逢大有年。"]'),
('106695de-b194-4100-845c-a7888ee5431d','行詣揚州壽寧寺','劉敞','宋','宋诗','song-poetry','','[]','隋宫老荆棘，淮地阻山川。',96,'全唐诗/poet.song.28000.json','["隋宫老荆棘，淮地阻山川。", "天子周王狩，諸侯楚社遷。", "宿軍江水上，休甲古城邊。", "清蹕乃過此，高臺亦宛然。", "殿空生影響，畫古剥丹玄。", "缺甃驚跳鮒，遺碑失紀年。", "廢興真可感，耆舊毎多傳。", "一詠蕪城作，斜陽聞暮蟬。"]'),
('6e10f78a-3336-4572-8231-0bb47b9a4708','和喜雨','劉敞','宋','宋诗','song-poetry','','[]','望歲憂農事，爲霖屬柄臣。',240,'全唐诗/poet.song.28000.json','["望歲憂農事，爲霖屬柄臣。", "吁嗟動雲漢，精祲驗天人。", "霏霧凝空曲，雄風激水濱。", "驅除斷炎燠，灑埽浄埃塵。", "勢欲翻河海，聲疑過鬼神。", "山川共秀發，穹壤劃清新。", "庶物含生意，元和倚大鈞。", "穴蛟深奮角，轍鮒默翻鱗。", "雷電天威遠，耕桑帝力勻。", "依然四時正，好在萬家春。", "會府開清旦，高堂引慶賓。", "沃焦心有待，濯熱正無倫。", "蒸礎遺占信，隨軒舊史真。", "京師并福潤，爻象在經綸。", "舞罷看佋服，談餘識墊巾。", "新詩追大雅，輿誦洽烝民。", "單袷寒仍薄，清和氣已震。", "晴暉明旭日，霽色卷高旻。", "亹亹希前哲，淒淒幸及辰。", "陽秋書閔雨，一頌魯公仁。"]'),
('c658b2a2-30a0-4e73-9acd-630e41f26f08','病中逢秋欣然慰懷作五言呈兩倅','劉敞','宋','宋诗','song-poetry','','[]','過更縻遠戍，懷祿滯歸休。',96,'全唐诗/poet.song.28000.json','["過更縻遠戍，懷祿滯歸休。", "一卧淮陽閣，三防塞外秋。", "傷時惟慟哭，謝病不幽憂。", "主畫稀前輩，忘形賴雋游。", "韓稜才抗俗，枚叔賦無儔。", "感慨今如此，支離尚有瘳。", "涼風鴈南去，清夜火西流。", "江海鱸魚興，何當泛斗牛。"]'),
('5ba804f3-9f6d-44e0-950f-3f677df29b15','詔書求方略之士咸令自陳','劉敞','宋','宋诗','song-poetry','','[]','破敵須多士，憂民賴九重。',72,'全唐诗/poet.song.28000.json','["破敵須多士，憂民賴九重。", "公車皆自薦，物議絕先容。", "駿骨何妨市，金臺不易逢。", "處嚢争耀末，躍治要居鎔。", "秋野騰鞲鶻，春雷起蟄龍。", "吾徒正高卧，欲老白雲峰。"]'),
('cbac6653-cd56-4d6e-a016-ba703d0b6080','聞德州河決','劉敞','宋','宋诗','song-poetry','','[]','九河乘積雨，大水出平原。',72,'全唐诗/poet.song.28000.json','["九河乘積雨，大水出平原。", "無復金堤固，空驚漏澤翻。", "蛟龍移窟宅，魚鼈害黎元。", "直想崑崙圻，兼疑渤澥渾。", "三山屢漂蕩，百谷互并吞。", "大懼彝倫斁，誰能謁帝閽。"]'),
('de1310aa-d254-4dcd-8bab-c60b66c1f3b8','送子高知潤州','劉敞','宋','宋诗','song-poetry','','[]','屈指朝廷士，誰能望素風。',120,'全唐诗/poet.song.28000.json','["屈指朝廷士，誰能望素風。", "賢良方正舉，父子弟兄同。", "鄙諺黄金貴，愚儒白首窮。", "今看一戰霸，信有萬夫雄。", "官秩南宫峻，天文右掖通。", "塤篪諧大雅，鴻鵠起層空。", "帝予夸鄉樂，民懷濟物功。", "吳人真得虎，漢守去憑熊。", "山勢端臨北，江流正直東。", "遙知子牟意，故在九城中。"]'),
('f6e0700f-5ee7-4078-905e-a12122ad8485','題幽州圖','劉敞','宋','宋诗','song-poetry','','[]','代北屯兵盛，漁陽突騎精。',192,'全唐诗/poet.song.28000.json','["代北屯兵盛，漁陽突騎精。", "棄捐看異域，感激問蒼生。", "尚識榆關路，仍存漢郡名。", "可憐成反拒，未見請横行。", "先帝曾親伐，斯人昔徯征。", "大功危一跌，遺恨似平城。", "往者干戈役，因之玉帛盟。", "權宜緩中國，苟且就升平。", "名號于今錯，恩威自此輕。", "奈何卑聖主，豈不負宗祊。", "事有違經合，功難與浴評。", "復讎宜百世，刷恥望諸卿。", "封畛唐虞舊，氛祲渤碣清。", "遺黎出塗炭，故老見簪纓。", "寒谷青陽及，幽都日月眀。", "此懷如萬一，高揖謝縱横。"]'),
('504bba12-55a5-4fb6-931d-06be4fa0ef3e','某往歲侍大人守丹陽粗知此郡之盛復戲成小詩呈子高','劉敞','宋','宋诗','song-poetry','','[]','自古佳麗地，到今風物奇。',96,'全唐诗/poet.song.28000.json','["自古佳麗地，到今風物奇。", "羣山盡迴抱，綠水止逶迤。", "事體存都會，繁華盛昔時。", "秋聲雄鼓角，曉色亂旌旗。", "樓觀渾飛動，林巒互蔽虧。", "子鵝留客飲，白紵送歌詞。", "太守貴如此，郎官清可知。", "虚投射堂策，深恨著鞭遲。"]'),
('fbbbbb01-b859-4c64-bc56-6b048a13bdf8','淮上期龐十一不至','劉敞','宋','宋诗','song-poetry','','[]','淮上稱晨朝，晨光滿麗譙。',96,'全唐诗/poet.song.28000.json','["淮上稱晨朝，晨光滿麗譙。", "有懷空悵望，無和獨行謠。", "水色全含鑒，林花半隱樵。", "雲烟平宿莽，鷗鳥破春苗。", "野俗陽歌麗，游人白馬驕。", "先生惟寂寞，至樂亦逍遙。", "洙泗風差遠，川原景幸饒。", "思君不得見，何以助簞瓢。"]'),
('71b64578-9e52-4c13-9f2c-32ec5ad038ae','和府公二十韻','劉敞','宋','宋诗','song-poetry','','[]','百草迎年茂，羣花逼夏零。',240,'全唐诗/poet.song.28000.json','["百草迎年茂，羣花逼夏零。", "天工感寥落，春事出丁寧。", "皓月彫寒魄，鮮風結暖馨。", "彩霞融縹緲，甘露灑清泠。", "照坐千枝燭，搖空九子鈴。", "輕黄金綴縷，凝碧玉鐫缾。", "爛漫輔鮫錦，褵褷聚鶴翎。", "問名驚競秀，變態駭流形。", "鍾美應成媪，儲芳或景星。", "意真乘澹泊，氣淑倚娉娗。", "浄影臨彫檻，疏音隔後庭。", "瑤妃旦酣酒，玉女夜窺櫺。", "時世妝濃澹，朝雲夢窈冥。", "魂從攀處亂，醉任看餘酲。", "禁籞曾迂幸，天歌獨仰聽。", "一時矜絕出，衆卉謝晶熒。", "正爾生成巧，由來造化靈。", "屬詞勞比興，圖象費丹青。", "雨重碧油幕，燈昏雲母屏。", "謫仙才不世，激賞爲君聆。"]'),
('22b0e119-6bc4-4b27-b020-27b7ba053c8c','同貢甫賀錢子飛兄弟','劉敞','宋','宋诗','song-poetry','','[]','盛德淳熙耀，豐規振後昆。',192,'全唐诗/poet.song.28000.json','["盛德淳熙耀，豐規振後昆。", "降心徠俊傑，前席問黎元。", "嘉會真千載，休聲聚一門。", "象賢俱秀出，濟美並鴻鶱。", "性復朱繩直，書曾玉露繁。", "十年森氣象，江海豁詞源。", "心伏驚諸老，名聞動至尊。", "深嚴親賜策，淵默静臨軒。", "明白朝廷制，丹青教化原。", "屢聞呼萬歲，争誦累千言。", "宜有非常遇，誰嫌不次恩。", "官儀推粉署，地望逼星垣。", "令聞人人得，風流善善存。", "春華照棠樹，高韻溢箎塤。", "義辱交游接，歡心抃笑煩。", "空慚一枝小，當謝北溟鯤。"]'),
('81cfe466-4988-49c2-984b-26ff99346f6b','召赴崇政殿觀新樂','劉敞','宋','宋诗','song-poetry','','[]','聖人千歲合，禮樂百年興。',144,'全唐诗/poet.song.28000.json','["聖人千歲合，禮樂百年興。", "律以聲身效，功兼述作稱。", "道將諧一變，天欲佑丕承。", "舊典周官在，遺音制氏增。", "獻書嘉魏叟，博物待延陵。", "金石完新制，工師變舊能。", "英華融治世，淳古邈逾繩。", "縱觀傾朝野，賡歌望股肱。", "和風動寥廓，協氣散凌兢。", "帝所真疑夢，天階自絕升。", "三雍漢未盛，九辯夏徒矜。", "珥筆欣攄頌，名山益望登。"]'),
('4fa08448-5395-4b00-b639-6c260e53f7f7','社後雪','劉敞','宋','宋诗','song-poetry','','[]','故陰不自斂，飛霰一何驕。',120,'全唐诗/poet.song.28000.json','["故陰不自斂，飛霰一何驕。", "强妒春陽盛，那妨玉琯調。", "滔天初極望，見晛已全消。", "詎損朱華麗，秖添綠野饒。", "泥塗窮道路，絺綌亂鼲貂。", "遂恐天時錯，仍虞歲事枵。", "浮雲猶苦結，燕賀乍驚飄。", "但使風從律，無嫌物反祅。", "初過元日社，又放紫宸朝。", "乘興從君飲，孤音續郢謠。"]'),
('513cfe01-3fe8-4155-b2ab-36276efd9ec8','立春日乾祐縣送梅花','劉敞','宋','宋诗','song-poetry','','[]','終南全近蜀，春日得新梅。',96,'全唐诗/poet.song.28000.json','["終南全近蜀，春日得新梅。", "始信秦風是，非關越使來。", "雪霙眀自照，雲葉薄誰裁。", "香重浮山露，膚清避俗埃。", "衆芳知遠矣，獨秀亦悠哉。", "翦綵何勝妒，嚴妝莫自猜。", "差池鼎鼐味，曠絕棟梁材。", "把酒千山外，那令寂寞開。"]'),
('e2786fd4-82ef-4de1-966e-36a63420b40e','淮西廟梅花獨此處有之','劉敞','宋','宋诗','song-poetry','','[]','荏苒江南村，芬菲臘後春。',72,'全唐诗/poet.song.28000.json','["荏苒江南村，芬菲臘後春。", "逾淮翻不變，映雪已争新。", "俠骨香驚俗，冰膚冷照鄰。", "定非隨驛使，直恐謫仙人。", "聞笛空含怨，看圖恨失真。", "應爲一時賞，莫與衆芳倫。"]'),
('ac07b682-5974-4bd5-9c47-c26d3fae0fdd','形鹽象虎','劉敞','宋','宋诗','song-poetry','','[]','備物崇賓饗，斯鹽肖虎形。',72,'全唐诗/poet.song.28000.json','["備物崇賓饗，斯鹽肖虎形。", "熬波煩巧匠，象武示君靈。", "天產參多品，秋嚴聳外庭。", "炳文隨鏤刻，毅氣得儀型。", "服孟非同趣，昭文亦異經。", "碎身如見取，調鼎薦芳馨。"]'),
('33b9f936-019b-4ff7-b03e-ec024f83034c','同徐監簿灞涘望長安','劉敞','宋','宋诗','song-poetry','','[]','驅車凌灞岸，回顧望長安。',72,'全唐诗/poet.song.28000.json','["驅車凌灞岸，回顧望長安。", "北闕塵明滅，南山氣鬱盤。", "人來日遠近，城轉斗闌干。", "長樂鐘聲斷，秦川樹色殘。", "聽歌迷夏首，倚瑟想邯鄲。", "鬒變驚遊子，因知行路難。"]'),
('c60ac459-7416-41da-b2df-09a9589e7bc2','捷詩','劉敞','宋','宋诗','song-poetry','','[]','捷報蒼龍闕，書從白豹城。',96,'全唐诗/poet.song.28000.json','["捷報蒼龍闕，書從白豹城。", "關河開地利，雷雨肅天兵。", "氣攝千山動，威加萬里平。", "獻俘多寶玉，効首悉長鯨。", "社稷靈何遠，巖廊策自精。", "餘妖暫煦沫，壯士待龔行。", "天馬來西域，貂裘實上京。", "遙知舞干羽，冠劍賀公卿。"]'),
('99b45164-cf64-4b17-9450-daa47a5b0fe2','寄上濠州舅氏','劉敞','宋','宋诗','song-poetry','','[]','天閣愁揚子，諸侯困仲舒。',96,'全唐诗/poet.song.28000.json','["天閣愁揚子，諸侯困仲舒。", "反爲清浄誤，竟以謗讒疏。", "開幕臨濠水，懷章下石渠。", "塞翁輕失馬，莊叟樂觀魚。", "倚杖曾何怪，逍遙直自如。", "貴爲千騎長，富有萬家居。", "卧理翻無事，高談雅不虚。", "舊憐狂簡性，遙想賦歸歟。"]'),
('809b14b8-4dc5-424c-a7a4-88445cdf223a','和永叔對雪次韻','劉敞','宋','宋诗','song-poetry','','[]','驚飈卷白日，朔氣逼寒門。',120,'全唐诗/poet.song.28000.json','["驚飈卷白日，朔氣逼寒門。", "已密何須急，雖多未覺繁。", "勢輕飛有態，光潔瑩無痕。", "磥砢封喬木，玲瓏綴夕軒。", "迹深看敝躧，歌苦相車轅。", "測厚矜膚寸，愁消怯晏温。", "崩騰雲將合，颯沓雨師屯。", "埽去蛟螭亂，堆成虎豹蹲。", "夜明休秉燭，詩興助開樽。", "公若憐萱桂，那辭訪小園。"]'),
('dd337d0d-d490-45bc-a9d0-223a93d03706','爲紀四謁舊相識','劉敞','宋','宋诗','song-poetry','','[]','非無負米志，復作退飛身。',96,'全唐诗/poet.song.28000.json','["非無負米志，復作退飛身。", "豈但龍蛇蟄，終慚鴻鴈賓。", "蕭條依陋巷，契闊問通津。", "長鋏行焉往，悲歌夜復晨。", "交遊青眼隔，世路白頭新。", "意謝栖栖侫，情依戀戀仁。", "敢齊天下士，真愧轍中鱗。", "肯問三年學，壺飱及病親。"]'),
('2d3f3357-c961-4a0a-a573-627b2b119420','和鄰幾聖俞持國雪十八韻依次用','劉敞','宋','宋诗','song-poetry','','[]','集霰羣陰結，飛霙萬寓低。',216,'全唐诗/poet.song.28000.json','["集霰羣陰結，飛霙萬寓低。", "乾坤豁開闢，方域露端倪。", "廣宇規茅藉，彫墻築粉泥。", "山容包紫翠，壤色變玄黎。", "筒葛來従越，冰紈製自齊。", "遊歡慰枚馬，獵興助良奚。", "飾貌沽珍粹，因方衒角圭。", "隙間巇可抵，行際道先迷。", "沾服驚遊霧，臨淵怪飲蜺。", "調元思暖津，跧伏憫靈蠵。", "幾誤烏成鵠，纔分鶴處雞。", "慘膚森若竪，墮指酷逾刲。", "澤國水還襲，焦原足易棲。", "貧儒欣夜誦，季女戚朝儕。", "舟楫膠藏壑，驊騮滑踠蹄。", "斵冰歌競若，擿埴杖頻攜。", "景幸人人得，詩從物物題。", "長吟歌真樂，安羨舞前溪。"]'),
('cd7b720f-0d96-4f3b-bc64-e8e3d6bb916c','奉同鄰幾詠雪','劉敞','宋','宋诗','song-poetry','','[]','侵旦滿城雪，從天萬里風。',216,'全唐诗/poet.song.28000.json','["侵旦滿城雪，從天萬里風。", "陰沈朝日變，慘澹宿雲同。", "徑渡湖沙遠，羣飛海上空。", "崩騰兼上下，眩晃失西東。", "帝所銀爲闕，河濱貝作宫。", "瑤林高不極，璧水闊無窮。", "巨麗神仙境，精微造化工。", "霏花争爛漫，噴霧極溟濛。", "埽灑埃塵豁，苞含物象充。", "牛衣愁病客，鶴髪思衰翁。", "侵冒貂餘黑，憑凌火似紅。", "厲威深刻轢，正色坦昭融。", "妒舞多珍鷺，迷羣有斷鴻。", "陽微怯頻復，陰老恣驕雄。", "蔀屋貧奢等，輝窗晝夜通。", "歲華驚朔易，故老識年豐。", "占賦慚賓右，聞歌慕郢中。", "閉門徒自喜，乘興力難崇。"]'),
('e24bc976-7df9-4285-9be5-3fb39dcfbde4','再和鄰幾','劉敞','宋','宋诗','song-poetry','','[]','冱寒凋暮節，大雪冒神州。',240,'全唐诗/poet.song.28000.json','["冱寒凋暮節，大雪冒神州。", "氣象昏千里，光芒混六幽。", "度前蚊過目，隕曠葉驚秋。", "烟素長誰引，雲羅薄自浮。", "勢輕低更起，影亂去還留。", "玉石均朝采，珠璣共暗投。", "圍城眀組練，格野亂旗旒。", "模象羣形富，牢籠衆險周。", "履空諳曳縱，騁望快登樓。", "栖璧函珍带，裝簾耀寶鈎。", "潤應何澤比，甘豈井泉侔。", "萬物紛同態，繁陰慘共愁。", "波聲增渤澥，原色借來麰。", "邀醉時吹面，欺貧屢灑裘。", "驅除夏蠱盡，排迮楚氛收。", "人謝泥塗辱，家成汗漫遊。", "畫圖饒粉堊，比興極歌謳。", "積久風逾厲，消遲歲聿遒。", "短才非子敵，秘思爲君抽。", "高韻侵梁郢，煩言不可酬。"]'),
('d3019e85-cbd6-4c54-8821-cc3569c5a23c','壺公祠大樹','劉敞','宋','宋诗','song-poetry','','[]','若人既羽化，伊樹亦千年。',72,'全唐诗/poet.song.28000.json','["若人既羽化，伊樹亦千年。", "委幹龍蛇蟄，交陰孔翠鮮。", "流光駒過隙，浮世海成田。", "信有壺中藥，能移物外天。", "真游藐何許，神理信茫然。", "會見遼東鶴，悲歌感市廛。"]'),
('79eeb372-f690-4211-a1c5-df8add2586a8','劉永年部署清燕堂','劉敞','宋','宋诗','song-poetry','','[]','漢庭謀帥用詩書，丞相今來握虎符。',96,'全唐诗/poet.song.28000.json','["漢庭謀帥用詩書，丞相今來握虎符。", "帳下偏裨皆緩带，軍中談笑亦投壺。", "故開廣榭宜高會，自有清泉入座隅。", "三輔衣冠獻謠俗，五陵豪俠壯規模。", "椎牛釃酒捐長日，急管哀弦舞豔姝。", "射取天狼作乾豆，莫推衛霍擅西都。"]'),
('5f23e48e-1996-496a-8b6f-b13804569569','和王待制新作白鷺亭七言十韻','劉敞','宋','宋诗','song-poetry','','[]','六朝形勢會層軒，前俯蒼洲卻踐山。',160,'全唐诗/poet.song.28000.json','["六朝形勢會層軒，前俯蒼洲卻踐山。", "二水中分鑑澄澈，萬峰離立翠回環。", "古人遺賞興亡外，良守來居仁智間。", "聽訟遂同棠樹愛，放懷真與海漚閒。", "嘯餘風雨知何處，望及雲霞若可攀。", "喬木參天愴城郭，浮萍滿地笑人寰。", "楚謠清絕酣秋興，吳拂從容舞玉顔。", "象魏由來心自遠，湡浯聊復樂忘還。", "掖垣幸許追遐躅，天祿仍欣接近班。", "塵土揚州頭欲白，遠從君借慰疏孱。"]'),
('2e5a408d-2730-48b1-84ec-201e57842f7d','和陳度支杜城園池長韻詩','劉敞','宋','宋诗','song-poetry','','[]','三輔衣冠多俊賢，邇來風物故依然。',128,'全唐诗/poet.song.28000.json','["三輔衣冠多俊賢，邇來風物故依然。", "君家復在城南社，時望從知尺五天。", "韋氏訓經門益大，酇侯治第世相傳。", "雪殘太一虛無裏，塵漲重城蒼莽邊。", "修竹萬竿迷暗谷，清渠百道散鳴泉。", "欣欣樹色知春近，寂寂禽聲覺地偏。", "使節歸來同晝錦，扁舟浮去似登仙。", "禆諶適野非無興，更挹逍遙池上篇。"]'),
('1ce4d36d-71cf-4728-a2aa-c94c67d1656d','賀春卿拜資政殿學士移西京留守','劉敞','宋','宋诗','song-poetry','','[]','自昔東郊擇股肱，至今筦鑰委名卿。',96,'全唐诗/poet.song.28000.json','["自昔東郊擇股肱，至今筦鑰委名卿。", "官儀高出金華殿，地理雄專北斗城。", "寶带别兼天馬賜，彩衣仍照玉符眀。", "正風鼓動周南什，和氣銷除武庫兵。", "聽訟甘棠從勿翦，攀轅舊吏不勝情。", "千年重得吳公守，門下無由望賈生。"]'),
('b3769261-3e91-4119-a343-c5cf0ac76804','蒲三首  其一','劉敞','宋','宋诗','song-poetry','','[]','青青水中蒲，根葉自勾带。',24,'全唐诗/poet.song.28000.json','["青青水中蒲，根葉自勾带。", "今我不如彼，望君萬里外。"]'),
('f65e1045-9fa0-46c8-8b34-d4e74e398566','蒲三首  其二','劉敞','宋','宋诗','song-poetry','','[]','青青水中蒲，秀色宜三春。',24,'全唐诗/poet.song.28000.json','["青青水中蒲，秀色宜三春。", "常苦秋氣早，飄飄悲路人。"]'),
('64164027-6306-4ac8-8d07-2b42a7bb943e','蒲三首  其三','劉敞','宋','宋诗','song-poetry','','[]','青青水中蒲，誰能移之陸。',24,'全唐诗/poet.song.28000.json','["青青水中蒲，誰能移之陸。", "婦人繫所徇，憔悴甘獨宿。"]'),
('d6108822-0ba7-462c-9bbb-26ba167d9ec5','順州聞角','劉敞','宋','宋诗','song-poetry','','[]','北山三千里，歸來已近邊。',24,'全唐诗/poet.song.28000.json','["北山三千里，歸來已近邊。", "如何聞鼓角，晨坐更悽然。"]'),
('fc5f5e04-37ab-45fe-88e8-03fe85e4fb5e','瑞竹','劉敞','宋','宋诗','song-poetry','','[]','聳節偶相並，雪霜終不迷。',24,'全唐诗/poet.song.28000.json','["聳節偶相並，雪霜終不迷。", "應将古人比，孤竹有夷齊。"]'),
('90f21cc6-5fdf-4cfe-a16d-e51d2c22ae62','暮冬寄鹽城弟二首  其一','劉敞','宋','宋诗','song-poetry','','[]','流水應無極，東流向海城。',24,'全唐诗/poet.song.28000.json','["流水應無極，東流向海城。", "殷勤囑雙鯉，爲寄别離情。"]'),
('194f01c6-76a1-4854-97d2-760d8c36f18a','暮冬寄鹽城弟二首  其二','劉敞','宋','宋诗','song-poetry','','[]','海上春常早，相思正一涯。',24,'全唐诗/poet.song.28000.json','["海上春常早，相思正一涯。", "北風吹雪盡，遙想折梅花。"]'),
('b801361e-3a91-4922-99d6-aacc469d87b5','東樓','劉敞','宋','宋诗','song-poetry','','[]','能懷望鄉思，慎勿上東樓。',24,'全唐诗/poet.song.28000.json','["能懷望鄉思，慎勿上東樓。", "海氣常常霧，淮聲故故愁。"]'),
('40b029d6-bd29-490f-afdd-cec23ccecbd9','鼎池','劉敞','宋','宋诗','song-poetry','','[]','丹成雞犬去，鼎在陵谷遷。',24,'全唐诗/poet.song.28000.json','["丹成雞犬去，鼎在陵谷遷。", "惟有千年鶴，時來浴水邊。"]'),
('d8b83202-a439-424f-8ccf-99e8474c4393','嘯臺','劉敞','宋','宋诗','song-poetry','','[]','高臺映水末，極望有層軒。',24,'全唐诗/poet.song.28000.json','["高臺映水末，極望有層軒。", "覽物惟長嘯，逢人未始言。"]'),
('fb7bdd24-f50a-49c7-a8c4-b39359980f62','酒舫','劉敞','宋','宋诗','song-poetry','','[]','悠悠轉小棹，漾漾逐浮萍。',24,'全唐诗/poet.song.28000.json','["悠悠轉小棹，漾漾逐浮萍。", "載酒和嘉月，投篇弔獨醒。"]'),
('5e02f171-d1a7-48f4-8579-da3e3bdc1bb7','杏源','劉敞','宋','宋诗','song-poetry','','[]','淺水通漁艇，低花損帽簷。',24,'全唐诗/poet.song.28000.json','["淺水通漁艇，低花損帽簷。", "東風日夜起，幽興此中添。"]'),
('fd676c61-ec23-4c57-b352-1f89bf7a3c82','蓮池','劉敞','宋','宋诗','song-poetry','','[]','東池種蓮子，紅白間稀疏。',24,'全唐诗/poet.song.28000.json','["東池種蓮子，紅白間稀疏。", "夏木陰成後，君看錦不如。"]'),
('2269bc04-ff37-4664-bbda-28861c34e9e3','漁臺','劉敞','宋','宋诗','song-poetry','','[]','陳漁何處好，層觀倚高城。',24,'全唐诗/poet.song.28000.json','["陳漁何處好，層觀倚高城。", "快意屠門嚼，安知萬里鯨。"]'),
('abc38385-ca05-4c80-adca-f4b18b5bcbde','花嶼','劉敞','宋','宋诗','song-poetry','','[]','孤嶼曲池中，芳菲四面同。',24,'全唐诗/poet.song.28000.json','["孤嶼曲池中，芳菲四面同。", "春愁隨雀舫，繚繞未曾窮。"]'),
('b9c5c881-6d79-4f63-94b7-74a53e36e7b4','袁真人祠','劉敞','宋','宋诗','song-poetry','','[]','絳節朝何所，白蜺空此堂。',24,'全唐诗/poet.song.28000.json','["絳節朝何所，白蜺空此堂。", "神仙詎學得，客到彊焚香。"]'),
('925574bc-2d4d-4ce3-8c3f-fe954817e6f2','丹井','劉敞','宋','宋诗','song-poetry','','[]','清源秪數尺，知是鍊丹餘。',24,'全唐诗/poet.song.28000.json','["清源秪數尺，知是鍊丹餘。", "安得棲真子，相邀肘後書。"]'),
('e40adc7c-5e12-493b-9437-e17ddf94077e','竹岡','劉敞','宋','宋诗','song-poetry','','[]','層岡南面起，仰見檀欒姿。',24,'全唐诗/poet.song.28000.json','["層岡南面起，仰見檀欒姿。", "詰曲成幽洞，因堪象武夷。"]'),
('2603a5ee-3716-4092-99c9-cb364290272e','大楸','劉敞','宋','宋诗','song-poetry','','[]','長楸蔭柏堂，小枝猶合抱。',24,'全唐诗/poet.song.28000.json','["長楸蔭柏堂，小枝猶合抱。", "得地遂天年，斧斤安敢到。"]'),
('ceb9b77a-15bc-4009-aea4-9e3b80021fff','紅玉誰家女四首  其一','劉敞','宋','宋诗','song-poetry','','[]','紅玉誰家女，雙曈如水流。',24,'全唐诗/poet.song.28000.json','["紅玉誰家女，雙曈如水流。", "映花看漢使，不覺墜搔頭。"]'),
('55886c66-af8d-4f46-a128-efec5e520e8f','紅玉誰家女四首  其二','劉敞','宋','宋诗','song-poetry','','[]','紅玉誰家女，眀豔奪青春。',24,'全唐诗/poet.song.28000.json','["紅玉誰家女，眀豔奪青春。", "羞人不得語，含笑卻成嚬。"]'),
('34f70866-ee71-43a8-b02a-014086892697','紅玉誰家女四首  其三','劉敞','宋','宋诗','song-poetry','','[]','翠霞金縷衣，獨立翳斜暉。',24,'全唐诗/poet.song.28000.json','["翠霞金縷衣，獨立翳斜暉。", "無奈春風蕩，吹人只欲飛。"]'),
('0b64b739-9114-4b1e-8acf-a97ad2347bd2','紅玉誰家女四首  其四','劉敞','宋','宋诗','song-poetry','','[]','春風能吹衣，不能解人意。',24,'全唐诗/poet.song.28000.json','["春風能吹衣，不能解人意。", "使我爲朝雲，與君從此逝。"]'),
('c0f91456-e859-4eab-9078-1bda4a386e16','清明後鴈','劉敞','宋','宋诗','song-poetry','','[]','留滯江南久，今來萬里歸。',24,'全唐诗/poet.song.28000.json','["留滯江南久，今來萬里歸。", "春風稍和暖，作意入雲飛。"]'),
('23c55cc0-524a-4666-a4f7-52c421c2c24e','憶關中諸弟','劉敞','宋','宋诗','song-poetry','','[]','好去北歸鴈，憑將千里書。',24,'全唐诗/poet.song.28000.json','["好去北歸鴈，憑將千里書。", "潼關何日到，送目故愁予。"]'),
('073759d8-b0a4-405c-b4fe-0554bb736d27','立春日宿高陽關以病酒不飲復用前韻','劉敞','宋','宋诗','song-poetry','','[]','月色初元夜，花香翦綵春。',24,'全唐诗/poet.song.28000.json','["月色初元夜，花香翦綵春。", "而公高陽客，翻作獨醒人。"]'),
('fadb9e39-f45d-4ee9-833e-d1bed50117eb','寄書','劉敞','宋','宋诗','song-poetry','','[]','區脫逢歸驛，作書憑寄聲。',24,'全唐诗/poet.song.28000.json','["區脫逢歸驛，作書憑寄聲。", "那知夢識路，先入大梁城。"]'),
('554eef82-59d8-409f-938d-6faa9a0f1a5c','雨後回文','劉敞','宋','宋诗','song-poetry','','[]','綠水池光冷，青苔砌色寒。',24,'全唐诗/poet.song.28000.json','["綠水池光冷，青苔砌色寒。", "竹深啼鳥亂，庭暗落花殘。"]'),
('a77cde9d-a0a9-4afe-a1de-342c1bb8acaa','芍藥','劉敞','宋','宋诗','song-poetry','','[]','跗蕚晴相照，芳香暖競飄。',24,'全唐诗/poet.song.28000.json','["跗蕚晴相照，芳香暖競飄。", "波翻蜀地錦，霞萃赤城標。"]'),
('edf78105-b1ad-4ce4-a54e-c758139a4850','萱花','劉敞','宋','宋诗','song-poetry','','[]','種萱不種蘭，自謂憂可忘。',24,'全唐诗/poet.song.28000.json','["種萱不種蘭，自謂憂可忘。", "綠葉何萋萋，春愁更茫茫。"]'),
('27394d0c-d39a-4e33-937f-fbb0f54cd7d5','疊韻','劉敞','宋','宋诗','song-poetry','','[]','圖書如蘧廬，吏事累志意。',24,'全唐诗/poet.song.28000.json','["圖書如蘧廬，吏事累志意。", "招邀即逍遙，醉寐自棄置。"]'),
('01f2df17-32c4-467a-ab55-6a6996c52f07','山行','劉敞','宋','宋诗','song-poetry','','[]','荒徑惑東西，回環極翠微。',24,'全唐诗/poet.song.28000.json','["荒徑惑東西，回環極翠微。", "空持征鳥意，長作準繩飛。"]'),
('bf87ccae-4eb0-4042-86fd-9b8dd964b830','池上','劉敞','宋','宋诗','song-poetry','','[]','修竹仍封雪，交渠已泮冰。',24,'全唐诗/poet.song.28000.json','["修竹仍封雪，交渠已泮冰。", "那知四時改，獨有醉騰騰。"]'),
('2957a2a9-ec78-4848-a285-8e46ae9a4186','過分水嶺','劉敞','宋','宋诗','song-poetry','','[]','去去百憂集，回頭歸路迷。',24,'全唐诗/poet.song.28000.json','["去去百憂集，回頭歸路迷。", "紛然萬行淚，自逐水東西。"]'),
