('d96f8b18-e27f-42bd-bed5-4404f4d5a74d','武皇','劉敞','宋','宋诗','song-poetry','','[]','武皇英氣古無儔，解道平城遺朕憂。',32,'全唐诗/poet.song.28000.json','["武皇英氣古無儔，解道平城遺朕憂。", "汗血龍媒十八萬，單于臺下獵清秋。"]'),
('8ff84041-8657-4539-8c2a-4bd420ec018e','后土廟瓊花','劉敞','宋','宋诗','song-poetry','','[]','繁香簇簇三株樹，冷艷飄飄六出霙。',32,'全唐诗/poet.song.28000.json','["繁香簇簇三株樹，冷艷飄飄六出霙。", "移植天中來幾月，欲看憔悴老江城。"]'),
('26d27af7-0bc9-4bf0-a50e-689fcd059468','送張奕進士歸廣德省親','劉敞','宋','宋诗','song-poetry','','[]','南北旅遊三十年，相逢依舊孝亷船。',32,'全唐诗/poet.song.28000.json','["南北旅遊三十年，相逢依舊孝亷船。", "千鍾不洎今吾老，羨爾歸安二頃田。"]'),
('670cac32-bf14-4f34-a382-20019f117d4d','瓊花','劉敞','宋','宋诗','song-poetry','','[]','海內無雙玉蘂花，異時來自八仙家。',32,'全唐诗/poet.song.28000.json','["海內無雙玉蘂花，異時來自八仙家。", "魯人得此天中樹，乞與春風賞物華。"]'),
('83ad57ff-eb31-4439-9195-40865d82d732','董相','劉敞','宋','宋诗','song-poetry','','[]','江都治後徙膠西，衰老諸侯等棄之。',32,'全唐诗/poet.song.28000.json','["江都治後徙膠西，衰老諸侯等棄之。", "爲問平津相天下，尚開東閣欲賓誰。"]'),
('af834836-811a-4f0d-959d-5e00b229b4ae','白登','劉敞','宋','宋诗','song-poetry','','[]','白登計秘自堪羞，相印猶歸曲逆侯。',32,'全唐诗/poet.song.28000.json','["白登計秘自堪羞，相印猶歸曲逆侯。", "安用熊羆三十萬，平城遺有子孫憂。"]'),
('6cbd8551-0e16-474b-98ea-b8cf8e0999e2','鎖宿禮部中夜口號','劉敞','宋','宋诗','song-poetry','','[]','浮雲不動月微眀，錦帳香寒夢易驚。',32,'全唐诗/poet.song.28000.json','["浮雲不動月微眀，錦帳香寒夢易驚。", "猶覺春風花未發，獨聞宫漏出重城。"]'),
('c88d796c-431c-49ab-a274-8d8d7d608bc3','題送客亭别任迥','劉敞','宋','宋诗','song-poetry','','[]','北飛鴻鴈南飛燕，擾擾俱非自在身。',32,'全唐诗/poet.song.28000.json','["北飛鴻鴈南飛燕，擾擾俱非自在身。", "莫向孤亭南北望，野花江草最愁人。"]'),
('157ece40-6bd6-466f-9237-353b95cb30ce','送魏廣秘校同年','劉敞','宋','宋诗','song-poetry','','[]','羨君歸著老萊衣，風雨紛紜欲别時。',32,'全唐诗/poet.song.28000.json','["羨君歸著老萊衣，風雨紛紜欲别時。", "會是東堂許爲友，自憐扶路不勝悲。"]'),
('6056c996-abf4-4661-8f56-55d2c9a9f1ae','風雨','劉敞','宋','宋诗','song-poetry','','[]','人生老去自多憂，索索逢春卻似秋。',32,'全唐诗/poet.song.28000.json','["人生老去自多憂，索索逢春卻似秋。", "過盡百花初不省，何須風雨更添愁。"]'),
('8454cb5f-3eb1-4753-9ba1-48d756e8b675','山光寺','劉敞','宋','宋诗','song-poetry','','[]','隋家昔日歌舞地，荒草滿庭烟霧深。',32,'全唐诗/poet.song.28000.json','["隋家昔日歌舞地，荒草滿庭烟霧深。", "猶有老松長百尺，悲風來動海潮音。"]'),
('d15447d1-42cb-4bf6-91e3-288bcd1dd0e4','答張安內翰見贈二絕  其一','劉敞','宋','宋诗','song-poetry','','[]','雲鵬自合縱天池，蒿鷃寧嫌寄一枝。',32,'全唐诗/poet.song.28000.json','["雲鵬自合縱天池，蒿鷃寧嫌寄一枝。", "適往蚤聞仙老辨，解嘲聊慰俗人嗤。"]'),
('45df379b-cc94-4c14-8577-68670ebd3e83','答張安內翰見贈二絕  其二','劉敞','宋','宋诗','song-poetry','','[]','玉螭階側鳳池邊，接武嚴徐愧昔賢。',32,'全唐诗/poet.song.28000.json','["玉螭階側鳳池邊，接武嚴徐愧昔賢。", "天驥絕塵方萬里，知君不顧繞朝鞭。"]'),
('0a74636c-7855-4733-9f2d-8ebe9112dad9','答阮逸中允','劉敞','宋','宋诗','song-poetry','','[]','天後天先隱姓名，曾聞注易動公卿。',32,'全唐诗/poet.song.28000.json','["天後天先隱姓名，曾聞注易動公卿。", "窮愁不得無編述，慚愧刪詩取正聲。"]'),
('2e39b855-eb26-4415-84ef-d63aba249272','小桃','劉敞','宋','宋诗','song-poetry','','[]','鳴鳩喚雨天色變，遲日烘雲花意催。',32,'全唐诗/poet.song.28000.json','["鳴鳩喚雨天色變，遲日烘雲花意催。", "一日出遊三日醉，自知慚負小桃開。"]'),
('546e641e-d5b2-4b4c-acc2-3a6ff2ddcf57','和趙七得屯田郎','劉敞','宋','宋诗','song-poetry','','[]','童稚聞君賦上林，校讎偏愧接華簪。',32,'全唐诗/poet.song.28000.json','["童稚聞君賦上林，校讎偏愧接華簪。", "朝廷禮樂推先進，莫歎郎潛佩肘金。"]'),
('315d9720-47ab-49ed-889c-81ba6a320b76','鄢陵興國寺題壁','劉敞','宋','宋诗','song-poetry','','[]','寂寞空堂欲暮時，鐘聲斷續雨千絲。',32,'全唐诗/poet.song.28000.json','["寂寞空堂欲暮時，鐘聲斷續雨千絲。", "此中會有西來意，正復庭前柏樹知。"]'),
('eddc5a3e-1387-4bd0-b255-a6a431d65212','詩一首','劉敞','宋','宋诗','song-poetry','','[]','本是昌家，又爲非類。',20,'全唐诗/poet.song.28000.json','["本是昌家，又爲非類。", "但有雄聲，唯聞艾氣。"]'),
('e05a837f-f7fa-476b-87a5-36dcc58117e0','出長蘆口','劉敞','宋','宋诗','song-poetry','','[]','濤翻鷺羽連天白，山疊屏峰到海青。',32,'全唐诗/poet.song.28000.json','["濤翻鷺羽連天白，山疊屏峰到海青。", "客路浮生兩如寄，萬重波裏一浮萍。"]'),
('c12f8665-490a-4a93-a4ab-10ab5307a8de','芍藥','劉敞','宋','宋诗','song-poetry','','[]','溱洧洵訏樂，維陽厥草夭。',72,'全唐诗/poet.song.28000.json','["溱洧洵訏樂，維陽厥草夭。", "傳聞多失實，看盡謾無聊。", "婉娩春陽謝，中開道路遙。", "誰移化工巧，忽是物華饒。", "跗萼晴相照，芳春暖並飄。", "波翻蜀江錦，霞萃赤城標。"]'),
('ffccab1e-1e90-4c26-9fb5-f9143bfa6dca','荼蘼二首  其一','劉敞','宋','宋诗','song-poetry','','[]','瓊林殿側玉鈎欄，雪覆新花四月閑。',32,'全唐诗/poet.song.28000.json','["瓊林殿側玉鈎欄，雪覆新花四月閑。", "密影酡容千客坐，柔條何啻萬龍蟠。"]'),
('e272ec19-0d08-4628-9633-726153cf8339','荼蘼二首  其二','劉敞','宋','宋诗','song-poetry','','[]','明紅暗紫競芬菲，送盡東風不自知。',32,'全唐诗/poet.song.28000.json','["明紅暗紫競芬菲，送盡東風不自知。", "占得餘香慰愁眼，百芳無得似荼蘼。"]'),
('53912eb4-24d1-48b3-a9b9-2edba6603041','木香花','劉敞','宋','宋诗','song-poetry','','[]','粉刺叢叢鬥野芳，春風搖曳不成行。',32,'全唐诗/poet.song.28000.json','["粉刺叢叢鬥野芳，春風搖曳不成行。", "只因愛學宮粧樣，分得梅花一半香。"]'),
('888f381d-c5a8-4d28-81a3-21683ba8b55d','迎春花','劉敞','宋','宋诗','song-poetry','','[]','華省當時綠鬢郎，金樽美酒醉紅芳。',32,'全唐诗/poet.song.28000.json','["華省當時綠鬢郎，金樽美酒醉紅芳。", "今日對花不成飲，春愁已與草俱長。"]'),
('2387b955-4170-492a-9f8c-b1729f60e81a','櫻桃','劉敞','宋','宋诗','song-poetry','','[]','晨暉照屋清露稀，櫻桃花房欲開齊。',48,'全唐诗/poet.song.28000.json','["晨暉照屋清露稀，櫻桃花房欲開齊。", "繁華先得造物巧，不與衆卉爭高低。", "參差萼萼相照耀，恍惚滿眼令人迷。"]'),
('d33b015d-7bf5-420e-b197-e79f3d8cf943','金錢花','劉敞','宋','宋诗','song-poetry','','[]','披沙百煉貴，濟世五銖圜。',48,'全唐诗/poet.song.28000.json','["披沙百煉貴，濟世五銖圜。", "侔色都疑似，頒行適自然。", "蕭蕭秋意早，采采露華鮮。", "貧謝侏儒甚，煩君慰眼前。"]'),
('3e45a3de-4edd-459d-b997-4e25f57507b0','柏','劉敞','宋','宋诗','song-poetry','','[]','柏生如拳柳如把，同時移根種庭下。',48,'全唐诗/poet.song.28000.json','["柏生如拳柳如把，同時移根種庭下。", "柏根未活柳已榮，春風飛飛意融冶。", "青條眼看千尺餘，疏蔭朦朧乃驚詫。"]'),
('633d8178-bdb3-4dbb-bcf5-19ce2c693b1f','筍','劉敞','宋','宋诗','song-poetry','','[]','龍孫春吐一尺芽，紫錦包玉離泥沙。',32,'全唐诗/poet.song.28000.json','["龍孫春吐一尺芽，紫錦包玉離泥沙。", "金刀璀璨截嫩節，銅錢不與大梁賒。"]'),
('905a23f9-b2e2-4d5b-b3ae-cf2b6fe9e3f3','燈花','劉敞','宋','宋诗','song-poetry','','[]','火中有芝，殊幹連葉。',40,'全唐诗/poet.song.28000.json','["火中有芝，殊幹連葉。", "頃刻三秀，爛其煜煜。", "孰爲而生，孰爲而滋。", "既富且壽，君子正之。"]'),
('f3e9aca7-a423-4d0c-a14d-fd9dfdda01c7','古風','劉敞','宋','宋诗','song-poetry','','[]','子欲富矣，何用爲富。',63,'全唐诗/poet.song.28000.json','["子欲富矣，何用爲富。", "農不苦工，工不若賈。", "子欲貴矣，何用爲貴。", "德不若名，名不若勢。", "粹兮純兮，三五之人兮。", "終窶且貧兮，孰知其珍兮。"]'),
('1a4dc8e4-9b36-4f89-bd4c-0b4694bdbef3','雜詩','劉敞','宋','宋诗','song-poetry','','[]','齊有梁丘據，晉有樂王鮒。',108,'全唐诗/poet.song.28000.json','["齊有梁丘據，晉有樂王鮒。", "據能愛晏嬰，鮒欲殘叔譽。", "二臣嬖兩朝，事君爲悅豫。", "景有尚賢志，據逆以爲助。", "平失宥善心，鮒乃速其去。", "毋以據爲賢，易地則同趣。", "丈夫處世間，必有遇不遇。", "豈無覺者乎，正色君亦悟。", "區區嬖倖徒，何忍就朋附。"]'),
('de54535d-2cb6-44d5-8cb9-49d96bbcdb23','重傷胡二','劉敞','宋','宋诗','song-poetry','','[]','今日寢門側，涕流予不堪。',48,'全唐诗/poet.song.28000.json','["今日寢門側，涕流予不堪。", "伊人竟長逝，回使返空函。", "如覺知音絕，深懷掛劍慚。", "仍聞身後事，生女不生男。"]'),
('74999349-5ffe-43ff-858e-6d80399ab8b5','采藍寄王深甫','劉敞','宋','宋诗','song-poetry','','[]','采采澤中藍，製爲金翠衣。',48,'全唐诗/poet.song.28000.json','["采采澤中藍，製爲金翠衣。", "春風爲君舞，婉轉有光輝。", "良辰古易失，麗色世云希。", "嗟嗟不盈掬，日暮空來歸。"]'),
('9b21c30e-d4bf-4ded-8cd2-5c78845e1412','觀陝西圖','劉敞','宋','宋诗','song-poetry','','[]','乘槎漢使者，聚米馬將軍。',48,'全唐诗/poet.song.28000.json','["乘槎漢使者，聚米馬將軍。", "關塞他年阻，河山此座分。", "悠悠傷戰骨，處處怒妖氛。", "未分儒生老，深希筆硯焚。"]'),
('1b98c963-7232-4fc4-8af0-f8731d88d483','周節推移曹州此君凡換五幕府','劉敞','宋','宋诗','song-poetry','','[]','珠履幕中客，棲棲亦倦遊。',48,'全唐诗/poet.song.28000.json','["珠履幕中客，棲棲亦倦遊。", "勞歌一長鋏，歷聘五諸侯。", "捧檄爲親喜，問津輕旅愁。", "誰憐在陳士，無友重悲秋。"]'),
('934818f9-7eca-43b7-9e6e-fb242e8f8e1f','送張六丈尉新安','劉敞','宋','宋诗','song-poetry','','[]','新安好江水，往復似桐廬。',48,'全唐诗/poet.song.28000.json','["新安好江水，往復似桐廬。", "吏隱應相稱，官卑還自如。", "洛塵趨走裏，周俗戰爭餘。", "會自求知己，頻飛一鶚書。"]'),
('e8d1296b-eff4-41fc-b3f6-bd8c403e73e6','芷亭','劉敞','宋','宋诗','song-poetry','','[]','籍甚離騷後，芬芬楚澤濱。',48,'全唐诗/poet.song.28000.json','["籍甚離騷後，芬芬楚澤濱。", "移根煩老圃，比興得佳人。", "秀色誰與玩，清香不自珍。", "吾廬故可愛，況及物華春。"]'),
('2a82be74-e9e7-4679-afa4-65d1d09095c3','晚涼','劉敞','宋','宋诗','song-poetry','','[]','楚山何處雨，天氣晚來涼。',48,'全唐诗/poet.song.28000.json','["楚山何處雨，天氣晚來涼。", "返照原野靜，清風松桂香。", "高樓半雲霧，遠水入滄浪。", "幽意驚飛動，真憑酒散狂。"]'),
('8b8b49d4-1e35-4600-a4b7-622b5dc84bad','奉同永叔於劉功曹家聽楊直講女奴彈啄木見寄之作','劉敞','宋','宋诗','song-poetry','','[]','空林多風霜霰零，啄木朝饑悲長鳴。',218,'全唐诗/poet.song.28000.json','["空林多風霜霰零，啄木朝饑悲長鳴。", "口雖能呼心不平，誰彈琵琶象其聲。", "雌雄切直相丁嚶，欲飛未飛皆有情。", "琵琶八十有四調，此曲獨得傳玄妙。", "翠鬟小女眉目殊，能承主歡供客娛。", "轉關揮撥意澹如，坐人雖多旁若無。", "醉翁引觴不汝餘，歌詩彈鋏歸來乎。", "兩君韻高尚如此，何況櫪上之馬淵中魚。", "我生不曉世俗樂，頃臥江城更寂寞。", "園中有時聞啄木，雖有高下無宮角。", "木聲梨然當人心，猋氏之風殆可學。", "淵明無弦非無意，白髮秋來自少樂。", "得公新詩濯我愁，因問楊子更借不，我欲醉聽江城樓。"]'),
('d71d209e-a1a7-4dd8-8f4e-ad580e1efd72','汾州有唐大曆中崇徽公主嫁回鶻時手迹在石壁上李山甫作七言詩並刻之子華永叔內翰皆繼其韻亦同賦','劉敞','宋','宋诗','song-poetry','','[]','錦車西去水東流，漢節何年送解憂。',64,'全唐诗/poet.song.28000.json','["錦車西去水東流，漢節何年送解憂。", "獨上青山自惆悵，強歌黄鵠少淹留。", "遺蹤不逐哀笳斷，麗句空增北渚愁。", "君念平城三十萬，謀臣奇計已堪羞。"]'),
('af5dcfbd-5b20-4c14-8d18-92eddc65c450','自入北界虜人候迓供帳每進益恭少嘗至契丹者皆云異他日示陳副使希元','劉敞','宋','宋诗','song-poetry','','[]','和親雖復用諸儒，聖德由來北服胡。',64,'全唐诗/poet.song.28000.json','["和親雖復用諸儒，聖德由來北服胡。", "天子今成大父行，匈奴自號兒單于。", "女真守燎羯圉馬，渤海西道奚前驅。", "塞外始知漢使貴，留犁撓酒直區區。"]'),
('0208c600-9637-4e02-902a-d05a87f9aa33','和永叔禁中對月','劉敞','宋','宋诗','song-poetry','','[]','珠宮銀闕閟金鑾，獨得清輝盡夕看。',64,'全唐诗/poet.song.28000.json','["珠宮銀闕閟金鑾，獨得清輝盡夕看。", "冷奪雪霜深刺骨，瑩分毫髪凜沖冠。", "通中夢覺爐香斷，方底封餘玉滴乾。", "佳句冠傳天上景，世人空仰白雲端。"]'),
('c133e8a6-3358-41a8-904b-59f03b25f310','正月初五日杜城集','劉敞','宋','宋诗','song-poetry','','[]','雪霽春容滿舊都，尋春寫鞚杜城隅。',64,'全唐诗/poet.song.28000.json','["雪霽春容滿舊都，尋春寫鞚杜城隅。", "冰消流水相縈带，日出南山半有無。", "往事廢興悲故老，扁舟沿泝想江湖。", "路人應笑山公醉，此興由來屬我徒。"]'),
('a9127687-e163-4ec3-8257-3cd994f2f66c','丙申閏月領揚州與京師諸公別戊戌十一月受詔還閣首尾僅三年爾然原叔伯庸隱甫子奇公南清卿之翰昌言八人者皆已徂謝感之愴然作七言寄滑州正臣密學給事','劉敞','宋','宋诗','song-poetry','','[]','冠蓋如雲笑別時，亦知陳迹易傷悲。',64,'全唐诗/poet.song.28000.json','["冠蓋如雲笑別時，亦知陳迹易傷悲。", "歸來未似鍾山醉，零落多於鄴下詩。", "人事可憐駒過隙，秋風幾許鬢成絲。", "何須更聽山陽笛，欲近西州涕自垂。"]'),
('a3d87cab-5b23-4c6e-957e-e299283c6e46','集禧齋宮雨後','劉敞','宋','宋诗','song-poetry','','[]','雨餘風露似清秋，燈燭愔愔十二樓。',64,'全唐诗/poet.song.28000.json','["雨餘風露似清秋，燈燭愔愔十二樓。", "高枕江湖時獨往，卷簾河漢正西流。", "人間浪逐顛冥客，物外初知汗漫遊。", "拂露卻趨青閣路，蓬萊回顧五雲浮。"]'),
('9b42c259-a271-4d82-80aa-8020239cd495','聽女奴彈胡琴','劉敞','宋','宋诗','song-poetry','','[]','女奴能爲馬上曲，一彈一彈復一彈。',32,'全唐诗/poet.song.28000.json','["女奴能爲馬上曲，一彈一彈復一彈。", "我醉已眠都不醒，半天落月微霜寒。"]'),
('000fe831-0228-495f-b5a5-f1be0b757a99','庭前菊花','劉敞','宋','宋诗','song-poetry','','[]','翠葉金花刮眼明，薄霜濃露倍多情。',32,'全唐诗/poet.song.28000.json','["翠葉金花刮眼明，薄霜濃露倍多情。", "誰人正苦山中醉，借與繁香醒宿酲。"]'),
('67f4f5d8-fb3c-4f44-93ca-9bda77282437','戲作二首  其一','劉敞','宋','宋诗','song-poetry','','[]','仙家千載亦何長，人世空驚日月忙。',32,'全唐诗/poet.song.28000.json','["仙家千載亦何長，人世空驚日月忙。", "洞裏桃花莫相笑，劉郎今是老劉郎。"]'),
('3dc25227-3e1f-4662-b6da-9f4a62d7d4f0','戲作二首  其二','劉敞','宋','宋诗','song-poetry','','[]','文章落筆有誰先，坐上詩成海外傳。',32,'全唐诗/poet.song.28000.json','["文章落筆有誰先，坐上詩成海外傳。", "明日帝京應紙貴，開簾卻扇有新編。"]'),
('32f0288a-5613-4d7b-97d6-fd9ccbd7bb95','詩一首','劉敞','宋','宋诗','song-poetry','','[]','蒼茫六合外，渺莽三皇初。',24,'全唐诗/poet.song.28000.json','["蒼茫六合外，渺莽三皇初。", "近既未必有，遠亦未必無。"]'),
('ca8d6c35-c853-4674-8e15-da7f6fc6137e','農父  其一','劉敞','宋','宋诗','song-poetry','','[]','入水作田，上山伐薪。',40,'全唐诗/poet.song.28000.json','["入水作田，上山伐薪。", "人世幾何，終歲苦貧。", "安有靈藥，化爲羽人。", "呼吸光景，爲君外臣。"]'),
('4c915007-aae4-4f0a-b58a-f9d9e1bb848b','農父  其二','劉敞','宋','宋诗','song-poetry','','[]','鳥飛不遠，暮還其宅。',40,'全唐诗/poet.song.28000.json','["鳥飛不遠，暮還其宅。", "我獨匪人，去從兵籍。", "釋棄耒耜，顧貪朝夕。", "轉徙異方，終世爲客。"]'),
('5c4be171-31d8-4f9b-94d3-c8d3820ad013','農哀','劉敞','宋','宋诗','song-poetry','','[]','陰陽失常度，水旱互爲災。',96,'全唐诗/poet.song.28000.json','["陰陽失常度，水旱互爲災。", "歲暮不成耕，閭里自相哀。", "相哀竟何奈，田畝棄汙萊。", "欲行關租急，欲居兵賦催。", "同知羅憂患，誰復念嬰孩。", "往往遺渠溝，顧之淚如頹。", "國庾須積粟，國帑須羨財。", "大臣職富國，爾命自宜哉。"]'),
('3e9428f9-1b22-40c2-a969-4132e8aee67e','贈別長安妓蔡嬌','劉敞','宋','宋诗','song-poetry','','[]','玳筵銀燭徹宵明，白玉佳人唱渭城。',32,'全唐诗/poet.song.28000.json','["玳筵銀燭徹宵明，白玉佳人唱渭城。", "更盡一杯須起舞，關河秋月不勝情。"]'),
('fbf872d0-f80e-4b5d-acf4-9134e0f81909','宿烏沙','劉敞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朝離巴陵岸，暮投烏沙汀。',84,'全唐诗/poet.song.28000.json','["朝離巴陵岸，暮投烏沙汀。", "大江屢回環，反顧猶洞庭。", "月色奪暗日，舟人各宵征。", "東南浮雲際，極望都冥冥。", "不辨水與天，高低皆見星。", "分明銀河流，來與江漢並。", "安得數尺槎，漂然向天庭。"]'),
('37d81f0a-aca3-4c0f-b9ce-0bdfd907175f','讀列子贈幾太博勝之殿丞君章監丞','劉敞','宋','宋诗','song-poetry','','[]','五嶽窮雲霓，滄海不可游。',204,'全唐诗/poet.song.28000.json','["五嶽窮雲霓，滄海不可游。", "玉臺焜朝日，珠華媚飛虬。", "飄颻羣仙子，來往何其稠。", "咫尺視千里，俯仰移九秋。", "潮波有時起，勢若空中浮。", "禺彊受帝命，巨鰲舉其頭。", "邇來百萬祀，無復遷播憂。", "龍伯何爲者，修干曳長鈎。", "不知意誰憾，似與鰲爲仇。", "六鱗既潛舉，二山忽飄流。", "衆真失其常，蕩析不自謀。", "孰云飛升樂，奔迫良可愁。", "盈虛誠難必，藏壑有亡舟。", "至人縱大觀，夷險固悠悠。", "如聞帝憑怒，侵減龍伯儔。", "且欲招羣仙，復還故時丘。", "勉哉凌雲迹，永謝北極幽。"]'),
('bc6ff1c8-5987-452d-bef2-77abc2812e33','迴風館','劉敞','宋','宋诗','song-poetry','','[]','殿翼翔空直，樓陰蔽日寬。',48,'全唐诗/poet.song.28000.json','["殿翼翔空直，樓陰蔽日寬。", "風聲彌玉宇，仙術廢冰丸。", "老檜頻成籟，相烏不定竿。", "世人驚未到，六月尚清寒。"]'),
('fffa7b3d-1500-4cb9-bba4-7ea6fff7c641','臨都館','劉敞','宋','宋诗','song-poetry','','[]','攬轡歲空盡，蕭條萬里間。',48,'全唐诗/poet.song.28000.json','["攬轡歲空盡，蕭條萬里間。", "向來貂已敝，此去鬢宜班。", "雪沒前王帳，沙連右地山。", "星回陽氣復，吾亦至幾還。"]'),
('67fe2007-f6dc-48be-b7e2-2944d038e888','張三館有前歲赴舉時題字處作  其一','劉敞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','羈旅關東來獻書，還曾題柱宿匡廬。',32,'全唐诗/poet.song.28000.json','["羈旅關東來獻書，還曾題柱宿匡廬。", "自知不及相如健，重到曾無駕駟車。"]'),
('79aa71bd-019c-4a29-a1eb-2948aff506e6','張三館有前歲赴舉時題字處作  其二','劉敞','宋','宋诗','song-poetry','','[]','暫懷印綬過家庭，車馬驂驔去路輕。',32,'全唐诗/poet.song.28000.json','["暫懷印綬過家庭，車馬驂驔去路輕。", "自爲綵衣生意氣，敢將晝錦比光榮。"]'),
('8ac600e5-0185-4170-9118-092964de10a8','自恩平還題嵩臺宋隆館  其一','劉敞','宋','宋诗','song-poetry','','[]','四山如畫古端州，州在西江欲盡頭。',32,'全唐诗/poet.song.28000.json','["四山如畫古端州，州在西江欲盡頭。", "謾道江山解留客，老夫歸思甚東流。"]'),
('63019861-3d20-4af3-8cc0-01cb1eb03ae9','自恩平還題嵩臺宋隆館  其二','劉敞','宋','宋诗','song-poetry','','[]','松菊壺山手自栽，二年羈宦客嵩臺。',32,'全唐诗/poet.song.28000.json','["松菊壺山手自栽，二年羈宦客嵩臺。", "無端卻被東風誤，又作恩平一夢回。"]'),
('868b988b-538e-4b81-aef6-96d686bde32f','和張景純初置館中','劉敞','宋','宋诗','song-poetry','','[]','張也湖海士，心與迹並真。',180,'全唐诗/poet.song.28000.json','["張也湖海士，心與迹並真。", "語默或不常，時以爲狂人。", "蹉跎太倉史，奔走京華塵。", "頗如喪家狗，纍纍敝精神。", "雖游公卿間，望絕要路津。", "感激自上書，生當致青雲。", "天光回日月，聖澤熙陽春。", "禁林給筆札，中府紬典墳。", "羣玉連帝居，東壁臨北辰。", "飛騰怪清切，寓直懷珍羣。", "慷慨氣益遒，咏歌思逾新。", "昔賢稽古力，利祿不足云。", "登瀛以爲榮，襆被寧厭頻。", "君乃鸞鳳姿，方當極逢辰。", "豈若楊執戟，白頭專校文。"]'),
('afb9e72f-41ea-485d-82d9-6787ae62673e','松子嶺','劉敞','宋','宋诗','song-poetry','','[]','鹿兒峽未盡，松子嶺相望。',48,'全唐诗/poet.song.28000.json','["鹿兒峽未盡，松子嶺相望。", "走險暇掃廕，摩空愁亂行。", "霜增頭皓白，塵變馬曬黄。", "不作還鄉意，羈人應斷腸。"]'),
('ffc8059f-05eb-4e87-bd93-205064673ae1','壺公祠大樹','劉敞','宋','宋诗','song-poetry','','[]','壺公飛昇向千歲，茲樹懸壺今尚在。',128,'全唐诗/poet.song.28000.json','["壺公飛昇向千歲，茲樹懸壺今尚在。", "繁根鬰屈蟠蛟龍，冗幹呺嚎作天籟。", "樛枝入土又旁出，四面童童若車蓋。", "大鈞播物信容易，父老相傳謾驚駭。", "孔明廟前千丈栢，老子庭中左紐檜。", "天資正直本當壽，地養堅強自宜大。", "嗟爾朽質名弗聞，雖能所生世何賴。", "雷霆不及斤斧遺，但恐狐貍假爲怪。"]'),
('abc65491-6ea1-4826-9e41-96ade2a5286f','和尚叔父病目','劉敞','宋','宋诗','song-poetry','','[]','慟器論時事，幽居祇杜門。',48,'全唐诗/poet.song.28000.json','["慟器論時事，幽居祇杜門。", "自然憂未弭，那不眼潛昏。", "火齊終無纇，泉沙暫有渾。", "誰資上池水，洞視一方垣。"]'),
('86c52644-8da5-41f3-a93d-50f50c9f8032','晚晴小園','劉敞','宋','宋诗','song-poetry','','[]','野客幽居何處尋，小園荒徑似山林。',96,'全唐诗/poet.song.28000.json','["野客幽居何處尋，小園荒徑似山林。", "雨足蝦蟆何自喜，秋來蟋蟀競悲吟。", "丹青果實同時熟，紅白荷花相映深。", "可怨幽蘭老堂下，無端柔蔓上城陰。", "微茫返照樓頭出，蕭索孤煙天際沉。", "楚澤偏傷千里目，西風自覺倦登臨。"]'),
('4df68eea-f808-4d3c-aa84-53dbbe4ea7a1','伏日尋鄰幾不見','劉敞','宋','宋诗','song-poetry','','[]','朝日出東北，青雲散朱暉。',72,'全唐诗/poet.song.28000.json','["朝日出東北，青雲散朱暉。", "堅金爲之鑠，信此庚氣微。", "吾子善閉關，今何冒炎威。", "流汗正被面，飛塵常滿衣。", "憶君若冰雪，無以慰渴饑。", "伏日萬鬼行，至如早旋歸。"]'),
('00cadb8b-0872-4489-83e0-46768d42e1f5','詩一首','劉敞','宋','宋诗','song-poetry','','[]','菩薩號文殊，禪堂名曲講。',24,'全唐诗/poet.song.28000.json','["菩薩號文殊，禪堂名曲講。", "語默本同源，名實不相愯。"]'),
('a5f8f9ec-cc08-4461-afef-35efe64c8111','種麥','劉敞','宋','宋诗','song-poetry','','[]','禹稷躬稼穡，春秋重麥禾。',84,'全唐诗/poet.song.28000.json','["禹稷躬稼穡，春秋重麥禾。", "勸耕聊及暇，稱力焉俟多。", "霜風雖凄緊，日晏更清和。", "輕裘頗自姿，扶杖勤來過。", "青青已布隴，芃芃在伐柯。", "農功欣嗣歲，節物嗟騰波。", "悵然念歸田，自顧將婆娑。"]'),
('736b2abb-0cb1-4b84-ae69-7a4f3946c545','葵花','劉敞','宋','宋诗','song-poetry','','[]','白露清風催八月，紫蘭紅葉共凄涼。',32,'全唐诗/poet.song.28000.json','["白露清風催八月，紫蘭紅葉共凄涼。", "黄花冷淡無人看，獨自傾心向太陽。"]'),
('9433c259-d44b-4a01-b99c-08a22937d304','五色菊','劉敞','宋','宋诗','song-poetry','','[]','屢聞白雪題詩句，飽見黄花泛酒杯。',32,'全唐诗/poet.song.28000.json','["屢聞白雪題詩句，飽見黄花泛酒杯。", "豈是一枝能五色，相隨次第雪中開。"]'),
('55dfe269-f353-46ab-a31a-99bbcff19c91','行吟三清墀中示雷生','劉敞','宋','宋诗','song-poetry','','[]','翠柏高松雨後新，薄寒初起地無塵。',32,'全唐诗/poet.song.28000.json','["翠柏高松雨後新，薄寒初起地無塵。", "自披鶴氅吟詩句，何必神仙更有人。"]'),
('17e5349d-1a08-43f3-9d38-98122134077e','上書行','劉敞','宋','宋诗','song-poetry','','[]','仕不至二千石，賈不至五百萬。',163,'全唐诗/poet.song.28000.json','["仕不至二千石，賈不至五百萬。", "此事夸者憂，而非志士嘆。", "君不見下邳少年受書起，幄中運籌制千里。", "功成不受二萬戶，拂衣歸從赤松子。", "君不見計倪半策誅強吳，鴟夷扁舟遊五湖。", "三致千金不自擅，至今籍籍宗陶朱。", "大賢富貴不爲己，心事邈與常人殊。", "逢時致身如反手，雲蒸龍變無時無。", "君勿愛上書獻賦稱賢豪，刺繡倚市相矜高。", "丈夫昔曾笑徒勞，商賈旦旦爭錐刀。"]'),
('7206aed5-4fc1-44e4-9783-b64827669398','集曲水臺','劉敞','宋','宋诗','song-poetry','','[]','羽觴泛中流，坐傍修竹里。',24,'全唐诗/poet.song.28000.json','["羽觴泛中流，坐傍修竹里。", "右軍期不來，白鷗自飛起。"]'),
('46aa49a3-3baa-4bf5-95f9-2703700e1057','句  其一','劉敞','宋','宋诗','song-poetry','','[]','因君古人風，更欲投吾簪。',12,'全唐诗/poet.song.28000.json','["因君古人風，更欲投吾簪。"]'),
('9a962672-cbf7-4527-aacb-b9487ff2170c','句  其二','劉敞','宋','宋诗','song-poetry','','[]','江色明吳甸，山香落楚梅。',12,'全唐诗/poet.song.28000.json','["江色明吳甸，山香落楚梅。"]'),
('0d3cc706-3f68-484a-88f6-9702f3127253','句  其三','劉敞','宋','宋诗','song-poetry','','[]','璽書幾日來宣室。',8,'全唐诗/poet.song.28000.json','["璽書幾日來宣室。"]'),
('b88ba840-c0c3-4ed9-b86c-d6ed057c9faf','句  其四','劉敞','宋','宋诗','song-poetry','','[]','傾家釀酒經年醉，不使春風負玉壺。',16,'全唐诗/poet.song.28000.json','["傾家釀酒經年醉，不使春風負玉壺。"]'),
('a392f9b5-6851-48f7-bd45-04d6f847a26f','句  其五','劉敞','宋','宋诗','song-poetry','','[]','強挽春風留一醉，露香還可析朝酲。',16,'全唐诗/poet.song.28000.json','["強挽春風留一醉，露香還可析朝酲。"]'),
('fdc54ad1-a835-401c-8a91-670f583078fe','句  其六','劉敞','宋','宋诗','song-poetry','','[]','城角日高人寂寞，小庭行遍拾桐花。',16,'全唐诗/poet.song.28000.json','["城角日高人寂寞，小庭行遍拾桐花。"]'),
('badee5aa-8268-4bf2-808b-1ce8eaa089fa','句  其七','劉敞','宋','宋诗','song-poetry','','[]','深林幽寂秋雨晦，叢蘭猗猗無所佩。',16,'全唐诗/poet.song.28000.json','["深林幽寂秋雨晦，叢蘭猗猗無所佩。"]'),
('3e8862e7-d2d6-40e2-bb7d-a16f0821908d','句  其八','劉敞','宋','宋诗','song-poetry','','[]','薰風四月濃芳歇，火玉燒枝拂露華。',16,'全唐诗/poet.song.28000.json','["薰風四月濃芳歇，火玉燒枝拂露華。"]'),
('d65eaf7b-fd06-4ddc-bad9-c264b775bbc9','句  其九','劉敞','宋','宋诗','song-poetry','','[]','南賓佳實傳名久，曾憶巴山寄楚人。',16,'全唐诗/poet.song.28000.json','["南賓佳實傳名久，曾憶巴山寄楚人。"]'),
('18d36f92-8a4a-47ff-af30-d3eddc08a595','句  其一○','劉敞','宋','宋诗','song-poetry','','[]','頌聲騷客誤，錫貢禹書遲。',12,'全唐诗/poet.song.28000.json','["頌聲騷客誤，錫貢禹書遲。"]'),
('709485dc-b1b5-439e-893e-e9d6eda25651','句  其一一','劉敞','宋','宋诗','song-poetry','','[]','江南碧木映霜秋，丹實清香破客愁。',16,'全唐诗/poet.song.28000.json','["江南碧木映霜秋，丹實清香破客愁。"]'),
('ad1e6b87-01d9-47f9-9eb9-3c2cd7916c8f','句  其一二','劉敞','宋','宋诗','song-poetry','','[]','不識日高眠起處，何如風定舞餘時。',16,'全唐诗/poet.song.28000.json','["不識日高眠起處，何如風定舞餘時。"]'),
('a8035581-158d-486e-8bd1-79b1ddf50140','句  其一三','劉敞','宋','宋诗','song-poetry','','[]','南牆雙柏天生直，材雖未老心千尺。',16,'全唐诗/poet.song.28000.json','["南牆雙柏天生直，材雖未老心千尺。"]'),
('4ec51450-8436-4313-90a5-0eaa41b4a97c','句  其一四','劉敞','宋','宋诗','song-poetry','','[]','美田鈎盾裏，躬稼麥秋餘。',12,'全唐诗/poet.song.28000.json','["美田鈎盾裏，躬稼麥秋餘。"]'),
('326c5caa-9ed7-4095-b230-8d86d3e18360','句  其一五','劉敞','宋','宋诗','song-poetry','','[]','但見古河東，蕎麥如鋪雪。',12,'全唐诗/poet.song.28000.json','["但見古河東，蕎麥如鋪雪。"]'),
('0eb0820f-cb35-43e5-bc75-cdb32a4f2445','句  其一六','劉敞','宋','宋诗','song-poetry','','[]','廉吏今無劌，仁人古戒磏。',12,'全唐诗/poet.song.28000.json','["廉吏今無劌，仁人古戒磏。"]'),
('8f67a36a-1cc7-4e50-b4c3-33409d98f7be','句  其一七','劉敞','宋','宋诗','song-poetry','','[]','世亂潁水濁，世治潁水清。',12,'全唐诗/poet.song.28000.json','["世亂潁水濁，世治潁水清。"]'),
('cf526ebc-71bd-44b7-a7a3-4841881af1fb','句  其一八','劉敞','宋','宋诗','song-poetry','','[]','說文黄葵常傾葉，向日不令照其根。',16,'全唐诗/poet.song.28000.json','["說文黄葵常傾葉，向日不令照其根。"]'),
('66d6aa6f-87ec-48c1-a2fe-148a1f292e6b','存目  其一','劉敞','宋','宋诗','song-poetry','','[]','詩題：晝寢首句：井逕從蕪漫。',14,'全唐诗/poet.song.28000.json','["詩題：晝寢首句：井逕從蕪漫。"]'),
('5e6aeda4-6475-4b5f-8d2c-bdfd7579f1df','存目  其二','劉敞','宋','宋诗','song-poetry','','[]','詩題：鴨脚首句：魏帝昧遠圖。',14,'全唐诗/poet.song.28000.json','["詩題：鴨脚首句：魏帝昧遠圖。"]'),
('b37fd480-c0d1-4c63-94b9-55243d498e17','皇帝冬至御大慶殿舉第一盞酒奏慶雲之曲','王珪','宋','宋诗','song-poetry','','[]','乾坤順夷，皇有嘉德。',40,'全唐诗/poet.song.28000.json','["乾坤順夷，皇有嘉德。", "爰施慶雲，承日五色。", "輪囷下垂，萬物皆飾。", "維天祚休，長被無極。"]'),
('1597f4dd-2b67-4658-8773-b474b0a27a26','皇帝冬至御大慶殿舉第二盞酒奏嘉禾之曲','王珪','宋','宋诗','song-poetry','','[]','太平之符，昭發衆瑞。',40,'全唐诗/poet.song.28000.json','["太平之符，昭發衆瑞。", "爰有嘉禾，異隴合穗。", "大田如雲，既穫既刈。", "野人愉愉，不亦有歲。"]'),
('168f96aa-cac6-44c9-8be5-2aae759e0390','白鷺亭','王珪','宋','宋诗','song-poetry','','[]','白鷺敞西軒，棟宇窮爽塏。',168,'全唐诗/poet.song.28000.json','["白鷺敞西軒，棟宇窮爽塏。", "千峰若聯環，翠色不可解。", "是時天宇曠，六幕無纖靄。", "金斗熨秋江，素練横衣帯。", "乾坤清且斂，氣象朝昏改。", "蘆花作雪風，飛舞來滄海。", "九霄汀鶴起，萬里檣烏快。", "月上三山頭，鳥没横塘外。", "蒼茫洲渚寒，銀錯星斗大。", "開樽屏絲竹，披襟向簫籟。", "余生本江湖，偃蹇欣作會。", "清興雖自發，苦嗜亦吾累。", "魚龍憑夜濤，四面忽滂湃。", "安得犀燈然，煌煌發水怪。"]'),
('b0cef49b-1069-4dc8-b438-15ecbecf6947','和景彝誚扶出者','王珪','宋','宋诗','song-poetry','','[]','天子重論秀，待之以公卿。',96,'全唐诗/poet.song.28000.json','["天子重論秀，待之以公卿。", "志士抱奇節，猶或塲屋輕。", "學能苦自琢，詩書腹縱横。", "胡爲懷袖間，挾冊角羣生。", "訶卒闚其旁，執衣來叩楹。", "狂狙就新縛，跳突哀且鳴。", "豈不念寒孤，顧有素令明。", "利祿非可苟，辱甚捨弗烹。"]'),
('6601df7b-33c1-4ae8-9a4b-aa01c5df4b62','來燕堂聯句','王珪','宋','宋诗','song-poetry','','[]','賢侯謝郡歸，從遊樂吾黨。',240,'全唐诗/poet.song.28000.json','["賢侯謝郡歸，從遊樂吾黨。", "林泉富餘地，卜築疏陳莽。", "是時春正中，來燕音下上。", "若賀大厦成，喜留衆賓賞。", "得名因笑談，揮墨粲題榜。", "所夸賢豪盛，豈止池榭廣。", "人心樂且閒，鳥意頡而頏。", "吟罇敞花軒，醉枕酣風幌。", "輕雲薄藻棟，初日麗珠網。", "紅袂生暗香，清絃泛餘響。", "林深隱飛蓋，岸曲遲去槳。", "波光欄檻明，竹氣衣巾爽。", "虛客涼樾入，影與文漣蕩。", "晨飈轉綠蕙，夕雨滋膏壤。", "嘉辰喜盍朋，命駕期屢往。", "觴詠陶淑真，世俗豈吾倣。", "得以爲勝遊，蕭然散煩想。", "公子固好士，世德復可像。", "今此大基構，不圖專奉養。", "美哉風流存，來葉足師仰。"]'),
('3a42145a-7130-43c9-98ab-bb0b5febf2ab','樓上述懷','王珪','宋','宋诗','song-poetry','','[]','空樓百尺江之滸，醉上凭軒懷故土。',64,'全唐诗/poet.song.28000.json','["空樓百尺江之滸，醉上凭軒懷故土。", "數鴻秋入衡陽雲，一帆暮過瀟湘雨。", "庾客傷心欲斷絃，文通别淚空横柱。", "舊山幾畝林泉鄉，安得歸兮事農圃。"]'),
('49510999-c620-417d-850f-823cc057b7a7','和永叔思白兔戲答公儀憶鶴雜言','王珪','宋','宋诗','song-poetry','','[]','兔自明月窟中出，鶴從羣玉峰頭下。',278,'全唐诗/poet.song.28000.json','["兔自明月窟中出，鶴從羣玉峰頭下。", "人間俗眼未嘗窺，已爲兩家藏以詫。", "玉堂詞人本仙材，光芒偶落銀河罅。", "謫向埃塵五十春，所趣無一不瀟灑。", "爲愛霜蹄特皎潔，貯以雕籠綠櫺亞。", "有時驚躑歘若犇，丹眸眩轉雙珠射。", "靈昌太守新歸來，惜將清唳寄京舍。", "玉繩低闕春露寒，常恐陰林惡聲嚇。", "傳宣忽出右銀臺，詔急許馳天廐馬。", "卻辭丹陛鎖南宫，兔鶴欲攜俱不暇。", "是時雪後簾幕明，燈火冷落入清夜。", "兩翁相顧悅有思，便索粉牋揮筆寫。", "有客月底吟影動，猝繼新章亦奇雅。", "大都吟苦不無牽，遂約東家看婭姹。", "醉翁良憤詆高懷，却揮醉墨幾欲罵。", "我聞此語初未平，隨手欲和思殊寡。", "玉山滄海莫放翻然歸，纖腰綠鬢何妨爲君倒金斝。"]'),
('c923c718-720e-4017-a3a1-f72046c436b9','和梅聖俞感李花','王珪','宋','宋诗','song-poetry','','[]','朝摘桃花紅破蕚，暮摘李花繁滿枝。',64,'全唐诗/poet.song.28000.json','["朝摘桃花紅破蕚，暮摘李花繁滿枝。", "客心浩蕩東風急，把酒看春能幾時。", "舞衣未放哀絃闋，鷤䳏欲鳴花影絕。", "將軍白首不功名，覇陵千古流青血。"]'),
('fe671827-8c78-481e-bb1a-7d2ea4cc30bb','和聖俞莫登樓','王珪','宋','宋诗','song-poetry','','[]','莫登樓，樓外華燈人競遊。',156,'全唐诗/poet.song.28000.json','["莫登樓，樓外華燈人競遊。", "翠枝威威六素虯，鳴梢一聲從天頭。", "金爐烟開雉尾收，正見月射雙瓊鈎。", "半峰飛泉落驚漚，嘘呵紫霧魚龍浮。", "絃清管高脆欲流，霜寒雛鳳丹山愁。", "臺上美人春風柔，舞腰回急寶釵投。", "禁街特勑香車留，簾疏的皪排星眸。", "畫省宵閒空翠幬，束如窮兔離新罘。", "況驚白髪心悠悠，安復繁華事輕裘。", "寄言俠少誰爲儔，爛醉玉樓歌始休。"]'),
('e15050cf-6571-45ac-baf5-b891bdf02c08','和敬叔弟七月十二夜胡伯恭園池對月即事之作','王珪','宋','宋诗','song-poetry','','[]','小庭追凉月生衣，紅蕖靜對丹桂枝。',64,'全唐诗/poet.song.28000.json','["小庭追凉月生衣，紅蕖靜對丹桂枝。", "凌波亭亭仙佩冷，弄香嫋嫋香風吹。", "百憂身世得一笑，二妙風流此一時。", "闌干獨夜發深省，憑詩寄與心相知。"]'),
('86b03281-c43c-48ba-a249-9c09c434741a','郊祀慶成詩  其一','王珪','宋','宋诗','song-poetry','','[]','國重天之報，神歆德所存。',120,'全唐诗/poet.song.28000.json','["國重天之報，神歆德所存。", "孝須三后配，禮莫一郊尊。", "翠羽來千仗，鳴鐃下九閽。", "服維周冕盛，樂自舜韶温。", "未酌羣靈降，先祠萬玉犇。", "黄流凝夕祼，紫焰亘霄燔。", "星拱低宸幄，雲回護帝轅。", "祥輝新日月，佳氣浹乾坤。", "紹古歸鴻鑠，含生濯至恩。", "欽惟齋格至，仰福在元元。"]'),
('3e22bace-7768-4fbf-a4f0-a2b5278be239','郊祀慶成詩  其二','王珪','宋','宋诗','song-poetry','','[]','有宋乘炎運，于今邁百年。',168,'全唐诗/poet.song.28000.json','["有宋乘炎運，于今邁百年。", "祖功雖不易，子聖自能傳。", "寶曆迎長至，神丘放大圜。", "靈宫千福降，清廟一誠專。", "翠仗鉤陳下，青城斗極邊。", "側班回衆弁，虛次待高煙。", "晦霧初宵斷，晴雲未曉鮮。", "天形何磊落，帝步亦周旋。", "麗澤沾魚鳥，休歌被筦絃。", "歡聲兼嶽動，和氣與春連。", "在昔開鴻業，斯民入化甄。", "監危常栗栗，受祉更乾乾。", "此日膺神筴，孤臣老禁筵。", "願將成命頌，獨奏邇英前。"]'),
('5b414eaf-944f-4f68-8fe9-9da2a3cebfbe','大饗明堂慶成詩','王珪','宋','宋诗','song-poetry','','[]','皇祐更秋律，明堂奉帝禋。',120,'全唐诗/poet.song.28000.json','["皇祐更秋律，明堂奉帝禋。", "粢盛雖薦德，霜露本懷親。", "於赫朝三后，無文秩百神。", "九筵交玉幣，重屋近星辰。", "邃幄留飈御，清壇墮月津。", "衣冠漢儀舊，金石舜韶新。", "受胙開宣室，鳴鐘降紫宸。", "羣陰先伏旦，協氣斗回春。", "靈貺叢千祝，豐恩滲四垠。", "慚非老辭筆，徒學頌堯人。"]'),
('7a3ca2c7-03a2-422f-8171-209a25994dc4','依韻恭和聖製俯同太師文彦博玉津園賜宴席上述懷','王珪','宋','宋诗','song-poetry','','[]','上苑張瑤席，春風萬象新。',72,'全唐诗/poet.song.28000.json','["上苑張瑤席，春風萬象新。", "誰知掛冠客，曾是釣璜人。", "感遇歸真主，勳勞念老臣。", "曲成雙鳯舞，酒入百花醇。", "日月恩華滿，朝廷喜氣均。", "天章照黄髪，異數極君仁。"]'),
('6456c1a5-23f0-4796-afe3-a722ac9b4488','從駕至開寶寺慶壽崇因閣依韻和吳相公','王珪','宋','宋诗','song-poetry','','[]','崇因開寶構，金碧畫相輝。',96,'全唐诗/poet.song.28000.json','["崇因開寶構，金碧畫相輝。", "禁蹕隨曦馭，曾城轉斗機。", "梵音獅子吼，妙相鴿王歸。", "洛水浮神篆，天花滿御衣。", "塔疑從地湧，棟儗入雲飛。", "上行乘今果，羣迷悟昨非。", "慧珠常自照，法雨徧成霏。", "但起真如念，梯梁即可幾。"]'),
('9440f06c-66a4-44aa-a560-8e15fe942891','擬試置章御座二首  其一','王珪','宋','宋诗','song-poetry','','[]','睿聽來嘉論，憂勤政事昌。',72,'全唐诗/poet.song.28000.json','["睿聽來嘉論，憂勤政事昌。", "顒顒瞻帝座，諤諤置臣章。", "語切青規上，文留黼扆傍。", "受言初拜禹，罪己忽興湯。", "進牘須盈几，垂衣豈下堂。", "只應千載治，危諫屬忠良。"]'),
('ea52f06f-e6f1-4f1b-a9b7-ec8e2afbf88a','擬試置章御座二首  其二','王珪','宋','宋诗','song-poetry','','[]','君心圖治切，座置直臣章。',72,'全唐诗/poet.song.28000.json','["君心圖治切，座置直臣章。", "密奏留中扆，虛懷拱峻廊。", "聰明開二帝，道德勸三王。", "温室焚初藁，丹帷緝舊囊。", "呈書勞夜覽，造膝被天光。", "欲識憂民意，忠規不可忘。"]'),
('a0d33881-7d14-4640-a187-3a2cdcf665fc','采藻爲旒','王珪','宋','宋诗','song-poetry','','[]','端扆垂君治，顒昂十二旒。',72,'全唐诗/poet.song.28000.json','["端扆垂君治，顒昂十二旒。", "藻文兼組爛，玉氣若虹浮。", "體重宸居邃，仁深帝視收。", "珠光延外燭，星采會中稠。", "法服雖周盛，巖廊自舜遊。", "無爲格天下，涵德永孚休。"]'),
('e87e165d-9a4d-4ab2-863c-9fba702dd21a','喜定號','王珪','宋','宋诗','song-poetry','','[]','憶昨懷君詔，章臺聽暮鐘。',72,'全唐诗/poet.song.28000.json','["憶昨懷君詔，章臺聽暮鐘。", "人從太微下，書自道山共。", "彩鳯看飛筆，長虹見吐胸。", "冤家成行對，側理入腰封。", "海闊珠難採，山輝玉易攻。", "别吟平樂賦，高第唱西廱。"]'),
('3b5e99ca-cde2-497e-8e84-da1ac6c21b99','題瑞芝圖','王珪','宋','宋诗','song-poetry','','[]','樂國芝呈瑞，賢侯貳郡時。',96,'全唐诗/poet.song.28000.json','["樂國芝呈瑞，賢侯貳郡時。", "甘棠方蔽芾，仙草亦葳蕤。", "異種傳三秀，靈華粲九枝。", "幽陰吐光怪，朽腐化神奇。", "美政邦人頌，嘉祥聖主知。", "特書輝史策，寵錫下天墀。", "治行能如此，公台到匪遲。", "誰爲燕許手，灑筆播聲詩。"]'),
('29a381be-9e9f-4473-9c54-3cea0be50196','依韻和王宣徽奉安中太乙神像','王珪','宋','宋诗','song-poetry','','[]','太乙真庭結寶壇，中涵元象本無言。',128,'全唐诗/poet.song.28000.json','["太乙真庭結寶壇，中涵元象本無言。", "三山波湧樓臺近，北極星環劍佩尊。", "歲入飛宫初在丑，神移列馭直從坤。", "妖氛自逐靈旂捲，瑞穀常登御廪蕃。", "曉日破紅浮鬭栱，夕雲凝紫護周垣。", "龍隨御筆棲碑首，鶴带仙書語洞門。", "天馬應歌來仗衞，嶽祗聫職聽朝昏。", "傳聞詞客新吟苦，玉案纔承上帝恩。"]'),
('017670dc-1ca1-44cc-adc9-cdd139885911','竹','王珪','宋','宋诗','song-poetry','','[]','天地得正氣，四時無易心。',48,'全唐诗/poet.song.28000.json','["天地得正氣，四時無易心。", "生來本孤節，高處獨千尋。", "月影龍蛇動，風枝簫籟吟。", "如何楓與柳，亦擬傍清陰。"]'),
('af57278d-e7ad-46bc-9204-5efdfe8db747','荷葉','王珪','宋','宋诗','song-poetry','','[]','柄密藏溪路，香清盪客襟。',48,'全唐诗/poet.song.28000.json','["柄密藏溪路，香清盪客襟。", "碧筒聊助飲，紫槖自供吟。", "魚戯涼波動，龜巢夕霧深。", "横塘雙槳急，菱唱有餘音。"]'),
('255ab9a6-dd78-45cc-8349-1cb228be553f','梅花','王珪','宋','宋诗','song-poetry','','[]','冷香疑到骨，瓊豔幾堪餐。',48,'全唐诗/poet.song.28000.json','["冷香疑到骨，瓊豔幾堪餐。", "半醉臨風折，清吟拂曉觀。", "贈春無限意，和雪不勝寒。", "桃李有慚色，枯枝試並欄。"]'),
('bb6df5ba-292f-4879-9205-e6b4eed43e0e','秋風','王珪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','獵桂來鍾嶺，翍椒度漢宫。',48,'全唐诗/poet.song.28000.json','["獵桂來鍾嶺，翍椒度漢宫。", "雲飛汾水闊，葉下洞庭空。", "海國檣帆壯，邊城鼓角雄。", "誰知洛陽客，歸意在江東。"]'),
('1c8fc42e-33a2-4914-834d-43ec67f401fd','喜雪','王珪','宋','宋诗','song-poetry','','[]','大野重陰合，危樓遠望迷。',48,'全唐诗/poet.song.28000.json','["大野重陰合，危樓遠望迷。", "風兼萬籟響，天與四溟低。", "病樹先春發，驚烏未曉啼。", "好同伊水客，香阜訪靈棲。"]'),
('2016a5bc-a117-4301-8717-470c8901b0c3','雪晴','王珪','宋','宋诗','song-poetry','','[]','溟渤蕩無垠，東嵎掛日輪。',48,'全唐诗/poet.song.28000.json','["溟渤蕩無垠，東嵎掛日輪。", "風雲始迴雨，天地不飛塵。", "氣動千峰翠，光浮萬瓦鱗。", "南亭一駐馬，十里望青春。"]'),
('0516fca4-7949-42db-a086-a991a2c27f4d','林亭','王珪','宋','宋诗','song-poetry','','[]','地迥林泉好，乘閒會勝游。',48,'全唐诗/poet.song.28000.json','["地迥林泉好，乘閒會勝游。", "深沉烟色聚，瀟灑雨聲收。", "貧過揚雄宅，狂思范蠡舟。", "寄言賞心友，巾褐此經秋。"]'),
('cfa57c63-8d75-4519-b697-6ce54a22c6d0','郊外','王珪','宋','宋诗','song-poetry','','[]','策馬陟平原，天空蕩楚氛。',48,'全唐诗/poet.song.28000.json','["策馬陟平原，天空蕩楚氛。", "秋聲無限葉，暮色幾重雲。", "草遠烟痕闊，山迴鳥道分。", "行行吟未已，歸路日西曛。"]'),
('c592d737-00c4-4a76-a876-0bd71203e9d3','即事','王珪','宋','宋诗','song-poetry','','[]','雲日散朝陰，清江更一臨。',48,'全唐诗/poet.song.28000.json','["雲日散朝陰，清江更一臨。", "北堂無草積，南浦有波深。", "春意饒芳樹，晴光動翠岑。", "自慚機亦淺，勞起海鷗心。"]'),
('62734f7a-25d6-4e84-a6a0-65b4d60a2d49','有感','王珪','宋','宋诗','song-poetry','','[]','聞笛更懷舊，望鴻難寄音。',48,'全唐诗/poet.song.28000.json','["聞笛更懷舊，望鴻難寄音。", "西風行客淚，明月故人心。", "離恨江波闊，歸期歲景深。", "何時紫溪隱，尊酒起狂吟。"]'),
('677c304d-e5bc-4b7d-ae05-62d46f5541c4','題招提院静照堂','王珪','宋','宋诗','song-poetry','','[]','身雖居城邑，趣不落人間。',48,'全唐诗/poet.song.28000.json','["身雖居城邑，趣不落人間。", "門外塵埃滿，庭中日月閒。", "潮隨朝梵響，雨入定衣斑。", "幾欲攜笻去，松陰一叩關。"]'),
('e56e8833-558f-46aa-83b7-2c7934cb4465','書隱者壁','王珪','宋','宋诗','song-poetry','','[]','客路森如棘，巖棲静掩關。',48,'全唐诗/poet.song.28000.json','["客路森如棘，巖棲静掩關。", "陶巾春漬酒，謝屐晚回山。", "醉夢雷霆息，棋聲日月閒。", "我慚攖世網，暫此一怡顔。"]'),
('c0260037-4901-4317-b2f4-6a23d528cf20','聞邵興宗拜命','王珪','宋','宋诗','song-poetry','','[]','訪政鳴堯鼓，旌賢走漢輪。',48,'全唐诗/poet.song.28000.json','["訪政鳴堯鼓，旌賢走漢輪。", "帝方驚主父，人已薦平津。", "筆落三千健，恩頒尺一新。", "歸來前席問，榮路邇嚴宸。"]'),
('4b5927ad-9535-4284-b895-4decede50c44','夏日登望海亭','王珪','宋','宋诗','song-poetry','','[]','藻棟臨流啟，涼飈蕩暑迴。',48,'全唐诗/poet.song.28000.json','["藻棟臨流啟，涼飈蕩暑迴。", "清如游玉宇，快若在蘭臺。", "海葉吟中下，番航望次來。", "披襟殊未已，雲外月弦開。"]'),
('12d14e2c-b0bf-4a1d-b2b5-d76c389b8d59','金陵','王珪','宋','宋诗','song-poetry','','[]','賞心亭下路，平昔艤歸艎。',48,'全唐诗/poet.song.28000.json','["賞心亭下路，平昔艤歸艎。", "游子去何許，綠蕪春自芳。", "城根侵海斷，日脚射雲長。", "往事不堪問，東風故壘荒。"]'),
('16101e40-9b59-4f75-a811-0e44d4857019','金陵會月','王珪','宋','宋诗','song-poetry','','[]','疏颯水風起，此宵何太清。',48,'全唐诗/poet.song.28000.json','["疏颯水風起，此宵何太清。", "危樓人未下，獨樹鳥頻驚。", "寒漏三更急，秋江萬里横。", "凄然六朝恨，依舊照空城。"]'),
('38e9db17-492e-4b6b-a364-0f27af2014e8','富谷館','王珪','宋','宋诗','song-poetry','','[]','萬雀噪山館，重來一叩扉。',48,'全唐诗/poet.song.28000.json','["萬雀噪山館，重來一叩扉。", "去年寒夢在，今日遠書違。", "殘雪留春槖，疏星掛曉衣。", "帝鄉不可望，心與白雲飛。"]'),
('9f474659-76ad-4fe8-9371-624d0e3f0f2f','發會同館','王珪','宋','宋诗','song-poetry','','[]','一持天子節，兹喜去龍庭。',48,'全唐诗/poet.song.28000.json','["一持天子節，兹喜去龍庭。", "大漠夜猶白，寒山春不青。", "峰多常蔽日，地絕欲回星。", "同類惟所適，鳴鑣毋暫停。"]'),
('e8a12b3f-229d-47f5-b42c-ee72e39d6980','和人聞雁二首  其一','王珪','宋','宋诗','song-poetry','','[]','岑寂夜將半，一聲來枕前。',48,'全唐诗/poet.song.28000.json','["岑寂夜將半，一聲來枕前。", "無風起羣籟，有月在中天。", "行子夢初斷，故鄉書未傳。", "不須聞别鶴，冷涕已潸然。"]'),
('f0c240b3-4e07-47df-90c5-6de54584a249','和人聞雁二首  其二','王珪','宋','宋诗','song-poetry','','[]','塞長霜草白，天闊夜雲愁。',48,'全唐诗/poet.song.28000.json','["塞長霜草白，天闊夜雲愁。", "影過空江月，聲來别枕秋。", "鄉音何處託，客恨幾時休。", "況有冥飛志，無爲弋者求。"]'),
('4cf4b59c-055b-4a45-8112-dae0fda7e27b','和聖俞春雪','王珪','宋','宋诗','song-poetry','','[]','二月猶逢雪，春寒一倍加。',48,'全唐诗/poet.song.28000.json','["二月猶逢雪，春寒一倍加。", "雲重應阻雁，風横祇愁花。", "碧水離思斷，瓊樓醉倚斜。", "誰知下帷苦，未曉已聞鴉。"]'),
('8be08d40-7392-4617-924e-5229d6c19368','依韻恭和聖製龍圖天章閣觀三聖御書','王珪','宋','宋诗','song-poetry','','[]','半夜傳君召，西清閲帝文。',48,'全唐诗/poet.song.28000.json','["半夜傳君召，西清閲帝文。", "筆回丹穴鳳，歌起沛中雲。", "御幄金虯轉，仙墀羽仗分。", "君王自天縱，況復睿心勤。"]'),
('218edf83-9609-44cc-938c-2a93912e2473','依韻和吳相公史院開局','王珪','宋','宋诗','song-poetry','','[]','曉下金門路，君筵聽召餘。',48,'全唐诗/poet.song.28000.json','["曉下金門路，君筵聽召餘。", "簪纓三壽客，筆削兩朝書。", "身老誰逢此，恩深盡醉歟。", "傳聞訪遺事，應走史臣車。"]'),
('59b5f299-dcd4-4bed-a917-e1d91a4e310a','依韻和王原叔內翰禁直有懷','王珪','宋','宋诗','song-poetry','','[]','暮鑰嚴温省，宵鈴靜浴堂。',48,'全唐诗/poet.song.28000.json','["暮鑰嚴温省，宵鈴靜浴堂。", "銀花無奈冷，瑤草又還芳。", "夢久聞仙吹，班清犯曉霜。", "帝閽何所叩，一炷祝堯香。"]'),
('64669486-b50d-4159-a3fc-900707ce8c2f','依韻和王宣徽春雨','王珪','宋','宋诗','song-poetry','','[]','春入東郊雨，油然協氣通。',48,'全唐诗/poet.song.28000.json','["春入東郊雨，油然協氣通。", "曉澌猶未破，歲事已知豐。", "輦鳳翔仙霧，臺烏轉瑞風。", "野農徒鼓舞，何以謝天功。"]'),
('529c819e-af0e-4caf-9273-72806ef2859f','和王景彝中丞衰病','王珪','宋','宋诗','song-poetry','','[]','東風吹畫省，衰病若爲情。',48,'全唐诗/poet.song.28000.json','["東風吹畫省，衰病若爲情。", "自惜春將過，相逢老已驚。", "夜愁聊把酒，早夢忽聞鸎。", "猶喜年來事，門前桃李生。"]'),
('4a9089cd-e18e-401b-98e4-6a91c95beb1c','送滕舜敷','王珪','宋','宋诗','song-poetry','','[]','七閩雖遠地，王事有程期。',48,'全唐诗/poet.song.28000.json','["七閩雖遠地，王事有程期。", "已試文無害，定知才不覊。", "仙山觀日處，雲海落潮時。", "會府多休暇，新詩倘見貽。"]'),
('56ba7dc0-ee5b-4a68-961f-27c4444081d2','送史寺丞赴真州六合縣','王珪','宋','宋诗','song-poetry','','[]','南國江山好，仍聞聚六峰。',48,'全唐诗/poet.song.28000.json','["南國江山好，仍聞聚六峰。", "歸心急春浪，别夢悵晨鐘。", "手澤存遺愛，民歌接舊封。", "涼秋鼓予楫，文酒待相從。"]'),
('e5e981ae-b088-438b-8ac3-e0408a980ff4','送山人程惟象東歸','王珪','宋','宋诗','song-poetry','','[]','君來客京洛，奇術世所聞。',48,'全唐诗/poet.song.28000.json','["君來客京洛，奇術世所聞。", "人事固倚伏，物情徒糾紛。", "衣霑九門雨，夢繞故山雲。", "飲罷忽東去，浩歌秋日曛。"]'),
('fe8d520e-ead8-4ae9-8c3c-e1d4a0edc914','送人南歸','王珪','宋','宋诗','song-poetry','','[]','自得歸休請，勞生事已平。',48,'全唐诗/poet.song.28000.json','["自得歸休請，勞生事已平。", "幾年懷故隱，此日悟浮榮。", "車騎少塵迹，溪山多去情。", "所安清白望，真可激時英。"]'),
('4f672ae7-0d22-4eab-907d-032cf430074b','送僧歸吳中','王珪','宋','宋诗','song-poetry','','[]','閒心輕出世，遠念起游方。',48,'全唐诗/poet.song.28000.json','["閒心輕出世，遠念起游方。", "潄月抛茶井，眠雲夢草堂。", "歸程指山色，去影背湖光。", "欲問重來日，孤雲未可量。"]'),
('43757e8f-98fd-45c3-a85f-efffdceb1b08','仁宗皇帝挽詞五首  其一','王珪','宋','宋诗','song-poetry','','[]','忽覺宮車晚，乘雲御帝鄉。',48,'全唐诗/poet.song.28000.json','["忽覺宮車晚，乘雲御帝鄉。", "空餘羣玉殿，不奏萬年觴。", "白髮孤臣淚，黄塵九陌荒。", "返虞歌未斷，陵柏已蒼蒼。"]'),
('399117b8-7959-41d5-8d21-9619893f3179','仁宗皇帝挽詞五首  其二','王珪','宋','宋诗','song-poetry','','[]','西葬青嵩道，千秋豈復晨。',48,'全唐诗/poet.song.28000.json','["西葬青嵩道，千秋豈復晨。", "皇圖先與子，廟號獨稱仁。", "二帝衣裳舊，三王禮樂新。", "茂陵書奏晚，不及議車巡。"]'),
('d995c961-f489-460f-b496-323002be4136','仁宗皇帝挽詞五首  其三','王珪','宋','宋诗','song-poetry','','[]','七月欑宮曉，愁看動素旂。',48,'全唐诗/poet.song.28000.json','["七月欑宮曉，愁看動素旂。", "乾坤清淚滿，車駕昔遊非。", "落月低黄繖，流塵上玉衣。", "蒼梧何日返，耘鳥傍陵飛。"]'),
('fc1f49f5-282b-480a-9af7-0561db0ed43b','仁宗皇帝挽詞五首  其四','王珪','宋','宋诗','song-poetry','','[]','平昔傳清蹕，金輿下紫宸。',48,'全唐诗/poet.song.28000.json','["平昔傳清蹕，金輿下紫宸。", "忽從滄海宴，遂隔屬車塵。", "劍落橋山夜，衣留漢廟春。", "東廂朝聖子，絕慟見羣臣。"]'),
('85f92678-a1b4-46e4-a324-add9c9c43e14','仁宗皇帝挽詞五首  其五','王珪','宋','宋诗','song-poetry','','[]','憶昨頒遺詔，猶聞玉几香。',48,'全唐诗/poet.song.28000.json','["憶昨頒遺詔，猶聞玉几香。", "鼎湖龍已去，汾水雁空翔。", "北極星辰暗，三山日月長。", "宸遊在何處，尚想赭袍光。"]'),
('7f1b4124-ba5f-475a-a114-b106b978a315','英宗皇帝挽詞五首  其一','王珪','宋','宋诗','song-poetry','','[]','上主提皇器，真人獻赤符。',48,'全唐诗/poet.song.28000.json','["上主提皇器，真人獻赤符。", "夜書勞玉几，夕駕促金鳬。", "洛自三陵咽，嵩猶萬歲呼。", "誰言虞帝壽，終不返蒼梧。"]'),
('4f7464fa-2dec-4637-be6f-a29636df5c63','英宗皇帝挽詞五首  其二','王珪','宋','宋诗','song-poetry','','[]','一夜催仙仗，悲聲到九宸。',48,'全唐诗/poet.song.28000.json','["一夜催仙仗，悲聲到九宸。", "玉階猶報曉，金殿不知春。", "碧海無來使，青宮有舊臣。", "華封曾未幸，應誤祝堯人。"]'),
('c410de40-3895-402c-ac8c-9831699afaec','英宗皇帝挽詞五首  其三','王珪','宋','宋诗','song-poetry','','[]','欲問俞跗術，秦亡世少傳。',48,'全唐诗/poet.song.28000.json','["欲問俞跗術，秦亡世少傳。", "玉書纔命子，金鼎已成仙。", "華渚星猶爛，昭陵柏未圓。", "空餘罪己詔，不似禹湯年。"]'),
('7752741e-a9f6-4baf-8553-d54c0c206390','英宗皇帝挽詞五首  其四','王珪','宋','宋诗','song-poetry','','[]','五載臨朝淺，羣生受福多。',48,'全唐诗/poet.song.28000.json','["五載臨朝淺，羣生受福多。", "徽名方鏤玉，顧命忽陳戈。", "風露翻金鐸，塵埃滿畫鼉。", "從茲天慶節，萬壽復誰歌。"]'),
('b7c40961-6ea3-4308-af1b-e8c598437e80','英宗皇帝挽詞五首  其五','王珪','宋','宋诗','song-poetry','','[]','憶昔承君召，春風候禁門。',48,'全唐诗/poet.song.28000.json','["憶昔承君召，春風候禁門。", "曾陪蕊珠殿，獨賜紫花墩。", "遼水千年隔，鈞天一夢存。", "龍髯攀不得，無路可酬恩。"]'),
('81f0544a-c656-443c-9b43-44571a482442','贈司空侍中晏元獻公挽詞二首  其一','王珪','宋','宋诗','song-poetry','','[]','震邸陪經席，辰階擁化鈞。',48,'全唐诗/poet.song.28000.json','["震邸陪經席，辰階擁化鈞。", "高謨帷幄舊，嘉績鼎彝新。", "露濕銘旌曉，塵凝燕榭春。", "許郊民愛厚，猶憶相車茵。"]'),
('ed89d8d1-55b5-4c27-9a9b-bff9812f107f','贈司空侍中晏元獻公挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','富貴誰爲並，文章世所稀。',48,'全唐诗/poet.song.28000.json','["富貴誰爲並，文章世所稀。", "勳名丹史在，體貌九天違。", "嵩極朝催峻，台躔夜掩輝。", "空餘舊遊客，淚向寢門揮。"]'),
('d812b24d-5573-41b0-8764-d6bd58b0cb65','贈太子太傅李康靖公挽詞二首  其一','王珪','宋','宋诗','song-poetry','','[]','議政西清貴，辭榮北第開。',48,'全唐诗/poet.song.28000.json','["議政西清貴，辭榮北第開。", "魯岡天與壽，荀里世多才。", "象吿中台坼，峰驚半嶽摧。", "秋風嵩少路，簫鼓有餘哀。"]'),
('15170bf9-5f9e-4e1d-9eb5-761503691b45','贈太子太傅李康靖公挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','陪幄方圖政，安車遂告年。',48,'全唐诗/poet.song.28000.json','["陪幄方圖政，安車遂告年。", "帝求惇史善，人嘆大夫賢。", "故館西州路，佳城京兆阡。", "惟應舊遊客，墮淚向碑前。"]'),
('709cf1d2-a523-4cdd-bf87-b53fd459e31e','贈禮部尚書唐質肅公挽詞二首  其一','王珪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','偶歇延英對，如何遽不來。',48,'全唐诗/poet.song.28000.json','["偶歇延英對，如何遽不來。", "卹恩天子厚，遺直世人哀。", "路轉侵龍耳，星沉近斗魁。", "送車知幾乘，莫賦泰山頹。"]'),
('ea554f50-faed-4adb-a399-fdb1d5801295','贈禮部尚書唐質肅公挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','昔在仁朝日，孤忠獨犯顔。',48,'全唐诗/poet.song.28000.json','["昔在仁朝日，孤忠獨犯顔。", "一身寧自顧，萬里偶生還。", "却度黄梅嶺，重趨玉笋班。", "不知君檻折，千古更誰攀。"]'),
('3240b5fe-96aa-4887-867e-3741717f5145','贈太尉鄭文肅公挽詞二首  其一','王珪','宋','宋诗','song-poetry','','[]','一擐黄金甲，征西戰馬驕。',48,'全唐诗/poet.song.28000.json','["一擐黄金甲，征西戰馬驕。", "十年邊算盡，今日旅魂招。", "落月孤營掩，酸風去路遙。", "平生忠烈在，史筆冠清朝。"]'),
('df1a9b65-90ee-4d21-84ea-61ca4b2d79f0','贈太尉鄭文肅公挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','星墜將軍府，邊山萬木腓。',48,'全唐诗/poet.song.28000.json','["星墜將軍府，邊山萬木腓。", "誰言夜舟固，那復玉關歸。", "旌旆低寒色，簫笳慘夕霏。", "所嗟恩館淚，不到九泉揮。"]'),
('2c136f7f-f8b0-4ae4-b49d-40ecce42d979','挽貢南漪三首  其一','王珪','宋','宋诗','song-poetry','','[]','齒德人皆仰，詩書老更耽。',48,'全唐诗/poet.song.28000.json','["齒德人皆仰，詩書老更耽。", "福兼鴻範五，瑞集鳳雛三。", "歲月供陶寫，江湖入笑談。", "流芳鍾四葉，蘭玉儼相參。"]'),
('6ed5cde4-0cf5-4b0d-a10b-4069dda8090c','挽貢南漪三首  其二','王珪','宋','宋诗','song-poetry','','[]','燕居宣聖像，侑坐祖黎公。',48,'全唐诗/poet.song.28000.json','["燕居宣聖像，侑坐祖黎公。", "矜佩一朝集，絃歌九族同。", "夜窗書案雪，春服舞雩風。", "長使南湖學，千秋紀此翁。"]'),
('ec71784d-3f92-464a-bbdc-7688e9918b44','挽貢南漪三首  其三','王珪','宋','宋诗','song-poetry','','[]','秀野春如綺，平湖水拍天。',48,'全唐诗/poet.song.28000.json','["秀野春如綺，平湖水拍天。", "商詩凉月夜，把酒狎鷗邊。", "秋柏已成實，寒花誰爲妍。", "傷心耆舊盡，何用慰華顛。"]'),
('9c901a13-7197-48aa-ba23-60fc5630c5ac','挽董瀾溪二首  其一','王珪','宋','宋诗','song-poetry','','[]','六館知名久，雙溪避地来。',48,'全唐诗/poet.song.28000.json','["六館知名久，雙溪避地来。", "交新如舊識，世短惜長才。", "悵望中年别，飛騰暮景催。", "蟇陵他日淚，不獨故人哀。"]'),
('1c18d7f7-4eb1-4f6e-b667-fc3e665b5797','挽董瀾溪二首  其二','王珪','宋','宋诗','song-poetry','','[]','嗜學嘗忘味，說詩堪解頤。',48,'全唐诗/poet.song.28000.json','["嗜學嘗忘味，說詩堪解頤。", "竹林雖晚會，濠上獨深知。", "蘭畹無留馥，鳳巢空舊枝。", "停雲正愁望，横笛未休吹。"]'),
('dd20733e-7990-4746-abca-9c0a16cd5d62','挽胡信芳上舍二首  其一','王珪','宋','宋诗','song-poetry','','[]','濠上初相得，竹林曾共游。',48,'全唐诗/poet.song.28000.json','["濠上初相得，竹林曾共游。", "清文三峽水，爽氣九華秋。", "世已從新學，人誰與此流。", "遺芳端不朽，未信盖棺休。"]'),
('48c03562-20d0-42b2-af25-592040ef0637','挽胡信芳上舍二首  其二','王珪','宋','宋诗','song-poetry','','[]','清弋江村外，工山右縣邊。',48,'全唐诗/poet.song.28000.json','["清弋江村外，工山右縣邊。", "追遊曾結社，許與更忘年。", "郢斵無爲質，牙琴有絕絃。", "巾箱遺墨在，披閲一潸然。"]'),
('f64d9b1a-a7d7-4acb-b91f-d9b4a062b939','王公和學士挽詞','王珪','宋','宋诗','song-poetry','','[]','念昔携君手，同遊金馬門。',48,'全唐诗/poet.song.28000.json','["念昔携君手，同遊金馬門。", "流年一鳥過，白首幾人存。", "星掛朝衣濕，塵埋相印昏。", "西風原上淚，不得灑清樽。"]'),
('2c07f85f-1605-4b5a-87b9-8b270df63bb2','挽吳止水','王珪','宋','宋诗','song-poetry','','[]','人生五馬貴，不負壯心期。',48,'全唐诗/poet.song.28000.json','["人生五馬貴，不負壯心期。", "竟作青門隱，空吟畫戟詩。", "家聲江表重，心事歲寒知。", "未恨風流絕，雙珠似可兒。"]'),
('f9f01354-2ea8-47b6-9e1e-72e094e88b5d','挽潘昌朝','王珪','宋','宋诗','song-poetry','','[]','道德諸儒表，文章大雅人。',48,'全唐诗/poet.song.28000.json','["道德諸儒表，文章大雅人。", "杏園三月暮，花縣一回春。", "脱屣官情薄，轉頭時事新。", "猗蘭芳未沒，世業不沉淪。"]'),
('f47c099b-979e-4149-8321-36299119b3f0','挽吳太社','王珪','宋','宋诗','song-poetry','','[]','文獻家聲遠，簪纓世德昌。',48,'全唐诗/poet.song.28000.json','["文獻家聲遠，簪纓世德昌。", "幾篇青玉案，三佩白銀章。", "北苑新阡好，平原舊業荒。", "百年喬木在，留得耐風霜。"]'),
('819e90d8-b610-4423-aa8c-68ca68ca3b3f','挽錢公起','王珪','宋','宋诗','song-poetry','','[]','家學三餘足，詞塲一眼空。',48,'全唐诗/poet.song.28000.json','["家學三餘足，詞塲一眼空。", "摘髭連薦鶚，點額不成龍。", "酒上新墳土，香銷舊桂藂。", "絕憐揚執戟，臨老悔雕蟲。"]'),
('dfe30aaf-4231-46bc-a572-85885f549e86','挽董儒仲二首  其一','王珪','宋','宋诗','song-poetry','','[]','戰藝升環水，論詩得異聞。',48,'全唐诗/poet.song.28000.json','["戰藝升環水，論詩得異聞。", "窺園仍舊隱，下馬忽新墳。", "白社真投分，青燈憶離羣。", "有書無子讀，此事最憐君。"]'),
('c9a666ed-e4b0-4fbb-bfe9-d90a4d5e559e','挽董儒仲二首  其二','王珪','宋','宋诗','song-poetry','','[]','復憶同遊處，經春在武林。',48,'全唐诗/poet.song.28000.json','["復憶同遊處，經春在武林。", "湖光浮鷁净，山木坐猿深。", "事往唯詩在，悲來託夢尋。", "朋知零落盡，投老若爲心。"]'),
('125dba04-e8b2-459b-bbfd-8a1b9b37eded','濮安懿王夫人挽詞二首  其一','王珪','宋','宋诗','song-poetry','','[]','王族親無儗，皇圖慶有歸。',48,'全唐诗/poet.song.28000.json','["王族親無儗，皇圖慶有歸。", "神樞曾感電，仙寢忽藏衣。", "正祚尊仁統，新阡祔濮圍。", "朝廷恩稱義，孝奏豈天違。"]'),
('965da95b-e0bf-4ba7-ac3f-be520d77901a','濮安懿王夫人挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','曉望青嵩道，仙雲滿畫輪。',48,'全唐诗/poet.song.28000.json','["曉望青嵩道，仙雲滿畫輪。", "黄龍盤吉仗，翠鳳繞哀珉。", "千古徽音在，三川王氣新。", "寂寥餘故壠，瑤草又逢春。"]'),
('1c6e88ff-c508-47b8-be38-7e1fda8adad7','春日郊外','王珪','宋','宋诗','song-poetry','','[]','十里烟郊晝景和，春閒流水渌生波。',64,'全唐诗/poet.song.28000.json','["十里烟郊晝景和，春閒流水渌生波。", "樓前人意望無盡，柳上風光来最多。", "雨歇隴雲猶漭瀁，草薫村燕自經過。", "匆匆歸路迎殘照，尚得桑間駐玉珂。"]'),
('fd496173-cada-429a-9bdf-fe73f927cf3b','池亭月下獨坐','王珪','宋','宋诗','song-poetry','','[]','遊雲銷盡月當空，危坐西軒快水風。',64,'全唐诗/poet.song.28000.json','["遊雲銷盡月當空，危坐西軒快水風。", "往恨忽從中夜起，賞心難與故人同。", "鼠驚琴匣聞餘響，螢度蓮塘見亂紅。", "星薄漏稀猶不寐，寒聲通夕戰疏桐。"]'),
('c32c170e-7a9d-453f-ac85-eeb5d59a9ea2','月夜有寄','王珪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','莎階切切思寒螿，爽籟泠然露氣凉。',64,'全唐诗/poet.song.28000.json','["莎階切切思寒螿，爽籟泠然露氣凉。", "半夜雲高蟾噴暈，一秋風緊桂飄香。", "鳥驚危樹棲無定，人倚空樓望更長。", "遙憶洞庭南去客，葉翻波急駐歸艎。"]'),
('1f00bd56-b91f-4a1c-9f87-17072f4a3d03','雷塘晚歸','王珪','宋','宋诗','song-poetry','','[]','塘梢黯黯夕雲低，蒼莽荒原望四迷。',64,'全唐诗/poet.song.28000.json','["塘梢黯黯夕雲低，蒼莽荒原望四迷。", "海日光寒銜島樹，江潮聲暴壓城鼙。", "喬林風勁横鵰眼，淺草霜亁快馬蹄。", "戰血未收邊戍苦，玉龍誰爲一提携。"]'),
('fef65612-f8b5-42ba-8e2f-d5708f31aa2a','夜意','王珪','宋','宋诗','song-poetry','','[]','泬寥爽澈游氛收，淡河如掃凝不流。',64,'全唐诗/poet.song.28000.json','["泬寥爽澈游氛收，淡河如掃凝不流。", "影過遠水雁侵月，目斷故鄉人倚樓。", "黄葉半林霜送曉，悲笳一曲風横秋。", "江南幾載未歸客，燈寂帳寒心正愁。"]'),
('935f3131-f8e8-4d6f-b384-635941c9eaae','遊山寺','王珪','宋','宋诗','song-poetry','','[]','寒日征驂懶復回，經宵仍喜駐巖隈。',64,'全唐诗/poet.song.28000.json','["寒日征驂懶復回，經宵仍喜駐巖隈。", "徑盤幽迹遙知鹿，林逗清香定有梅。", "曉影痩猿窺澗溜，夜聲肥栗託爐灰。", "我心非動我非靜，白足禪僧無妄猜。"]'),
('b67cf25f-bb4f-4626-86dd-8f71ee30ce76','書四望亭','王珪','宋','宋诗','song-poetry','','[]','軒然獨到碧峰頭，萬里青霄入寸眸。',64,'全唐诗/poet.song.28000.json','["軒然獨到碧峰頭，萬里青霄入寸眸。", "日夜松聲如雨急，古今山色與雲浮。", "廢朝風物依依在，客路江波滚滚流。", "漢輦已沉江樹老，天涯寂寞下歸舟。"]'),
('ad6d517e-11e3-4290-bcee-2279e3823fca','客感','王珪','宋','宋诗','song-poetry','','[]','行子征驂去易迷，故鄉回首在天涯。',64,'全唐诗/poet.song.28000.json','["行子征驂去易迷，故鄉回首在天涯。", "春心南陌風光遠，曉夢西樓月影遲。", "沈客带寛無奈痩，阮生車斷不勝悲。", "花狂蝶亂家園晚，何事東歸竟未期。"]'),
('bd35bdb5-ff88-46e1-b1ee-28359b784861','夏夜宿江亭有懷','王珪','宋','宋诗','song-poetry','','[]','夜衝江浦始停舟，天際蕭騷急雨收。',64,'全唐诗/poet.song.28000.json','["夜衝江浦始停舟，天際蕭騷急雨收。", "枕上月華清到曉，簟間風意冷如秋。", "一溪碧水懷歸意，九陌紅塵倦旅遊。", "待得星稀城角斷，舊酲消盡起新愁。"]'),
('d2b47809-7457-4840-960e-a7553ab9c87d','京口遇大風','王珪','宋','宋诗','song-poetry','','[]','虹蜺赫奕射中天，怒竅風號勢塕然。',64,'全唐诗/poet.song.28000.json','["虹蜺赫奕射中天，怒竅風號勢塕然。", "雲翼扶摶彌九萬，海帆飛迅越三千。", "鯢嘘駭浪時開闔，鰲負靈山或泝沿。", "安得琴高控雙鯉，一驅霾曀靜洪淵。"]'),
('c6b89bb2-3f04-4f7c-b4cb-daa6d1b0252f','遊賞心亭','王珪','宋','宋诗','song-poetry','','[]','六朝遺跡此空存，城壓滄波到海門。',64,'全唐诗/poet.song.28000.json','["六朝遺跡此空存，城壓滄波到海門。", "萬里江山来醉眼，九秋天地入吟魂。", "于今玉樹悲歌起，當日黄旗王氣昏。", "人事不同風物在，悵然猶得對芳樽。"]'),
('243b9e50-ec62-4efc-a2e4-f95d5cb47ef1','四并亭','王珪','宋','宋诗','song-poetry','','[]','蹛林初躍玉羈旋，已覺芳菲近日邊。',64,'全唐诗/poet.song.28000.json','["蹛林初躍玉羈旋，已覺芳菲近日邊。", "塞上臙脂侵酒面，江南寒食落尊前。", "魂迷一水花臨浦，醉入東風絮滿天。", "金谷更饒春色好，四難猶恐負華年。"]'),
('6ce598e1-0969-4efc-97f3-178543ed4010','樓上會友述懷','王珪','宋','宋诗','song-poetry','','[]','烟城疏雨隔斜陽，一上危樓睇大荒。',64,'全唐诗/poet.song.28000.json','["烟城疏雨隔斜陽，一上危樓睇大荒。", "原憲自貧非苦病，次公未飲已多狂。", "江帆來往年光度，驛堠東西客意長。", "公至和中首陳建，儲之策白居易晚。"]'),
('028af961-c6ab-437c-b3b1-2bcb0eb8d3b0','聞琵琶','王珪','宋','宋诗','song-poetry','','[]','夜拍水雲非故鄉，未聞終曲已凄凉。',64,'全唐诗/poet.song.28000.json','["夜拍水雲非故鄉，未聞終曲已凄凉。", "舟中月白寒江闊，馬上酸風紫塞長。", "思婦有懷停别杵，征人無語對清觴。", "平時不見秦城役，餘韻空傳戰壘荒。"]'),
('c37f7773-9054-4e72-bff6-66065623edb6','秋雨','王珪','宋','宋诗','song-poetry','','[]','秋容浩蕩夕雲高，旻宇蕭然絕一毫。',64,'全唐诗/poet.song.28000.json','["秋容浩蕩夕雲高，旻宇蕭然絕一毫。", "漢塞草平嘶牧馬，越溪風急送歸舠。", "天衢夜失清蟾魄，海國寒飛白鷺濤。", "誰共危樓凌爽氣，左持樽酒右持螯。"]'),
('5124ee25-64ce-4e0f-b312-7c69d54fd357','友生失意','王珪','宋','宋诗','song-poetry','','[]','夢到天閽寤翼傷，拂衣歸去樂江鄉。',64,'全唐诗/poet.song.28000.json','["夢到天閽寤翼傷，拂衣歸去樂江鄉。", "丈夫豈識原非病，丞相應嗤盖有狂。", "失馬未須嗟北塞，過關重約使南陽。", "君知韝上雄飛日，秋勁霜嚴始一翔。"]'),
('417d8870-828f-47fe-b39e-0e2d283acc87','題道錄陳景元中太乙宮種玉軒','王珪','宋','宋诗','song-poetry','','[]','一住仙祠絕世塵，庭前種玉已嶙峋。',64,'全唐诗/poet.song.28000.json','["一住仙祠絕世塵，庭前種玉已嶙峋。", "朝昏龍虎常聽法，左右瓊瑤自逼人。", "翠鳳有時翻瑞影，銀蟾通夕墮清津。", "黄金絡馬何年醉，得去同遊幾洞春。"]'),
('37d443a3-98ea-49a8-bff3-f1613a2516ab','留題吳仲庶省副北軒畫壁兼呈楊樂道諫院龍圖三首  其一','王珪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','文書滿眼紛紛裏，忽覺滄波起荻洲。',64,'全唐诗/poet.song.28000.json','["文書滿眼紛紛裏，忽覺滄波起荻洲。", "紅日不知華省暮，扁舟如下洞庭秋。", "林泉傲物非無約，軒冕拘人此未休。", "與拂素塵尋絕景，羡君瀟灑特遲留。"]'),
('cf4a2b72-0684-44d3-9172-860f68e2147b','留題吳仲庶省副北軒畫壁兼呈楊樂道諫院龍圖三首  其二','王珪','宋','宋诗','song-poetry','','[]','誰將畫手分平遠，幾度曾窺雁鶩洲。',64,'全唐诗/poet.song.28000.json','["誰將畫手分平遠，幾度曾窺雁鶩洲。", "六月炎風方病暑，五湖烟景已迎秋。", "班趨規地來常晚，詩入籠紗思未休。", "爲惜主人林下意，暮鐘沉閣尚應留。"]'),
('62688f3c-4945-4a2d-9d62-ff58fb8b5a1a','留題吳仲庶省副北軒畫壁兼呈楊樂道諫院龍圖三首  其三','王珪','宋','宋诗','song-poetry','','[]','聞道北窗開繪境，偶來歸思滿滄洲。',64,'全唐诗/poet.song.28000.json','["聞道北窗開繪境，偶來歸思滿滄洲。", "卷簾宿鳥驚初旭，隔浦疏林似舊秋。", "夢憶清溪知幾曲，醉尋危磴欲三休。", "何時又賜通中枕，與對雲山盡日留。"]'),
('1613a1bb-6ca0-4a18-afa8-f027017a0ef7','金陵懷古二首  其一','王珪','宋','宋诗','song-poetry','','[]','懷鄉訪古事悠悠，獨上江城滿目秋。',64,'全唐诗/poet.song.28000.json','["懷鄉訪古事悠悠，獨上江城滿目秋。", "一鳥带烟來别渚，數帆和雨下歸舟。", "蕭蕭暮吹驚紅葉，慘慘寒雲壓舊樓。", "故國凄凉誰與問，人心無復更風流。"]'),
('fd98a72b-5ef5-45fb-b516-b82ea32eeadd','金陵懷古二首  其二','王珪','宋','宋诗','song-poetry','','[]','控带洪流古帝城，欲尋舊事半榛荆。',64,'全唐诗/poet.song.28000.json','["控带洪流古帝城，欲尋舊事半榛荆。", "六朝山色青終在，千古江聲恨未平。", "設險邱陵荒蔓草，壓邨桑柘接新畊。", "十年重到無人問，獨立東風一愴情。"]'),
('61666b7e-4162-432b-b4e0-1490c95b82b1','登懸瓠城感吴季子','王珪','宋','宋诗','song-poetry','','[]','將軍戈甲從天下，丞相旌旗匝地來。',64,'全唐诗/poet.song.28000.json','["將軍戈甲從天下，丞相旌旗匝地來。", "堪笑怒螳猶强臂，不知蟄戶欲驚雷。", "咄嗟武相深冤洗，指顧山東治境開。", "吏部聲名千古在，斷碑何處卧蒼苔。"]'),
('2024e4fa-4fa9-4ae7-9765-ff4af8650fa0','三鄉懷古','王珪','宋','宋诗','song-poetry','','[]','清洛東流去不還，漢唐遺事有無間。',64,'全唐诗/poet.song.28000.json','["清洛東流去不還，漢唐遺事有無間。", "廟荒古木連空谷，宫廢春蕪入亂山。", "南陌絮飛人寂寂，孤城花落鳥關關。", "登臨幾度遊人老，又對東風髩欲班。"]'),
('10c83d59-6c2c-49ce-9595-029e6c9f1420','登海州樓','王珪','宋','宋诗','song-poetry','','[]','城外滄溟日夜流，城南山直對城樓。',64,'全唐诗/poet.song.28000.json','["城外滄溟日夜流，城南山直對城樓。", "溪田雨足禾先熟，海樹風高葉易秋。", "疏傅里閭尋故老，秦皇車甲想東遊。", "客心不待傷千里，檻外風煙盡是愁。"]'),
('4eed59ab-bbb5-4dd8-924b-a647c28942f1','新亭','王珪','宋','宋诗','song-poetry','','[]','獨上新亭怨不勝，荒城搖落暮烟凝。',64,'全唐诗/poet.song.28000.json','["獨上新亭怨不勝，荒城搖落暮烟凝。", "翠筠無限悲湘水，玉碗空聞泣茂陵。", "秋館樹寒風戰葉，夜樓人散雨飄燈。", "紫臺路遠關山隔，回首陰雲幾萬層。"]'),
('2aaac075-df0c-4595-862f-a02d1f52230b','涿州','王珪','宋','宋诗','song-poetry','','[]','涿州亭下柳依依，誰折長條送客歸。',64,'全唐诗/poet.song.28000.json','["涿州亭下柳依依，誰折長條送客歸。", "曉月未消燕戍酒，春雲初拂漢臺衣。", "玉堂社燕宜先入，沙磧晴鴻己半飛。", "回首青山欲千里，行人猶自馬騑騑。"]'),
('2c4517d3-58ff-42a1-b50a-fe26da051135','冀館春夕見月','王珪','宋','宋诗','song-poetry','','[]','甚寵無如使牡行，曾同萬里聽秋聲。',64,'全唐诗/poet.song.28000.json','["甚寵無如使牡行，曾同萬里聽秋聲。", "黄金臺下嘶宛馬，木葉山前度漢旌。", "纔到關南逢雁盡，重来海上見波平。", "故人臨月應相望，一夕寒光特爲明。"]'),
('a935646e-05f5-424f-b467-67800de7348d','正月五日與館伴耶律防夜燕永壽給事不赴留别','王珪','宋','宋诗','song-poetry','','[]','萬里來持聘玉通，今宵賓燕爲誰同。',64,'全唐诗/poet.song.28000.json','["萬里來持聘玉通，今宵賓燕爲誰同。", "鐃歌自醉天山北，漢節先隨斗柄東。", "半夜騰裝吹朔雪，平明躍馬向春風。", "使車少别無多戀，只隔燕南一信中。"]'),
('beb421cf-5af1-4429-b5ea-aaed290c3788','被詔考制科呈胡武平內翰三首  其一','王珪','宋','宋诗','song-poetry','','[]','奉詔金門草聖題，平明趨過殿西墀。',64,'全唐诗/poet.song.28000.json','["奉詔金門草聖題，平明趨過殿西墀。", "宫牀賜筆宣名早，赭案焚香上策時。", "朝論只應收畯傑，皇心非不監安危。", "玉堂詞客承恩久，幾度曾來醉御巵。"]'),
('3e57881a-581f-4408-a2b1-c6096335c537','被詔考制科呈胡武平內翰三首  其二','王珪','宋','宋诗','song-poetry','','[]','清曉華芝度景陽，凝嚴又許對西廂。',64,'全唐诗/poet.song.28000.json','["清曉華芝度景陽，凝嚴又許對西廂。", "通宵客夢聞鈞吹，幾日朝衣带御香。", "東觀圖書經屢讀，舊溪桃李見新芳。", "三千文字皆奇册，飽死侏儒詎足量。"]'),
('8db58c6b-299e-424d-a778-a4d2cdd1ded1','被詔考制科呈胡武平內翰三首  其三','王珪','宋','宋诗','song-poetry','','[]','忝班清禁接嚴徐，詔侍延英訪對初。',64,'全唐诗/poet.song.28000.json','["忝班清禁接嚴徐，詔侍延英訪對初。", "滄海烟霞連太液，丹霄日月近雕輿。", "明廷已奏安危策，紫府誰將姓字書。", "從此青雲知有路，致君材業不應疏。"]'),
('22eeb0c7-8bc8-4cc9-9e9c-debf05f34f64','靴淀除夕之會呈王原叔給事燕唐卿諫議','王珪','宋','宋诗','song-poetry','','[]','歲華相逐走燕塵，此夕覉懷暫一申。',64,'全唐诗/poet.song.28000.json','["歲華相逐走燕塵，此夕覉懷暫一申。", "把手豈辭三處酒，别家看作二年人。", "因逢塞雁驚來信，却憶江梅贈去春。", "莫向天涯憂白髪，東風猶與到關新。"]'),
('a3fe9d15-71f1-454c-8740-310076df4bc9','元日呈原叔給事唐卿諫議','王珪','宋','宋诗','song-poetry','','[]','欲曉東風拂面來，征驂初喜共春回。',64,'全唐诗/poet.song.28000.json','["欲曉東風拂面來，征驂初喜共春回。", "九天應下階庭拜，萬蟄先驚漢地雷。", "冷徹貂裘須護節，和侵氊屋莫窮杯。", "出疆慷慨男兒事，未信霜顔便一摧。"]'),
('0c97e7c8-4bc2-4156-88de-d6f3481a7e05','戲呈唐卿','王珪','宋','宋诗','song-poetry','','[]','行到鹿兒山更峭，八千歸路可勝勞。',64,'全唐诗/poet.song.28000.json','["行到鹿兒山更峭，八千歸路可勝勞。", "長安日遠思親髮，紫漢星回促使軺。", "曉磴雲濃藏去驛，陰崖冰折斷前橋。", "覉懷一夕猶難遣，况是辭家九十朝。"]'),
('cba54b1d-748a-4dbd-b1ab-92656f6309b4','莫京甫知事有臺掾之辟賦詩識别二首  其一','王珪','宋','宋诗','song-poetry','','[]','烈士思酧國士知，雲霄羽翼政相期。',64,'全唐诗/poet.song.28000.json','["烈士思酧國士知，雲霄羽翼政相期。", "人言雅望臺中妙，我識壮懷天下奇。", "自是英才爲世用，由来了事笑兒癡。", "回頭說向虞羅軰，鵠舉鸞鶱可得覊。"]'),
('4bb81be7-4ab1-4695-938e-72fa7ca59a91','莫京甫知事有臺掾之辟賦詩識别二首  其二','王珪','宋','宋诗','song-poetry','','[]','蘭生空谷混荆榛，不礙幽香到處聞。',64,'全唐诗/poet.song.28000.json','["蘭生空谷混荆榛，不礙幽香到處聞。", "幕府才流推謝掾，宣州賓客憶崔羣。", "清懷疊陣三秋月，行槖雙溪一片雲。", "白髪書生何以報，慚君出力衛斯文。"]'),
('2eaef6d3-7b2b-4f89-9b7c-7fa589f49398','胡則大學士滿秩趨京賦詩爲贈','王珪','宋','宋诗','song-poetry','','[]','一室蕭然數卷書，三年冷掾出無驢。',64,'全唐诗/poet.song.28000.json','["一室蕭然數卷書，三年冷掾出無驢。", "每因芳草憂鵜鴂，苦詠塲苗羡白駒。", "俗吏何嘗知大體，清朝方急用真儒。", "燕臺從去流聲實，見說諸公誦子虛。"]'),
('93347c1f-c1a8-416a-acfd-623aaaa0c21a','訪别成獻甫經歷時新拜西臺御史之命二首  其一','王珪','宋','宋诗','song-poetry','','[]','江上秋風吹繡衣，客槎西上渺天涯。',64,'全唐诗/poet.song.28000.json','["江上秋風吹繡衣，客槎西上渺天涯。", "得爲李御平生願，一識荆州是别時。", "柏署行分秦地月，棠陰好在召南詩。", "日邊消息長安近，佇聽朝趋上玉墀。"]');
